-- Poems batch 410
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-322','卜算子','陈师道','宋','宋词','song-ci','卜算子','[]','纤软小腰身，明秀天真面。',52,'宋词/ci.song.4000.json','["纤软小腰身，明秀天真面。", "淡画修眉小作春，中有相思怨。", "背立向人羞，颜破因谁倩。", "不比阳台梦里逢，亲向尊前见。"]'),
('song-ci-323','洛阳春・一落萦','陈师道','宋','宋词','song-ci','洛阳春・一落萦','[]','酒到横波娇满。',56,'宋词/ci.song.4000.json','["酒到横波娇满。", "和香喷面。", "攀花落雨祝东风，诮不借、周郎便。", "背立腰肢挪拈。", "更须回盼。", "多生不作好因缘，甚只向、尊前见。"]'),
('song-ci-324','浣溪沙','陈师道','宋','宋词','song-ci','浣溪沙','[]','暮叶朝花种种陈。',48,'宋词/ci.song.4000.json','["暮叶朝花种种陈。", "三秋作意向诗人。", "安排云雨要新清。", "随意且须追去马，轻衫从使著行尘。", "晚窗谁念一愁新。"]'),
('song-ci-325','临江仙','陈师道','宋','宋词','song-ci','临江仙','[]','官样初黄过闰九。',70,'宋词/ci.song.4000.json','["官样初黄过闰九。", "鲜妍时更宜寒。", "挽回人意不成阑。", "香罗堆叶密，芳意著心单。", "过与后房歌舞手，轻盈喜色生颜。", "堕钗拥髻与垂鬟。", "欲知谁称面，遍插一枝看。"]'),
('song-ci-326','清平乐','陈师道','宋','宋词','song-ci','清平乐','[]','重重叠叠。',54,'宋词/ci.song.4000.json','["重重叠叠。", "娜娜裙千襵。", "时样官黄香百叶。", "一岁相逢两节。", "曲阑绕遍芳丛。", "一枝作意妍秾。", "折得有谁相忆，却须还与秋风。"]'),
('song-ci-327','南乡子','陈师道','宋','宋词','song-ci','南乡子','[]','风絮落东邻。',66,'宋词/ci.song.4000.json','["风絮落东邻。", "点缀繁枝旋化尘。", "关锁玉楼巢燕子，冥冥。", "桃李摧残不见春。", "流转到如今。", "翡翠生儿翠作衿。", "花样腰身官样立，婷婷。", "困倚阑干一欠伸。"]'),
('song-ci-328','南乡子','陈师道','宋','宋词','song-ci','南乡子','[]','乱蕊压枝繁。',66,'宋词/ci.song.4000.json','["乱蕊压枝繁。", "堆积金钱闹作团。", "晚起涂黄仍带酒，看看。", "衣剩腰肢故著单。", "薄瘦却禁寒。", "牵引人心不放阑。", "拟折一枝遮老眼，难难。", "蝶横蜂争只倚阑。"]'),
('song-ci-329','临江仙','陈师道','宋','宋词','song-ci','临江仙','[]','曲巷斜街信马，小桥流水谁家。',68,'宋词/ci.song.4000.json','["曲巷斜街信马，小桥流水谁家。", "浅衫深袖倚门斜。", "只缘些子意，消得百般夸。", "粉面初生明月，酒容欲退朝霞。", "春风还解染霜华。", "肯持鸳绮被，来伴杜家花。"]'),
('song-ci-330','蝶恋花','陈师道','宋','宋词','song-ci','蝶恋花','["\u957f\u6c5f"]','九里山前千里路。',70,'宋词/ci.song.4000.json','["九里山前千里路。", "流水无情，只送行人去。", "路转河回寒日暮。", "连峰不许重回顾。", "水解随人花却住。", "衾冷香销，但有残妆污。", "泪入长江空几许。", "双洪一抹无寻处。"]'),
('song-ci-331','西江月','陈师道','宋','宋词','song-ci','西江月','[]','浅色千重柔叶，深心一点娇黄。',58,'宋词/ci.song.4000.json','["浅色千重柔叶，深心一点娇黄。", "只消可意更须香。", "好个风流模样。", "玉蕊今谁攀折，诗人此日凄凉。", "正须蛮素作伊凉。", "与插钗傍鬓上。"]'),
('song-ci-332','洛阳春・一落萦','陈师道','宋','宋词','song-ci','洛阳春・一落萦','[]','素手拈花纤软。',56,'宋词/ci.song.4000.json','["素手拈花纤软。", "生香相乱。", "却须诗力与丹青，恐俗手、难成染。", "一顾教人微倩。", "那堪亲见。", "不辞紫袖拂清尘，也要识、春风面。"]'),
('song-ci-333','菩萨蛮','陈师道','宋','宋词','song-ci','菩萨蛮','[]','清词丽句前朝曲。',52,'宋词/ci.song.4000.json','["清词丽句前朝曲。", "使君借与灯前读。", "读罢已三更。", "寒窗雨打声。", "应怜诗客老。", "要使情怀好。", "犹有解歌人。", "尊前未得听。"]'),
('song-ci-334','木兰花减字・减字木兰花','陈师道','宋','宋词','song-ci','木兰花减字・减字木兰花','[]','清愁叠积。',52,'宋词/ci.song.4000.json','["清愁叠积。", "更莫迟留春酒逼。", "吹面和风。", "梅信新来一线通。", "危楼晓望。", "雪满群山开画障。", "目断瑶川。", "同凭阑干意几般。"]'),
('song-ci-335','卜算子','陈师道','宋','宋词','song-ci','卜算子','[]','梅岭数枝春，疏影斜临水。',52,'宋词/ci.song.4000.json','["梅岭数枝春，疏影斜临水。", "不借芳华只自香，娇面长如洗。", "还把最繁枝，过与偏怜底。", "拭傍鸾台仔细看，何似丹青里。"]'),
('song-ci-336','渔家傲','陈师道','宋','宋词','song-ci','渔家傲','[]','一舸姑苏风雨疾。',72,'宋词/ci.song.4000.json','["一舸姑苏风雨疾。", "吴笺满载红犹湿。", "色润朝花光触日。", "人未识。", "街南小阮应先得。", "青入柳条初著色。", "溪梅已露春消息。", "拟作新词酬帝力。", "轻落笔。", "黄秦去后无强敌。"]'),
('song-ci-337','少年游','陈师道','宋','宋词','song-ci','少年游','[]','御园果子压枝繁。',63,'宋词/ci.song.4000.json','["御园果子压枝繁。", "看看分摘无缘。", "团沙弄雪，劳心费手，不肯暂时圆。", "赛神旧愿心儿有，终了待、几时还。", "芍药梢头，红红白白，一种几千般。"]'),
('song-ci-338','南乡子','陈师道','宋','宋词','song-ci','南乡子','[]','袅娜破瓜馀。',66,'宋词/ci.song.4000.json','["袅娜破瓜馀。", "豆蔻梢头二月初。", "众里腰肢遥可识，应殊。", "暗里犹能摸得渠。", "醉侧不须扶。", "唤作周家行画图。", "背立欠伸花絮底，知无。", "未信丹青画得如。"]'),
('song-ci-339','木兰花减字・减字木兰花','陈师道','宋','宋词','song-ci','木兰花减字・减字木兰花','[]','今年百五。',52,'宋词/ci.song.4000.json','["今年百五。", "风日清明尘不举。", "紫袖红陈。", "三节烟花次第春。", "来舆去马。", "千念一空春事谢。", "白下门东。", "谁见初杨弄晚风。"]'),
('song-ci-340','踏莎行','陈师道','宋','宋词','song-ci','踏莎行','[]','红上花梢，风传梅信。',68,'宋词/ci.song.4000.json','["红上花梢，风传梅信。", "青春欲动群芳竞。", "林声鸟语带馀寒，江光野色开游径。", "乍雨还晴，喧寒不定。", "重门深院帘帷静。", "又还日日唤愁生，到谁准拟风流病。"]'),
('song-ci-341','菩萨蛮','陈师道','宋','宋词','song-ci','菩萨蛮','[]','晓来误入桃源洞。',52,'宋词/ci.song.4000.json','["晓来误入桃源洞。", "恰见佳人春睡重。", "玉腕枕香腮。", "荷花藕上开。", "一扇俄惊起。", "敛黛凝秋水。", "笑倩整金衣。", "问郎来几时。"]'),
('song-ci-342','卜算子','陈师道','宋','宋词','song-ci','卜算子','[]','摇风影似凝，带雪香如抱。',52,'宋词/ci.song.4000.json','["摇风影似凝，带雪香如抱。", "开尽南枝到北枝，不道春将老。", "飘颻姑射仙，谁识冰肌好。", "会有青绫梦觉人，可爱池塘草。"]'),
('song-ci-343','卜算子','陈师道','宋','宋词','song-ci','卜算子','[]','绣幕罩梅花，莫放清香透。',52,'宋词/ci.song.4000.json','["绣幕罩梅花，莫放清香透。", "鉴里朱颜岁岁移，只道花依旧。", "把酒问梅花，知我离情否。", "若使梅花知我时，料得花须瘦。"]'),
('song-ci-344','卜算子','陈师道','宋','宋词','song-ci','卜算子','[]','雪暗岭头云，竹冷溪边树。',52,'宋词/ci.song.4000.json','["雪暗岭头云，竹冷溪边树。", "还似潇湘缥缈人，玉骨笼香雾。", "月下幽香度。", "梦里香魂驻。", "回首南枝酒半醺，寂寞无寻处。"]'),
('song-ci-345','减字木兰花','青幕子妇','宋','宋词','song-ci','减字木兰花','[]','清词丽句。',26,'宋词/ci.song.4000.json','["清词丽句。", "永叔子瞻曾独步。", "似恁文章。", "写得出来当甚强。"]'),
('song-ci-346','减字木兰花','张耒','宋','宋词','song-ci','减字木兰花','[]','个人风味。',52,'宋词/ci.song.4000.json','["个人风味。", "只有江梅些子似。", "每到开时。", "满眼清愁只自知。", "霞裾仙珮。", "姑射神人风露态。", "蜂蝶休忙。", "不与春风一点香。"]'),
('song-ci-347','鹧鸪天','张耒','宋','宋词','song-ci','鹧鸪天','[]','倾盖相逢汝水滨。',64,'宋词/ci.song.4000.json','["倾盖相逢汝水滨。", "须知见面过闻名。", "马头虽去无千里，酒盏才倾且百分。", "嗟得失，一微尘。", "莫教冰炭损精神。", "北扉西禁须公等，金榜当年第一人。"]'),
('song-ci-348','满庭芳','张耒','宋','宋词','song-ci','满庭芳','[]','裂楮裁筠，虚明潇洒，制成方丈屠苏。',120,'宋词/ci.song.4000.json','["裂楮裁筠，虚明潇洒，制成方丈屠苏。", "草团蒲坐，中置一山炉。", "拙似春林鸠宿，易于□、秋野鹑居。", "谁相对，时烦孟妇，石鼎煮寒蔬。", "嗟吁。", "人生随分足，风云际会，漫付伸舒。", "且偷取闲时，向此踌躇。", "谩取黄金建厦，繁华梦、毕竟空虚。", "争如且、寒村厨火，汤饼一斋盂。"]'),
('song-ci-349','风流子','张耒','宋','宋词','song-ci','风流子','[]','木叶亭皋下，重阳近，又是捣衣秋。',136,'宋词/ci.song.4000.json','["木叶亭皋下，重阳近，又是捣衣秋。", "奈愁入庾肠，老侵潘鬓，谩簪黄菊，花也应羞。", "楚天晚，白苹烟尽处，红蓼水边头。", "芳草有情，夕阳无语，雁横南浦，人倚西楼。", "玉容，知安否，香笺共锦字，两处悠悠。", "空恨碧云离合，青鸟沈浮。", "向风前懊恼，芳心一点，寸眉两叶，禁甚闲愁。", "情到不堪言处，分付东流。"]'),
('song-ci-350','秋蕊香','张耒','宋','宋词','song-ci','秋蕊香','[]','帘幕疏疏风透。',56,'宋词/ci.song.4000.json','["帘幕疏疏风透。", "一线香飘金兽。", "朱阑倚遍黄昏后。", "廊上月华如昼。", "别离滋味浓於酒。", "著人瘦。", "此情不及墙东柳。", "春色年年如旧。"]'),
('song-ci-351','少年游','张耒','宋','宋词','song-ci','少年游','[]','含羞倚醉不成歌。',62,'宋词/ci.song.4000.json','["含羞倚醉不成歌。", "纤手掩香罗。", "偎花映烛，偷传深意，酒思入横波。", "看朱成碧心迷乱，翻脉脉、敛双蛾。", "相见时稀隔别多。", "又春尽、奈愁何。"]'),
('song-ci-352','失调名','张耒','宋','宋词','song-ci','失调名','[]','水团冰浸砂糖裹。',17,'宋词/ci.song.4000.json','["水团冰浸砂糖裹。", "有透明角黍松儿和。"]'),
('song-ci-353','失调名','张耒','宋','宋词','song-ci','失调名','[]','菖蒲酒满劝人人，愿年年欢醉。',28,'宋词/ci.song.4000.json','["菖蒲酒满劝人人，愿年年欢醉。", "偎倚。", "把合欢彩索，殷勤寄与。"]'),
('song-ci-354','失调名','张耒','宋','宋词','song-ci','失调名','[]','手把合欢彩索，殷勤微笑殢檀郎。',29,'宋词/ci.song.4000.json','["手把合欢彩索，殷勤微笑殢檀郎。", "低低告，不图系腕，图系人肠。"]'),
('song-ci-355','临江仙','侯蒙','宋','宋词','song-ci','临江仙','[]','未遇行藏谁肯信，如今方表名踪。',70,'宋词/ci.song.4000.json','["未遇行藏谁肯信，如今方表名踪。", "无端良匠画形容。", "当风轻借力，一举入高空。", "才得吹嘘身渐稳，只疑远赴蟾宫。", "雨馀时候夕阳红。", "几人平地上，看我碧霄中。"]'),
('song-ci-356','瑞龙吟','周邦彦','宋','宋词','song-ci','瑞龙吟','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','章台路。',163,'宋词/ci.song.4000.json','["章台路。", "还见褪粉梅梢，试花桃树。", "愔愔坊陌人家，定巢燕子，归来旧处。", "暗凝伫。", "因念个人痴小，乍窥门户。", "侵晨浅约宫黄，障风映袖，盈盈笑语。", "前度刘郎重到，访邻寻里，同时歌舞。", "唯有旧家秋娘，声价如故。", "吟笺赋笔，犹记燕台句。", "知谁伴，名园露饮，东城闲步。", "事与孤鸿去。", "探春尽是，伤离意绪。", "官柳低金缕。", "归骑晚，纤纤池塘飞雨。", "断肠院落，一帘风絮。"]'),
('song-ci-357','锁窗寒・琐寒窗','周邦彦','宋','宋词','song-ci','锁窗寒・琐寒窗','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','暗柳啼鸦，单衣伫立，小帘朱户。',122,'宋词/ci.song.4000.json','["暗柳啼鸦，单衣伫立，小帘朱户。", "桐花半亩，静锁一庭愁雨。", "洒空阶，夜阑未休，故人剪烛西窗语。", "似楚江暝宿，风灯零乱，少年羁旅。", "迟暮。", "嬉游处。", "正店舍无烟，禁城百五。", "旗亭唤酒，付与高阳俦侣。", "想东园，桃李自春，小唇秀靥今在否。", "到归时，定有残英，待客携尊俎。"]'),
('song-ci-358','风流子','周邦彦','宋','宋词','song-ci','风流子','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','新绿小池塘。',134,'宋词/ci.song.4000.json','["新绿小池塘。", "风帘动，碎影舞斜阳。", "羡金屋去来，旧时巢燕，土花缭绕，前度莓墙。", "绣阁凤帏深几许，曾听得理丝簧。", "欲说又休，虑乖芳信，未歌先咽，愁近清觞。", "遥知新妆了，开朱户，应自待月西厢。", "最苦梦魂，今宵不到伊行。", "问甚时说与，佳音密耗，寄将秦镜，偷换韩香。", "天便教人，霎时厮见何妨。"]'),
('song-ci-359','渡江云','周邦彦','宋','宋词','song-ci','渡江云','[]','晴岚低楚甸，暖回雁翼，阵势起平沙。',124,'宋词/ci.song.4000.json','["晴岚低楚甸，暖回雁翼，阵势起平沙。", "骤惊春在眼，借问何时，委曲到山家。", "涂香晕色，盛粉饰、争作妍华。", "千万丝、陌头杨柳，渐渐可藏鸦。", "堪嗟。", "清江东注，画舸西流，指长安日下。", "愁宴阑，风翻旗尾，潮溅乌纱。", "今宵正对初弦月，傍水驿，深舣蒹葭。", "沈恨处，时时自剔灯花。"]'),
('song-ci-360','应天长','周邦彦','宋','宋词','song-ci','应天长','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','条风布暖，霏雾弄晴，池塘遍满春色。',122,'宋词/ci.song.4000.json','["条风布暖，霏雾弄晴，池塘遍满春色。", "正是夜堂无月，沈沈暗寒食。", "梁间燕，前社客。", "似笑我、闭门愁寂。", "乱花过，隔院芸香，满地狼藉。", "长记那回时，邂逅相逢，郊外驻油壁。", "又见汉宫传烛，飞烟五候宅。", "青青草，迷路陌。", "强带酒，细寻前迹。", "市桥远，柳下人家，犹自相识。"]'),
('song-ci-361','荔枝香近・荔枝香','周邦彦','宋','宋词','song-ci','荔枝香近・荔枝香','[]','照水残红零乱，风唤去。',90,'宋词/ci.song.4000.json','["照水残红零乱，风唤去。", "尽日测测轻寒，帘底吹香雾。", "黄昏客枕无憀，细响当窗雨。", "看两两相依燕新乳。", "楼下水，渐绿遍、行舟浦。", "暮往朝来，心逐片帆轻举。", "何日迎门，小槛朱笼报鹦鹉。", "共剪西窗蜜炬。"]'),
('song-ci-362','荔枝香近・荔枝香','周邦彦','宋','宋词','song-ci','荔枝香近・荔枝香','[]','夜来寒侵酒席，露微泫。',90,'宋词/ci.song.4000.json','["夜来寒侵酒席，露微泫。", "舄履初会，香泽方熏，无端暗雨催人，但怪灯偏帘卷。", "回顾，始觉惊鸿去云远。", "大都世间，最苦唯聚散。", "到得春残，看即是、开离宴。", "细思别后，柳眼花须更谁剪。", "此怀何处消遣。"]'),
('song-ci-363','还京乐','周邦彦','宋','宋词','song-ci','还京乐','[]','禁烟近，触处、浮香秀色相料理。',126,'宋词/ci.song.4000.json','["禁烟近，触处、浮香秀色相料理。", "正泥花时候，奈何客里，光阴虚费。", "望箭波无际。", "迎风漾日黄云委。", "任去远，中有万点，相思清泪。", "到长淮底。", "过当时楼下，殷勤为说，春来羁旅况味。", "堪嗟误约乖期，向天涯、自看桃李。", "想而今、应恨墨盈笺，愁妆照水。", "怎得青鸾翼，飞归教见憔悴。"]'),
('song-ci-364','扫地花・扫地游','周邦彦','宋','宋词','song-ci','扫地花・扫地游','[]','晓阴翳日，正雾霭烟横，远迷平楚。',117,'宋词/ci.song.4000.json','["晓阴翳日，正雾霭烟横，远迷平楚。", "暗黄万缕。", "听鸣禽按曲，小腰欲舞。", "细绕回堤，驻马河桥避雨。", "信流去。", "想一叶怨题，今在何处。", "春事能几许。", "任占地持杯，扫花寻路。", "泪珠溅俎。", "叹将愁度日，病伤幽素。", "恨入金徽，见说文君更苦。", "黯凝伫。", "掩重关、遍城锺鼓。"]'),
('song-ci-365','解连环','周邦彦','宋','宋词','song-ci','解连环','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','怨怀无托。',132,'宋词/ci.song.4000.json','["怨怀无托。", "嗟情人断绝，信音辽邈。", "信妙手、能解连环，似风散雨收，雾轻云薄。", "燕子楼空，暗尘锁、一床弦索。", "想移根换叶。", "尽是旧时，手种红药。", "汀洲渐生杜若。", "料舟依岸曲，人在天角。", "谩记得、当日音书，把闲语闲言，待总烧却。", "水驿春回，望寄我、江南梅萼。", "拚今生，对花对酒，为伊落泪。"]'),
('song-ci-366','玲珑四犯','周邦彦','宋','宋词','song-ci','玲珑四犯','[]','秾李夭桃，是旧日潘郎，亲试春艳。',118,'宋词/ci.song.4000.json','["秾李夭桃，是旧日潘郎，亲试春艳。", "自别河阳，长负露房烟脸。", "憔悴鬓点吴霜，念想梦魂飞乱。", "叹画阑玉砌都换。", "才始有缘重见。", "夜深偷展香罗荐。", "暗窗前、醉眠葱茜。", "浮花浪蕊都相识，谁更曾抬眼。", "休问旧色旧香，但认取、芳心一点。", "又片时一阵，风雨恶，吹分散。"]'),
('song-ci-367','丹凤吟','周邦彦','宋','宋词','song-ci','丹凤吟','[]','迤逦春光无赖，翠藻翻池，黄蜂游阁。',137,'宋词/ci.song.4000.json','["迤逦春光无赖，翠藻翻池，黄蜂游阁。", "朝来风暴，飞絮乱投帘幕。", "生憎暮景，倚墙临岸，杏靥夭斜，榆钱轻薄。", "昼永惟思傍枕，睡起无憀，残照犹在亭角。", "况是别离气味，坐来但觉心绪恶。", "痛引浇愁酒，奈愁浓如酒，无计消铄。", "那堪昏暝，簌簌半檐花落。", "弄粉调朱柔素手，问何时重握。", "此时此意，长怕人道著。"]'),
('song-ci-368','满江红','周邦彦','宋','宋词','song-ci','满江红','[]','昼日移阴，揽衣起、春帷睡足。',115,'宋词/ci.song.4000.json','["昼日移阴，揽衣起、春帷睡足。", "临宝鉴，绿云撩乱，未忺妆束。", "蝶粉蜂黄都褪了，枕痕一线红生肉。", "背画栏、脉脉悄无言，寻棋局。", "重会面，犹未卜。", "无限事，萦心曲。", "想秦筝依旧，尚鸣金屋。", "芳草连天迷远望，宝香熏被成孤宿。", "最苦是、蝴蝶满园飞，无人扑。"]'),
('song-ci-369','瑞鹤仙','周邦彦','宋','宋词','song-ci','瑞鹤仙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','悄郊原带郭。',125,'宋词/ci.song.4000.json','["悄郊原带郭。", "行路永，客去车尘漠漠。", "斜阳映山落。", "敛馀红、犹恋孤城栏角。", "凌波步弱。", "过短亭、何用素约。", "有流莺劝我，重解绣鞍，缓引春酌。", "不记归时早暮，上马谁扶，醒眠朱阁。", "惊飙动幕。", "扶残醉，绕红药。", "叹西园、已是花深无地，东风何事又恶。", "任流光过却。", "犹喜洞天自乐。"]'),
('song-ci-370','西平乐','周邦彦','宋','宋词','song-ci','西平乐','[]','稚柳苏晴，故溪歇雨，川迥未觉春赊。',167,'宋词/ci.song.4000.json','["稚柳苏晴，故溪歇雨，川迥未觉春赊。", "驼褐寒侵，正怜初日，轻阴抵死须遮。", "叹事逐孤鸿尽去，身与塘蒲共晚，争知向此，征途迢递，伫立尘沙。", "追念朱颜翠发，曾到处、故地使人嗟。", "道连三楚，天低四野，乔木依前，临路敧斜。", "重慕想，东陵晦迹，彭泽归来，左右琴书自乐，松菊相依，何况风流鬓未华。", "多谢故人，亲驰郑驿，时倒融尊，劝此淹留，共过芳时，翻令倦客思家。"]'),
('song-ci-371','浪涛沙・浪淘沙','周邦彦','宋','宋词','song-ci','浪涛沙・浪淘沙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','昼阴重，霜凋岸草，雾隐城堞。',162,'宋词/ci.song.4000.json','["昼阴重，霜凋岸草，雾隐城堞。", "南陌脂车待发。", "东门帐饮乍阕。", "正拂面垂杨堪缆结。", "掩红泪、玉手亲折。", "念汉浦离鸿去何许，经时信音绝。", "情切。", "望中地远天阔。", "向露冷风清，无人处、耿耿寒漏咽。", "嗟万事难忘，唯是轻别。", "翠尊未竭。", "凭断云留取，西楼残月。", "罗带光销纹衾叠。", "连环解、旧香顿歇。", "怨歌永、琼壶敲尽缺。", "恨春去、不与人期，弄夜色，空馀满地梨花雪。"]'),
('song-ci-372','忆旧游','周邦彦','宋','宋词','song-ci','忆旧游','[]','记愁横浅黛，泪洗红铅，门掩秋宵。',124,'宋词/ci.song.4000.json','["记愁横浅黛，泪洗红铅，门掩秋宵。", "坠叶惊离思，听寒蜇夜泣，乱雨潇潇。", "凤钗半脱云鬓，窗影烛光摇。", "渐暗竹敲凉，疏荧照晚，两地魂销。", "迢迢。", "问音信，道径底花阴，时认鸣镳。", "也拟临朱户，叹因郎憔悴，羞见郎招。", "旧巢更有新燕，杨柳拂河桥。", "但满目京尘，东风竟日吹露桃。"]'),
('song-ci-373','蓦山溪','周邦彦','宋','宋词','song-ci','蓦山溪','[]','湖平春水，菱荇萦船尾。',102,'宋词/ci.song.4000.json','["湖平春水，菱荇萦船尾。", "空翠入衣襟，拊轻桹、游鱼惊避。", "晚来潮上，迤逦没沙痕，山四倚。", "云渐起。", "鸟度屏风里。", "周郎逸兴，黄帽侵云水。", "落日媚沧洲，泛一棹、夷犹未已。", "玉箫金管，不共美人游，因个甚，烟雾底。", "独爱莼羹美。"]'),
('song-ci-374','少年游','周邦彦','宋','宋词','song-ci','少年游','[]','南都石黛扫晴山。',60,'宋词/ci.song.4000.json','["南都石黛扫晴山。", "衣薄耐朝寒。", "一夕东风，海棠花谢，楼上卷帘看。", "而今丽日明如洗，南陌暖雕鞍。", "旧赏园林，喜无风雨，春鸟报平安。"]'),
('song-ci-375','少年游','周邦彦','宋','宋词','song-ci','少年游','[]','朝云漠漠散轻丝。',60,'宋词/ci.song.4000.json','["朝云漠漠散轻丝。", "楼阁淡春姿。", "柳泣花啼，九街泥重，门外燕飞迟。", "而今丽日明金屋，春色在桃枝。", "不似当时，小桥冲雨，幽恨两人知。"]'),
('song-ci-376','秋蕊香','周邦彦','宋','宋词','song-ci','秋蕊香','[]','乳鸭池塘水暖。',56,'宋词/ci.song.4000.json','["乳鸭池塘水暖。", "风紧柳花迎面。", "午妆粉指印窗眼。", "曲里长眉翠浅。", "问知社日停针线。", "探新燕。", "宝钗落枕春梦远。", "帘影参差满院。"]'),
('song-ci-377','渔家傲','周邦彦','宋','宋词','song-ci','渔家傲','[]','灰暖香融销永昼。',72,'宋词/ci.song.4000.json','["灰暖香融销永昼。", "蒲萄架上春藤秀。", "曲角栏干群雀斗。", "清明后。", "风梳万缕亭前柳。", "日照钗梁光欲溜。", "循阶竹粉沾衣袖。", "拂拂面红如著酒。", "沈吟久。", "昨宵正是来时候。"]'),
('song-ci-378','渔家傲','周邦彦','宋','宋词','song-ci','渔家傲','[]','几日轻阴寒测测。',72,'宋词/ci.song.4000.json','["几日轻阴寒测测。", "东风急处花成积。", "醉踏阳春怀故国。", "归未得。", "黄鹂久住如相识。", "赖有蛾眉能暖客。", "长歌屡劝金杯侧。", "歌罢月痕来照席。", "贪欢适。", "帘前重露成涓滴。"]'),
('song-ci-379','南乡子','周邦彦','宋','宋词','song-ci','南乡子','[]','晨色动妆楼。',66,'宋词/ci.song.4000.json','["晨色动妆楼。", "短烛荧荧悄未收。", "自在开帘风不定，飕飕。", "池面冰澌趁水流。", "早起怯梳头。", "欲绾云鬟又却休。", "不会沈吟思底事，凝眸。", "两点春山满镜愁。"]'),
('song-ci-380','望江南・忆江南','周邦彦','宋','宋词','song-ci','望江南・忆江南','[]','游妓散，独自绕回堤。',64,'宋词/ci.song.4000.json','["游妓散，独自绕回堤。", "芳草怀烟迷水曲，密云衔雨暗城西。", "九陌未沾泥。", "桃李下，春晚未成蹊。", "墙外见花寻路转，柳阴行马过莺啼。", "无处不凄凄。"]'),
('song-ci-381','浣溪沙','周邦彦','宋','宋词','song-ci','浣溪沙','[]','争挽桐花两鬓垂。',48,'宋词/ci.song.4000.json','["争挽桐花两鬓垂。", "小妆弄影照清池。", "出帘踏袜趁蜂儿。", "跳脱添金双腕重，琵琶拨尽四弦悲。", "夜寒谁肯剪春衣。"]'),
('song-ci-382','浣溪沙','周邦彦','宋','宋词','song-ci','浣溪沙','[]','雨过残红湿未飞。',48,'宋词/ci.song.4000.json','["雨过残红湿未飞。", "珠帘一行透斜晖。", "游蜂酿蜜窃香归。", "金屋无人风竹乱，衣篝尽日水沈微。", "一春须有忆人时。"]'),
('song-ci-383','浣溪沙','周邦彦','宋','宋词','song-ci','浣溪沙','[]','楼上晴天碧四垂。',48,'宋词/ci.song.4000.json','["楼上晴天碧四垂。", "楼前芳草接天涯。", "劝君莫上最高梯。", "新笋已成堂下竹，落花都上燕巢泥。", "忍听林表杜鹃啼。"]'),
('song-ci-384','迎春乐','周邦彦','宋','宋词','song-ci','迎春乐','[]','清池小圃开云屋。',65,'宋词/ci.song.4000.json','["清池小圃开云屋。", "结春伴、往来熟。", "忆年时，纵酒杯行速。", "看月上、归禽宿。", "墙里修篁森似束。", "记名字、曾刊新绿。", "见说别来长，沿翠藓、封寒玉。"]'),
('song-ci-385','迎春乐','周邦彦','宋','宋词','song-ci','迎春乐','[]','桃蹊柳曲闲踪迹。',65,'宋词/ci.song.4000.json','["桃蹊柳曲闲踪迹。", "俱曾是、大堤客。", "解春衣、贳酒城南陌。", "频醉卧、胡姬侧。", "鬓点吴霜嗟早白。", "更谁念、玉溪消息。", "他日水云身，相望处，无南北。"]'),
('song-ci-386','点绛唇','周邦彦','宋','宋词','song-ci','点绛唇','[]','台上披襟，快风一瞬收残雨。',50,'宋词/ci.song.4000.json','["台上披襟，快风一瞬收残雨。", "柳丝轻举。", "蛛网粘飞絮。", "极目平芜，应是春归处。", "愁凝伫。", "楚歌声苦。", "村落黄昏鼓。"]'),
('song-ci-387','一落索','周邦彦','宋','宋词','song-ci','一落索','[]','眉共春山争秀。',56,'宋词/ci.song.4000.json','["眉共春山争秀。", "可怜长皱。", "莫将清泪湿花枝，恐花也、如人瘦。", "清润玉箫闲久。", "知音稀有。", "欲知日日倚阑愁，但问取、亭前柳。"]'),
('song-ci-388','一落索','周邦彦','宋','宋词','song-ci','一落索','[]','杜宇思归声苦。',56,'宋词/ci.song.4000.json','["杜宇思归声苦。", "和春催去。", "倚阑一霎酒旗风，任扑面、桃花雨。", "目断陇云江树。", "难逢尺素。", "落霞隐隐日平西，料想是、分携处。"]'),
('song-ci-389','垂丝钓','周邦彦','宋','宋词','song-ci','垂丝钓','[]','缕金翠羽。',82,'宋词/ci.song.4000.json','["缕金翠羽。", "妆成才见眉妩。", "倦倚绣帘，看舞风絮。", "愁几许。", "寄凤丝雁柱。", "春将暮。", "向层城苑路。", "钿车似水，时时花径相遇。", "旧游伴侣。", "还到曾来处。", "门掩风和雨。", "梁间燕语。", "问那人在否。"]'),
('song-ci-390','满庭芳','周邦彦','宋','宋词','song-ci','满庭芳','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','风老莺雏，雨肥梅子，午阴嘉树清圆。',118,'宋词/ci.song.4000.json','["风老莺雏，雨肥梅子，午阴嘉树清圆。", "地卑山近，衣润费垆烟。", "人静乌鸢自乐，小桥外、新绿溅溅。", "凭栏久，黄芦苦竹，拟泛九江船。", "年年。", "如社燕，飘流瀚海，来寄修椽。", "且莫思身外，长近尊前。", "憔悴江南倦客，不堪听、急管繁弦。", "歌筵畔，先安簟枕，容我醉时眠。"]'),
('song-ci-391','隔浦莲・隔浦莲近拍','周邦彦','宋','宋词','song-ci','隔浦莲・隔浦莲近拍','[]','新篁摇动翠葆。',89,'宋词/ci.song.4000.json','["新篁摇动翠葆。", "曲径通深窈。", "夏果收新脆，金丸落、惊飞鸟。", "浓霭迷岸草。", "蛙声闹。", "骤雨鸣池沼。", "水亭小。", "浮萍破处，帘花檐影颠倒。", "纶巾羽扇，困卧北窗清晓。", "屏里吴山梦自到。", "惊觉。", "依然身在江表。"]'),
('song-ci-392','法曲献仙音','周邦彦','宋','宋词','song-ci','法曲献仙音','[]','蝉咽凉柯，燕飞尘幕，漏阁签声时度。',113,'宋词/ci.song.4000.json','["蝉咽凉柯，燕飞尘幕，漏阁签声时度。", "倦脱纶巾，困便湘竹，桐阴半侵朱户。", "向抱影凝情处。", "时闻打窗雨。", "耿无语。", "叹文圆、近来多病，情绪懒，尊酒易成间阻。", "缥缈玉京人，想依然、京兆眉妩。", "翠幕深中，对徽容、空在纨素。", "待花前月下，见了不教归去。"]'),
('song-ci-393','过秦楼','周邦彦','宋','宋词','song-ci','过秦楼','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','水浴清蟾，叶喧凉吹，巷陌马声初断。',135,'宋词/ci.song.4000.json','["水浴清蟾，叶喧凉吹，巷陌马声初断。", "闲依露井，笑扑流萤，惹破画罗轻扇。", "人静夜久凭阑，愁不归眠，立残更箭。", "叹年华一瞬，人今千里，梦沈书远。", "空见说、鬓怯琼梳，容销金镜，渐懒趁时匀染。", "梅风地溽，虹雨苔滋，一架舞红都变。", "谁信无憀，为伊才减江淹，情伤荀倩。", "但明河影下，还看稀星数点。"]'),
('song-ci-394','侧犯','周邦彦','宋','宋词','song-ci','侧犯','[]','暮霞霁雨，小莲出水红妆靓。',95,'宋词/ci.song.4000.json','["暮霞霁雨，小莲出水红妆靓。", "风定。", "看步袜江妃照明镜。", "飞萤度暗草，秉烛游花径。", "人静。", "携艳质、追凉就槐影。", "金环皓腕，雪藕清泉莹。", "谁念省。", "满身香、犹是旧荀令。", "见说胡姬，酒垆寂静。", "烟锁漠漠，藻池苔井。"]'),
('song-ci-395','塞翁吟','周邦彦','宋','宋词','song-ci','塞翁吟','[]','暗叶啼风雨，窗外晓色珑璁。',116,'宋词/ci.song.4000.json','["暗叶啼风雨，窗外晓色珑璁。", "散水麝，小池东。", "乱一岸芙蓉。", "蕲州簟展双纹浪，轻帐翠缕如空。", "梦念远别、泪痕重。", "淡铅脸斜红。", "忡忡。", "嗟憔悴、新宽带结，羞艳冶、都销镜中。", "有蜀纸、堪凭寄恨，等今夜、洒血书词，剪浊亲封。", "菖蒲渐老，早晚成花，教见薰风。"]'),
('song-ci-396','苏幕遮','周邦彦','宋','宋词','song-ci','苏幕遮','[]','燎沈香，消溽暑。',76,'宋词/ci.song.4000.json','["燎沈香，消溽暑。", "鸟雀呼晴，侵晓窥檐语。", "叶上初阳乾宿雨，水面清圆，一一风荷举。", "故乡遥，何日去。", "家住吴门，久作长安旅。", "五月渔郎相忆否。", "小楫轻舟，梦入芙蓉浦。"]'),
('song-ci-397','浣溪沙','周邦彦','宋','宋词','song-ci','浣溪沙','[]','日射敧红蜡蒂香。',48,'宋词/ci.song.4000.json','["日射敧红蜡蒂香。", "风乾微汗粉襟凉。", "碧纱对掩簟纹光。", "自剪柳枝明画阁，戏抛莲菂种横塘。", "长亭无事好思量。"]'),
('song-ci-398','浣溪沙','周邦彦','宋','宋词','song-ci','浣溪沙','[]','翠葆参差竹径成。',48,'宋词/ci.song.4000.json','["翠葆参差竹径成。", "新荷跳雨泪珠倾。", "曲阑斜转小池亭。", "风约帘衣归燕急，水摇扇影戏鱼惊。", "柳梢残日弄微晴。"]'),
('song-ci-399','浣溪沙','周邦彦','宋','宋词','song-ci','浣溪沙','[]','薄薄纱橱望似空。',48,'宋词/ci.song.4000.json','["薄薄纱橱望似空。", "簟纹如水浸芙蓉。", "起来娇眼未惺惚。", "强整罗衣抬皓腕，更将纨扇掩酥胸。", "羞郎何事面微红。"]'),
('song-ci-400','浣溪沙','周邦彦','宋','宋词','song-ci','浣溪沙','[]','宝扇轻圆浅画缯。',48,'宋词/ci.song.4000.json','["宝扇轻圆浅画缯。", "象床平稳细穿藤。", "飞蝇不到避壶冰。", "翠枕面凉频忆睡，玉箫手汗错成声。", "日长无力要人凭。"]'),
('song-ci-401','点绛唇','周邦彦','宋','宋词','song-ci','点绛唇','[]','征骑初停，酒行莫放离歌举。',50,'宋词/ci.song.4000.json','["征骑初停，酒行莫放离歌举。", "柳汀莲浦。", "看尽江南路。", "苦恨斜阳，冉冉催人去。", "空回顾。", "淡烟横素。", "不见扬鞭处。"]'),
('song-ci-402','诉衷情','周邦彦','宋','宋词','song-ci','诉衷情','[]','出林杏子落金盘。',54,'宋词/ci.song.4000.json','["出林杏子落金盘。", "齿软怕尝酸。", "可惜半残青紫，犹有小唇丹。", "南陌上，落花闲。", "雨斑斑。", "不言不语，一段伤春，都在眉间。"]'),
('song-ci-403','风流子','周邦彦','宋','宋词','song-ci','风流子','[]','枫林凋晚叶，关河迥，楚客惨将归。',135,'宋词/ci.song.4000.json','["枫林凋晚叶，关河迥，楚客惨将归。", "望一川暝霭，雁声哀怨，半规凉月，人影参差。", "酒醒后，泪花销凤蜡，风幕卷金泥。", "砧杵韵高，唤回残梦，绮罗香减，牵起馀悲。", "亭皋分襟地，难拚处、偏是掩面牵衣。", "何况怨怀长结，重见无期。", "想寄恨书中，银钩空满，断肠声里，玉筋还垂。", "多少暗愁密意，唯有天知。"]'),
('song-ci-404','华胥引','周邦彦','宋','宋词','song-ci','华胥引','[]','川原澄映，烟月冥濛，去舟如叶。',104,'宋词/ci.song.4000.json','["川原澄映，烟月冥濛，去舟如叶。", "岸足沙平，蒲根水冷留雁唼。", "别有孤角吟秋，对晓风呜轧。", "红日三竿，醉头扶起还怯。", "离思相萦，渐看看、鬓丝堪镊。", "舞衫歌扇，何人轻怜细阅。", "点检从前恩爱，但凤笺盈箧，愁剪灯花，夜来和泪双叠。"]'),
('song-ci-405','宴清都','周邦彦','宋','宋词','song-ci','宴清都','[]','地僻无锺鼓。',126,'宋词/ci.song.4000.json','["地僻无锺鼓。", "残灯灭，夜长人倦难度。", "寒吹断梗，风翻暗雪，洒窗填户。", "宾鸿谩说传书，算过尽、千俦万侣。", "始信得、庾信愁多，江淹恨极须赋。", "凄凉病损文园，徽弦乍拂，音韵先苦。", "淮山夜月，金城暮草，梦魂飞去。", "秋霜半入清镜，叹带眼、都移旧处。", "更久长、不见文君，归时认否。"]'),
('song-ci-406','四园竹','周邦彦','宋','宋词','song-ci','四园竹','[]','浮云护月，未放满朱扉。',95,'宋词/ci.song.4000.json','["浮云护月，未放满朱扉。", "鼠摇暗壁，萤度破窗，偷入书帏。", "秋意浓，闲伫立、庭柯影里。", "好风襟袖先知。", "夜何其。", "江南路绕重山，心知谩与前期。", "奈向灯前堕泪，肠断萧娘，旧日书辞。", "犹在纸。", "雁信绝，清宵梦又稀。"]'),
('song-ci-407','齐天乐','周邦彦','宋','宋词','song-ci','齐天乐','[]','绿芜凋尽台城路，殊乡又逢秋晚。',123,'宋词/ci.song.4000.json','["绿芜凋尽台城路，殊乡又逢秋晚。", "暮雨生寒，鸣蛩劝织，深阁时闻裁剪。", "云窗静掩。", "叹重拂罗裀，顿疏花簟。", "尚有綀囊，露萤清夜照书卷。", "荆江留滞最久，故人相望处，离思何限。", "渭水西风，长安乱叶，空忆诗情宛转。", "凭高眺远。", "正玉液新篘，蟹螯初荐。", "醉倒山翁，但愁斜照敛。"]'),
('song-ci-408','木兰花・玉楼春','周邦彦','宋','宋词','song-ci','木兰花・玉楼春','[]','郊原雨过金英秀。',64,'宋词/ci.song.4000.json','["郊原雨过金英秀。", "风扫霜威寒入袖。", "感君一曲断肠歌，劝我十分和泪酒。", "古道尘清榆柳瘦。", "系马邮亭人散后。", "今宵灯尽酒醒时，可惜朱颜成皓首。"]'),
('song-ci-409','霜叶飞','周邦彦','宋','宋词','song-ci','霜叶飞','[]','露迷衰草。',135,'宋词/ci.song.4000.json','["露迷衰草。", "疏星挂，凉蟾低下林表。", "素娥青女斗婵娟，正倍添凄悄。", "渐飒飒、丹枫撼晓。", "横天云浪鱼鳞小。", "似故人相看，又透入、清辉半饷，特地留照。", "迢递望极关山，波穿千里，度日如岁难到。", "凤楼今夜听秋风，奈五更愁抱。", "想玉匣、哀弦闭了。", "无心重理相思调。", "见皓月、牵离恨，屏掩孤颦，泪流多少。"]'),
('song-ci-410','蕙兰芳引','周邦彦','宋','宋词','song-ci','蕙兰芳引','[]','寒莹晚空，点清镜、断霞孤鹜。',103,'宋词/ci.song.4000.json','["寒莹晚空，点清镜、断霞孤鹜。", "对客馆深扃，霜草未衰更绿。", "倦游厌旅，但梦绕、阿娇金屋。", "想故人别后，尽日空疑风竹。", "塞北氍毹，江南图障，是处温燠。", "更花管云笺，犹写寄情旧曲。", "音尘迢递，但劳远目。", "今夜长，争奈枕单人独。"]'),
('song-ci-411','塞垣春','周邦彦','宋','宋词','song-ci','塞垣春','[]','暮色分平野。',117,'宋词/ci.song.4000.json','["暮色分平野。", "傍苇岸、征帆卸。", "烟村极浦，树藏孤馆，秋景如画。", "渐别离气味难禁也。", "更物象、供潇洒。", "念多材浑衰减，一怀幽恨难写。", "追念绮窗人，天然自、风韵娴雅。", "竟夕起相思，谩嗟怨遥夜。", "又还将、两袖珠泪，沈吟向寂寥寒灯下。", "玉骨为多感，瘦来无一把。"]'),
('song-ci-412','丁香结','周邦彦','宋','宋词','song-ci','丁香结','[]','苍藓沿阶，冷萤粘屋，庭树望秋先陨。',121,'宋词/ci.song.4000.json','["苍藓沿阶，冷萤粘屋，庭树望秋先陨。", "渐雨凄风迅。", "澹暮色，倍觉园林清润。", "汉姬纨扇在，重吟玩、弃掷未忍。", "登山临水，此恨自古，销磨不尽。", "牵引。", "记试酒归时，映月同看雁阵。", "宝幄香缨，熏炉象尺，夜寒灯晕。", "谁念留滞故国，旧事劳方寸。", "唯丹青相伴，那更尘昏蠹损。"]'),
('song-ci-413','氐州第一','周邦彦','宋','宋词','song-ci','氐州第一','[]','波落寒汀，村渡向晚，遥看数点帆小。',127,'宋词/ci.song.4000.json','["波落寒汀，村渡向晚，遥看数点帆小。", "乱叶翻鸦，惊风破雁，天角孤云缥缈。", "官柳萧疏，甚尚挂、微微残照。", "景物关情，川途换目，顿来催老。", "渐解狂朋欢意少。", "奈犹被、思牵情绕。", "座上琴心，机中锦字，觉最萦怀抱。", "也知人、悬望久，蔷薇谢、归来一笑。", "欲梦高唐，未成眠、霜空又晓。"]'),
('song-ci-414','解蹀躞','周邦彦','宋','宋词','song-ci','解蹀躞','[]','候馆丹枫吹尽，面旋随风舞。',90,'宋词/ci.song.4000.json','["候馆丹枫吹尽，面旋随风舞。", "夜寒霜月，飞来伴孤旅。", "还是独拥秋衾，梦馀酒困都醒，满怀离苦。", "甚情绪。", "深念凌波微步。", "幽房暗相遇，泪珠都作，秋宵枕前雨。", "此恨音驿难通，待凭征雁归时，带将愁去。"]'),
('song-ci-415','少年游','周邦彦','宋','宋词','song-ci','少年游','[]','并刀如水，吴盐胜雪，纤手破新橙。',62,'宋词/ci.song.4000.json','["并刀如水，吴盐胜雪，纤手破新橙。", "锦幄初温，兽烟不断，相对坐调笙。", "低声问向谁行宿，城上已三更。", "马滑霜浓，不如休去，直是少人行。"]'),
('song-ci-416','庆春宫・高阳台','周邦彦','宋','宋词','song-ci','庆春宫・高阳台','[]','云接平冈，山围寒野，路回渐转孤城。',126,'宋词/ci.song.4000.json','["云接平冈，山围寒野，路回渐转孤城。", "衰柳啼鸦，惊风驱雁，动人一片秋声。", "倦途休驾，澹烟里、微茫见星。", "尘埃憔悴，生怕黄昏，离思牵萦。", "华堂旧日逢迎。", "花艳参差，香雾飘零。", "弦管当头，偏怜娇凤，夜深簧暖笙清。", "眼波传意，恨密约、匆匆未成。", "许多烦恼，只为当时，一饷留情。"]'),
('song-ci-417','醉桃源・阮郎归','周邦彦','宋','宋词','song-ci','醉桃源・阮郎归','[]','冬衣初染远山青。',56,'宋词/ci.song.4000.json','["冬衣初染远山青。", "双丝云雁绫。", "夜寒袖湿欲成冰。", "都缘珠泪零。", "情黯黯，闷腾腾。", "身如秋后蝇。", "若教随马逐郎行。", "不辞多少程。"]'),
('song-ci-418','醉桃源・阮郎归','周邦彦','宋','宋词','song-ci','醉桃源・阮郎归','[]','菖蒲叶老水平沙。',56,'宋词/ci.song.4000.json','["菖蒲叶老水平沙。", "临流苏小家。", "画阑曲径宛秋蛇。", "金英垂露华。", "烧蜜炬，引莲娃。", "酒香薰脸霞。", "再来重约日西斜。", "倚门听暮鸦。"]'),
('song-ci-419','点绛唇','周邦彦','宋','宋词','song-ci','点绛唇','[]','孤馆迢迢，暮天草露沾衣润。',50,'宋词/ci.song.4000.json','["孤馆迢迢，暮天草露沾衣润。", "夜来秋近。", "月晕通风信。", "今日原头，黄叶飞成阵。", "知人闷。", "故来相趁。", "共结临岐恨。"]'),
('song-ci-420','夜游宫','周邦彦','宋','宋词','song-ci','夜游宫','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','叶下斜阳照水。',71,'宋词/ci.song.4000.json','["叶下斜阳照水。", "卷轻浪、沈沈千里。", "桥上酸风射眸子。", "立多时，看黄昏，灯火市。", "古屋寒窗底。", "听几片、井桐飞坠。", "不恋单衾再三起。", "有谁知，为萧娘，书一纸。"]'),
('song-ci-421','夜游宫','周邦彦','宋','宋词','song-ci','夜游宫','[]','客去车尘未敛。',71,'宋词/ci.song.4000.json','["客去车尘未敛。", "古帘暗、雨苔千点。", "月皎风清在处见。", "奈今宵，照初弦，吹一箭。", "池曲河声转。", "念归计，眼迷魂乱。", "明日前村更荒远。", "且开尊，任红鳞，生酒面。"]'),
('song-ci-422','诉衷情','周邦彦','宋','宋词','song-ci','诉衷情','[]','堤前亭午未融霜。',54,'宋词/ci.song.4000.json','["堤前亭午未融霜。", "风紧雁无行。", "重寻旧日岐路，茸帽北游装。", "期信杳，别离长。", "远情伤。", "风翻酒幔，寒凝茶烟，又是何乡。"]'),
('song-ci-423','伤情怨・清商怨','周邦彦','宋','宋词','song-ci','伤情怨・清商怨','[]','枝头风势渐小。',51,'宋词/ci.song.4000.json','["枝头风势渐小。", "看暮鸦飞了。", "又是黄昏，闭门收返照。", "江南人去路缈。", "信未通、愁已先到。", "怕见孤灯，霜寒催睡早。"]'),
('song-ci-424','红林擒近','周邦彦','宋','宋词','song-ci','红林擒近','[]','高柳春才软，冻梅寒更香。',94,'宋词/ci.song.4000.json','["高柳春才软，冻梅寒更香。", "暮雪助清峭，玉尘散林塘。", "那堪飘风递冷，故遣度幕穿窗。", "似欲料理新妆。", "呵手弄丝簧。", "冷落词赋客，萧索水云乡。", "援毫授简，风流犹忆东梁。", "望虚檐徐转，迥廊未扫，夜长莫惜空酒觞。"]'),
('song-ci-425','红林擒近','周邦彦','宋','宋词','song-ci','红林擒近','[]','风雪惊初霁，水乡增暮寒。',94,'宋词/ci.song.4000.json','["风雪惊初霁，水乡增暮寒。", "树杪坠飞羽，檐牙挂琅玕。", "才喜门堆巷积，可惜迤逦销残。", "渐看低竹翩翻。", "清池涨微澜。", "步屐晴正好，宴席晚方欢。", "梅花耐冷，亭亭来入冰盘。", "对前山横素，愁云变色，放杯同觅高处看。"]'),
('song-ci-426','满路花・促拍满路花','周邦彦','宋','宋词','song-ci','满路花・促拍满路花','[]','金花落烬灯，银砾鸣窗雪。',101,'宋词/ci.song.4000.json','["金花落烬灯，银砾鸣窗雪。", "夜深微漏断，行人绝。", "风扉不定，竹圃琅玕折。", "玉人新间阔。", "著甚情悰，更当恁地时节。", "无言敧枕，帐底流清血。", "愁如春后絮，来相接。", "知他那里，争信人心切。", "除共天公说。", "不成也还，似伊无个分别。"]'),
('song-ci-427','解语花','周邦彦','宋','宋词','song-ci','解语花','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','风销焰蜡，露浥烘炉。',124,'宋词/ci.song.4000.json','["风销焰蜡，露浥烘炉。", "花市光相射。", "桂华流瓦。", "纤云散，耿耿素娥欲下。", "衣裳淡雅。", "看楚女、纤腰一把。", "箫鼓喧，人影参差，满路飘香麝。", "因念都城放夜。", "望千门如昼，嬉笑游冶。", "钿车罗帕。", "相逢处，自有暗尘随马。", "年光是也。", "唯只见、旧情衰谢。", "清漏移，飞盖归来，从舞休歌罢。"]'),
('song-ci-428','六么令','周邦彦','宋','宋词','song-ci','六么令','[]','快风收雨，亭馆清残燠。',112,'宋词/ci.song.4000.json','["快风收雨，亭馆清残燠。", "池光静横秋影，岸柳如新沐。", "闻道宜城酒美，昨日新醅熟。", "轻镳相逐。", "冲泥策马，来折东篱半开菊。", "华堂花艳对列，一一惊郎目。", "歌韵巧共泉声，间杂琮琤玉。", "惆怅周郎已老，莫唱当时曲。", "幽欢难卜。", "明年谁健，更把茱萸再三嘱。"]'),
('song-ci-429','倒犯','周邦彦','宋','宋词','song-ci','倒犯','[]','霁景、对霜蟾乍升，素烟如扫。',129,'宋词/ci.song.4000.json','["霁景、对霜蟾乍升，素烟如扫。", "千林夜缟。", "徘徊处、渐移深窈。", "何人正弄，孤影蹁跹，西窗悄。", "冒霜冷貂裘，玉斝邀云表。", "共寒光、饮清醥。", "淮左旧游，记送行人，归来山路窵。", "驻马望素魄，印遥碧、金枢小。", "爱秀色、初娟好。", "念漂浮、绵绵思远道。", "料异日宵征，必定还相照。", "奈何人自衰老。"]'),
('song-ci-430','大','周邦彦','宋','宋词','song-ci','大','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','对宿烟收，春禽静，飞雨时鸣高屋。',164,'宋词/ci.song.4000.json','["对宿烟收，春禽静，飞雨时鸣高屋。", "墙头青玉旆，洗铅霜都尽，嫩梢相触。", "润逼琴丝，寒侵枕障，虫网吹沾帘竹。", "邮亭无人处，听檐声不断，困眠初熟。", "奈愁极顿惊，梦轻难记，自怜幽独。", "行人归意速。", "最先念、流潦妨车毂。", "怎奈向、兰成憔悴，卫玠清羸，等闲时、易伤心目。", "未怪平阳客，双泪落、笛中哀曲。", "况萧索、青芜国。", "红糁铺地，门外荆桃如菽。", "夜游共谁秉烛。"]'),
('song-ci-431','玉烛新','周邦彦','宋','宋词','song-ci','玉烛新','[]','溪源新腊后。',124,'宋词/ci.song.4000.json','["溪源新腊后。", "见数朵江梅，剪裁初就。", "晕酥砌玉芳英嫩，故把春心轻漏。", "前村昨夜，想弄月、黄昏时候。", "孤岸峭，疏影横斜，浓香暗沾襟袖。", "尊前赋与多材，问岭外风光，故人知否。", "寿阳谩斗。", "终不似，照水一枝清瘦。", "风娇雨秀。", "好乱插、繁花盈首。", "须信道，羌管无情，看看又奏。"]'),
('song-ci-432','花犯','周邦彦','宋','宋词','song-ci','花犯','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','粉墙低，梅花照眼，依然旧风味。',126,'宋词/ci.song.4000.json','["粉墙低，梅花照眼，依然旧风味。", "露痕轻缀。", "疑净洗铅华，无限佳丽。", "去年胜赏曾孤倚。", "冰盘同宴喜。", "更可惜，雪中高树，香篝熏素被。", "今年对花最匆匆，相逢似有恨，依依愁悴。", "吟望久，青苔上、旋看飞坠。", "相将见、脆丸荐酒，人正在、空江烟浪里。", "但梦想、一枝潇洒，黄昏斜照水。"]'),
('song-ci-433','丑奴儿・采桑子','周邦彦','宋','宋词','song-ci','丑奴儿・采桑子','[]','肌肤绰约真仙子，来伴冰霜。',52,'宋词/ci.song.4000.json','["肌肤绰约真仙子，来伴冰霜。", "洗尽铅黄。", "素面初无一点妆。", "寻花不用持银烛，暗里闻香。", "零落池塘。", "分付馀妍与寿阳。"]'),
('song-ci-434','水龙吟','周邦彦','宋','宋词','song-ci','水龙吟','[]','素肌应怯馀寒，艳阳占立青芜地。',126,'宋词/ci.song.4000.json','["素肌应怯馀寒，艳阳占立青芜地。", "樊川照日，灵关遮路，残红敛避。", "传火楼台，妒花风雨，长门深闭。", "亚帘栊半湿，一枝在手，偏勾引、黄昏泪。", "别有风前月底。", "布繁英、满圆歌吹。", "朱铅退尽，潘妃却酒，昭君乍起。", "雪浪翻空，粉裳缟夜，不成春意。", "恨玉容不见，琼英谩好，与何人比。"]'),
('song-ci-435','六丑','周邦彦','宋','宋词','song-ci','六丑','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','正单衣试酒，恨客里、光阴虚掷。',172,'宋词/ci.song.4000.json','["正单衣试酒，恨客里、光阴虚掷。", "愿春暂留，春归如过翼。", "一去无迹。", "为问花何在，夜来风雨，葬楚宫倾国。", "钗钿堕处遗香泽。", "乱点桃蹊，轻翻柳陌。", "多情为谁追惜。", "但蜂媒蝶使，时叩窗隔。", "东园岑寂。", "渐蒙笼暗碧。", "静绕珍丛底，成叹息。", "长条故惹行客。", "似牵衣待话，别情无极。", "残英小、强簪巾帻。", "终不似一朵，钗头颤袅，向人敧侧。", "漂流处、莫趁潮汐。", "恐断红、尚有相思字，何由见得。"]'),
('song-ci-436','虞美人','周邦彦','宋','宋词','song-ci','虞美人','[]','金闺平帖春云暖。',66,'宋词/ci.song.4000.json','["金闺平帖春云暖。", "昼漏花前短。", "玉颜酒解艳红消。", "一面捧心啼困、不成娇。", "别来新翠迷行径。", "窗锁玲珑影。", "砑绫小字夜来封。", "斜倚曲栏凝睇、数归鸿。"]'),
('song-ci-437','虞美人','周邦彦','宋','宋词','song-ci','虞美人','[]','廉纤小雨池塘遍。',66,'宋词/ci.song.4000.json','["廉纤小雨池塘遍。", "细点看萍面。", "一双燕子守朱门。", "比似寻常时候、易黄昏。", "宜城酒泛浮香絮。", "细作更阑语。", "相将羁思乱如云。", "又是一窗灯影、两愁人。"]'),
('song-ci-438','兰陵王','周邦彦','宋','宋词','song-ci','兰陵王','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','柳阴直。',159,'宋词/ci.song.4000.json','["柳阴直。", "烟里丝丝弄碧。", "隋堤上、曾见几番，拂水飘绵送行色。", "登临望故国。", "谁识。", "京华倦客。", "长亭路，年去岁来，应折柔条过千尺。", "闲寻旧踪迹。", "又酒趁哀弦，灯照离席。", "梨花榆火催寒食。", "愁一箭风快，半篙波暖，回头迢递便数驿。", "望人在天北。", "凄恻。", "恨堆积。", "渐别浦萦回，津堠岑寂。", "斜阳冉冉春无极。", "念月榭携手，露桥闻笛。", "沈思前事，似梦里，泪暗滴。"]'),
('song-ci-439','蝶恋花','周邦彦','宋','宋词','song-ci','蝶恋花','[]','爱日轻明新雪后。',70,'宋词/ci.song.4000.json','["爱日轻明新雪后。", "柳眼星星，渐欲穿窗牖。", "不待长亭倾别酒。", "一枝已入骚人手。", "浅浅挼蓝轻蜡透。", "过尽冰霜，便与春争秀。", "强对青铜簪白首。", "老来风味难依旧。"]'),
('song-ci-440','蝶恋花','周邦彦','宋','宋词','song-ci','蝶恋花','[]','桃萼新香梅落后。',70,'宋词/ci.song.4000.json','["桃萼新香梅落后。", "暗叶藏鸦，苒苒垂亭牖。", "舞困低迷如著酒。", "乱丝偏近游人手。", "雨过朦胧斜日透。", "客舍青青，特地添明秀。", "莫话扬鞭回别首。", "渭城荒远无交旧。"]'),
('song-ci-441','蝶恋花','周邦彦','宋','宋词','song-ci','蝶恋花','[]','蠢蠢黄金初脱后。',70,'宋词/ci.song.4000.json','["蠢蠢黄金初脱后。", "暖日飞绵，取次粘窗牖。", "不见长条低拂酒。", "赠行应已输先手。", "莺掷金梭飞不透。", "小榭危楼，处处添奇秀。", "何日隋堤萦马首。", "路长人倦空思旧。"]'),
('song-ci-442','蝶恋花','周邦彦','宋','宋词','song-ci','蝶恋花','[]','小阁阴阴人寂后。',70,'宋词/ci.song.4000.json','["小阁阴阴人寂后。", "翠幕褰风，烛影摇疏牖。", "夜半霜寒初索酒。", "金刀正在柔荑手。", "彩薄粉轻光欲透。", "小叶尖新，未放双眉秀。", "记得长条垂鹢首。", "别离情味还依旧。"]'),
('song-ci-443','西河','周邦彦','宋','宋词','song-ci','西河','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','佳丽地。',126,'宋词/ci.song.4000.json','["佳丽地。", "南朝盛事谁记。", "山围故国绕清江，髻鬟对起。", "怒涛寂寞打孤城，风樯遥度天际。", "断崖树，犹倒倚。", "莫愁艇子曾系。", "空馀旧迹郁苍苍，雾沈半垒。", "夜深月过女墙来，赏心东望淮水。", "酒旗戏鼓甚处市。", "想依稀、王谢邻里。", "燕子不知何世。", "入寻常、巷陌人家，相对如说兴亡，斜阳里。"]'),
('song-ci-444','归去难・促拍满路花','周邦彦','宋','宋词','song-ci','归去难・促拍满路花','[]','佳约人未知，背地伊先变。',101,'宋词/ci.song.4000.json','["佳约人未知，背地伊先变。", "恶会称停事，看深浅。", "如今信我，委的论长远。", "好来无可怨。", "洎合教伊，因些事后分散。", "密意都休，待说先肠断。", "此恨除非是，天相念。", "坚心更守，未死终相见。", "多少闲磨难。", "到得其时，知他做甚头眼。"]'),
('song-ci-445','三部乐','周邦彦','宋','宋词','song-ci','三部乐','[]','浮玉飞琼，向邃馆静轩，倍增清绝。',122,'宋词/ci.song.4000.json','["浮玉飞琼，向邃馆静轩，倍增清绝。", "夜窗垂练，何用交光明月。", "近闻道、官阁多梅，趁暗香未远，冻蕊初发。", "倩谁摘取，寄赠情人桃叶。", "回文近传锦字，道为君瘦损，是人都说。", "祆知染红著手，胶梳粘发。", "转思量、镇长堕睫。", "都只为、情深意切。", "欲报消息，无一句、堪愈愁结。"]'),
('song-ci-446','菩萨蛮','周邦彦','宋','宋词','song-ci','菩萨蛮','[]','银河宛转三千曲。',52,'宋词/ci.song.4000.json','["银河宛转三千曲。", "浴凫飞鹭澄波绿。", "何处是归舟。", "夕阳江上楼。", "天憎梅浪发。", "故下封枝雪。", "深院卷帘看。", "应怜江上寒。"]'),
('song-ci-447','品令','周邦彦','宋','宋词','song-ci','品令','[]','夜阑人静。',67,'宋词/ci.song.4000.json','["夜阑人静。", "月痕寄、梅梢疏影。", "帘外曲角栏干近。", "旧携手处，花发雾寒成阵。", "应是不禁愁与恨。", "纵相逢难问。", "黛眉曾把春衫印。", "后期无定。", "断肠香销尽。"]'),
('song-ci-448','玉楼春','周邦彦','宋','宋词','song-ci','玉楼春','[]','玉琴虚下伤心泪。',64,'宋词/ci.song.4000.json','["玉琴虚下伤心泪。", "只有文君知曲意。", "帘烘楼迥月宜人，酒暖香融春有味。", "萋萋芳草迷千里。", "惆怅王孙行未已。", "天涯回首一销魂，二十四桥歌舞地。"]'),
('song-ci-449','黄鹂绕碧树','周邦彦','宋','宋词','song-ci','黄鹂绕碧树','[]','双阙笼嘉气，寒威日晚，岁华将暮。',119,'宋词/ci.song.4000.json','["双阙笼嘉气，寒威日晚，岁华将暮。", "小院闲庭，对寒梅照雪，淡烟凝素。", "忍当迅景，动无限、伤春情绪。", "犹赖是、上苑风光渐好，芳容将煦。", "草荚兰芽渐吐。", "且寻芳、更休思虑。", "这浮世、甚驱驰利禄，奔竞尘土。", "纵有魏珠照乘，未买得流年住。", "争如盛饮流霞，醉偎琼树。"]'),
('song-ci-450','满路花・促拍满路花','周邦彦','宋','宋词','song-ci','满路花・促拍满路花','[]','帘烘泪雨乾，酒压愁城破。',101,'宋词/ci.song.4000.json','["帘烘泪雨乾，酒压愁城破。", "冰壶防饮渴，培残火。", "朱消粉退，绝胜新梳裹。", "不是寒宵短，日上三竿，殢人犹要同卧。", "如今多病，寂寞章台左。", "黄昏风弄雪，门深锁。", "兰房密爱，万种思量过。", "也须知有我。", "著甚情悰，你但忘了人呵。"]'),
('song-ci-451','绮寮怨','周邦彦','宋','宋词','song-ci','绮寮怨','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','上马人扶残醉，晓风吹未醒。',129,'宋词/ci.song.4000.json','["上马人扶残醉，晓风吹未醒。", "映水曲、翠瓦朱檐，垂杨里、乍见津亭。", "当时曾题败壁，蛛丝罩、淡墨苔晕青。", "念去来、岁月如流，徘徊久、叹息愁思盈。", "去去倦寻路程。", "江陵旧事，何曾再问杨琼。", "旧曲凄清。", "敛愁黛、与谁听。", "尊前故人如在，想念我、最关情。", "何须渭城。", "歌声未尽处，先泪零。"]'),
('song-ci-452','拜星月・拜星月慢','周邦彦','宋','宋词','song-ci','拜星月・拜星月慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','夜色催更，清尘收露，小曲幽坊月暗。',125,'宋词/ci.song.4000.json','["夜色催更，清尘收露，小曲幽坊月暗。", "竹槛灯窗，识秋娘庭院。", "笑相遇，似觉琼枝玉树，暖日明霞光烂。", "水眄兰情，总平生稀见。", "画图中、旧识春风面。", "谁知道、自到瑶台畔。", "眷恋雨润云温，苦惊风吹散。", "念荒寒、寄宿无人馆。", "重门闭、败壁秋虫叹。", "怎奈向、一缕相思，隔溪山不断。"]'),
('song-ci-453','尉迟杯','周邦彦','宋','宋词','song-ci','尉迟杯','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','隋堤路。',129,'宋词/ci.song.4000.json','["隋堤路。", "渐日晚、密霭生深树。", "阴阴淡月笼沙，还宿河桥深处。", "无情画舸，都不管、烟波隔南浦。", "等行人、醉拥重衾，载将离恨归去。", "因念旧客京华，长偎傍、疏林小槛欢聚。", "冶叶倡条俱相识，仍惯见、珠歌翠舞。", "如今向、渔村水驿，夜如岁、焚香独自语。", "有何人、念我无憀，梦魂凝想鸳侣。"]'),
('song-ci-454','绕佛阁','周邦彦','宋','宋词','song-ci','绕佛阁','[]','暗尘四敛。',123,'宋词/ci.song.4000.json','["暗尘四敛。", "楼观迥出，高映孤馆。", "清漏将短。", "厌闻夜久，签声动书幔。", "桂华又满。", "闲步露草，偏爱幽远。", "花气清婉，望中迤逦，城阴度河岸。", "倦客最萧索，醉倚斜桥穿柳线。", "还似汴堤，虹梁横水面。", "看浪飐春灯，舟下如箭。", "此行重见。", "叹故友难逢，羁思空乱。", "两眉愁、向谁舒展。"]'),
('song-ci-455','一寸金','周邦彦','宋','宋词','song-ci','一寸金','[]','州夹苍崖，下枕江山是城郭。',133,'宋词/ci.song.4000.json','["州夹苍崖，下枕江山是城郭。", "望海霞接日，红翻水面，晴风吹草，青摇山脚。", "波暖凫鷖作。", "沙痕退、夜潮正落。", "疏林外、一点炊烟，渡口参差正寥廓。", "自叹劳生，经年何事，京华信漂泊。", "念渚蒲汀柳，空归闲梦，风轮雨楫，终辜前约。", "情景牵心眼，流连处、利名易薄。", "回头谢、冶叶倡条，便入渔钓乐。"]'),
('song-ci-456','蝶恋花','周邦彦','宋','宋词','song-ci','蝶恋花','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','月皎惊乌栖不定。',71,'宋词/ci.song.4000.json','["月皎惊乌栖不定。", "更漏将残，轣辘，牵金井。", "唤起两眸清炯炯。", "泪花落枕红棉泠。", "执手霜风吹鬓影。", "去意徊徨，别语愁难听。", "楼上阑干横斗柄。", "露寒人远鸡相应。"]'),
('song-ci-457','如梦令','周邦彦','宋','宋词','song-ci','如梦令','[]','尘满一絣文绣。',40,'宋词/ci.song.4000.json','["尘满一絣文绣。", "泪湿领巾红皱。", "初暖绮罗轻，腰胜武昌官柳。", "长昼。", "长昼。", "困卧午窗中酒。"]'),
('song-ci-458','如梦令','周邦彦','宋','宋词','song-ci','如梦令','[]','门外迢迢行路。',40,'宋词/ci.song.4000.json','["门外迢迢行路。", "谁送郎边尺素。", "巷陌雨馀风，当面湿花飞去。", "无绪。", "无绪。", "闲处偷垂玉箸。"]'),
('song-ci-459','月中行・月宫春','周邦彦','宋','宋词','song-ci','月中行・月宫春','[]','蜀丝趁日染乾红。',59,'宋词/ci.song.4000.json','["蜀丝趁日染乾红。", "微暖面脂融。", "博山细篆霭房栊。", "静看打窗虫。", "愁多胆怯疑虚幕，声不断、暮景疏钟。", "团团四壁小屏风。", "啼尽梦魂中。"]'),
('song-ci-460','浣沙溪・浣溪沙','周邦彦','宋','宋词','song-ci','浣沙溪・浣溪沙','[]','日薄尘飞官路平。',48,'宋词/ci.song.4000.json','["日薄尘飞官路平。", "眼前喜见汴河倾。", "地遥人倦莫兼程。", "下马先寻题壁字，出门闲记榜村名。", "早收灯火梦倾城。"]'),
('song-ci-461','浣沙溪・浣溪沙','周邦彦','宋','宋词','song-ci','浣沙溪・浣溪沙','[]','贪向津亭拥去车。',48,'宋词/ci.song.4000.json','["贪向津亭拥去车。", "不辞泥雨溅罗襦。", "泪多脂粉了无馀。", "酒酽未须令客醉，路长终是少人扶。", "早教幽梦到华胥。"]'),
('song-ci-462','浣沙溪・浣溪沙','周邦彦','宋','宋词','song-ci','浣沙溪・浣溪沙','[]','不为萧娘旧约寒。',48,'宋词/ci.song.4000.json','["不为萧娘旧约寒。", "何因容易别长安。", "预愁衣上粉痕乾。", "幽阁深沈灯焰喜，小炉邻近酒杯宽。", "为君门外脱归鞍。"]'),
('song-ci-463','点绛唇','周邦彦','宋','宋词','song-ci','点绛唇','[]','辽鹤归来，故乡多少伤心地。',50,'宋词/ci.song.4000.json','["辽鹤归来，故乡多少伤心地。", "寸书不寄。", "鱼浪空千里。", "凭仗桃根，说与凄凉意。", "愁无际。", "旧时衣袂。", "犹有东门泪。"]'),
('song-ci-464','少年游','周邦彦','宋','宋词','song-ci','少年游','[]','檐牙缥缈小倡楼。',60,'宋词/ci.song.4000.json','["檐牙缥缈小倡楼。", "凉月挂银钩。", "聒席笙歌，透帘灯火，风景似扬州。", "当时面色欺春雪，曾伴美人游。", "今日重来，更无人问，独自倚阑愁。"]'),
('song-ci-465','望江南・忆江南','周邦彦','宋','宋词','song-ci','望江南・忆江南','[]','歌席上，无赖是横波。',64,'宋词/ci.song.4000.json','["歌席上，无赖是横波。", "宝髻玲珑敧玉燕，绣巾柔腻掩香罗。", "人好自宜多。", "无个事，因甚敛双蛾。", "浅淡梳妆疑见画，惺忪言语胜闻歌。", "何况会婆娑。"]'),
('song-ci-466','意难忘','周邦彦','宋','宋词','song-ci','意难忘','[]','衣染莺黄。',114,'宋词/ci.song.4000.json','["衣染莺黄。", "爱停歌驻拍，劝酒持觞。", "低鬟蝉影动，私语口脂香。", "檐露滴，竹风凉。", "拚剧饮淋浪。", "夜渐深，笼灯就月，子细端相。", "知音见说无双。", "解移宫换羽，未怕周郎。", "长颦知有恨，贪耍不成妆。", "些个事，恼人肠。", "试说与何妨。", "又恐伊、寻消问息，瘦减容光。"]'),
('song-ci-467','迎春乐','周邦彦','宋','宋词','song-ci','迎春乐','[]','人人花艳明春柳。',64,'宋词/ci.song.4000.json','["人人花艳明春柳。", "忆筵上、偷携手。", "趁歌停舞罢来相就。", "醒醒个、无些酒。", "比目香囊新刺绣。", "连隔座、一时薰透。", "为甚月中归，长是他、随车后。"]'),
('song-ci-468','定风波','周邦彦','宋','宋词','song-ci','定风波','[]','莫倚能歌敛黛眉。',70,'宋词/ci.song.4000.json','["莫倚能歌敛黛眉。", "此歌能有几人知。", "他日相逢花月底。", "重理。", "好声须记得来时。", "苦恨城头更漏永，无情岂解惜分飞。", "休诉金尊推玉臂。", "从醉。", "明朝有酒遣谁持。"]'),
('song-ci-469','红罗袄','周邦彦','宋','宋词','song-ci','红罗袄','[]','画烛寻欢去，羸马载愁归。',65,'宋词/ci.song.4000.json','["画烛寻欢去，羸马载愁归。", "念取酒东垆，尊罍虽近，采花南浦，蜂蝶须知。", "自分袂、天阔鸿稀。", "空怀梦约心期。", "楚客忆江蓠。", "算宋玉、未必为秋悲。"]'),
('song-ci-470','玉楼春','周邦彦','宋','宋词','song-ci','玉楼春','[]','当时携手城东道。',64,'宋词/ci.song.4000.json','["当时携手城东道。", "月堕檐牙人睡了。", "酒边难使客愁惊，帐底不教春梦到。", "别来人事如秋草。", "应有吴霜侵翠葆。", "夕阳深锁绿苔门，一任卢郎愁里老。"]'),
('song-ci-471','玉楼春','周邦彦','宋','宋词','song-ci','玉楼春','[]','大堤花艳惊郎目。',64,'宋词/ci.song.4000.json','["大堤花艳惊郎目。", "秀色秾华看不足。", "休将宝瑟写幽怀，座上有人能顾曲。", "平波落照涵赪玉。", "画舸亭亭浮澹渌。", "临分何以祝深情，只有别离三万斛。"]'),
('song-ci-472','玉楼春','周邦彦','宋','宋词','song-ci','玉楼春','[]','玉奁收起新妆了。',64,'宋词/ci.song.4000.json','["玉奁收起新妆了。", "鬓畔斜枝红袅袅。", "浅颦轻笑百般宜，试著春衫犹更好。", "裁金簇翠天机巧。", "不称野人簪破帽。", "满头聊插片时狂，顿减十年尘土貌。"]'),
('song-ci-473','玉楼春','周邦彦','宋','宋词','song-ci','玉楼春','[]','桃溪不作从容住。',64,'宋词/ci.song.4000.json','["桃溪不作从容住。", "秋藕绝来无续处。", "当时相候赤栏桥，今日独寻黄叶路。", "烟中列岫青无数。", "雁背夕阳红欲暮。", "人如风后入江云，情似雨馀黏地絮。"]'),
('song-ci-474','夜飞鹊・夜飞鹊慢','周邦彦','宋','宋词','song-ci','夜飞鹊・夜飞鹊慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','河桥送人处，凉夜何其。',129,'宋词/ci.song.4000.json','["河桥送人处，凉夜何其。", "斜月远堕馀辉。", "铜盘烛泪已流尽，霏霏凉露沾衣。", "相将散离会，探风前津鼓，树杪参旗。", "华骢会意，纵扬鞭、亦自行迟。", "迢递路回清野，人语渐无闻，空带愁归。", "何意重红满地，遗钿不见，斜径都迷。", "兔葵燕麦，向残阳、欲与人齐。", "但徘徊班草，欷歔酹酒，极望天西。"]'),
('song-ci-475','早梅芳・喜迁莺','周邦彦','宋','宋词','song-ci','早梅芳・喜迁莺','[]','花竹深，房栊好。',100,'宋词/ci.song.4000.json','["花竹深，房栊好。", "夜阒无人到。", "隔窗寒雨，向壁孤灯弄馀照。", "泪多罗袖重，意密莺声小。", "正魂惊梦怯，门外已知晓。", "去难留，话未了。", "早促登长道。", "风披宿雾，露洗初阳射林表。", "乱愁迷远览，苦语萦怀抱。", "谩回头，更堪归路杳。"]'),
('song-ci-476','早梅芳・喜迁莺','周邦彦','宋','宋词','song-ci','早梅芳・喜迁莺','[]','缭墙深，丛竹绕。',100,'宋词/ci.song.4000.json','["缭墙深，丛竹绕。", "宴席临清沼。", "微呈纤履，故隐烘帘自嬉笑。", "粉香妆晕薄，带紧腰围小。", "看鸿惊凤翥，满座叹轻妙。", "酒醒时，会散了。", "回首城南道。", "河阴高转，露脚斜飞夜将晓。", "异乡淹岁月，醉眼迷登眺。", "路迢迢，恨满千里草。"]'),
('song-ci-477','凤来朝','周邦彦','宋','宋词','song-ci','凤来朝','[]','逗晓看娇面。',62,'宋词/ci.song.4000.json','["逗晓看娇面。", "小窗深、弄明未遍。", "爱残朱宿粉云鬟乱。", "最好是、帐中见。", "说梦双蛾微敛。", "锦衾温、酒香未断。", "待起难舍拚。", "任日炙、画栏暖。"]'),
('song-ci-478','芳草渡・系裙腰','周邦彦','宋','宋词','song-ci','芳草渡・系裙腰','[]','昨夜里，又再宿桃源，醉邀仙侣。',110,'宋词/ci.song.4000.json','["昨夜里，又再宿桃源，醉邀仙侣。", "听碧窗风快，珠帘半卷疏雨。", "多少离恨苦。", "方留连啼诉。", "凤帐晓，又是匆匆，独自归去。", "愁睹。", "满怀泪粉，瘦马冲泥寻去路。", "谩回首、烟迷望眼，依稀见朱户。", "似痴似醉，暗恼损、凭阑情绪。", "澹暮色，看尽栖鸦乱舞。"]'),
('song-ci-479','感皇恩','周邦彦','宋','宋词','song-ci','感皇恩','[]','露柳好风标，娇莺能语。',83,'宋词/ci.song.4000.json','["露柳好风标，娇莺能语。", "独占春光最多处。", "浅颦轻笑，未肯等闲分付。", "为谁心子里，长长苦。", "洞房见说，云深无路。", "凭仗青鸾道情素。", "酒空歌断，又被涛江催去。", "怎奈向、言不尽，愁无数。"]'),
('song-ci-480','虞美人','周邦彦','宋','宋词','song-ci','虞美人','[]','灯前欲去仍留恋。',66,'宋词/ci.song.4000.json','["灯前欲去仍留恋。", "肠断朱扉远。", "未须红雨洗香腮。", "待得蔷薇花谢、便归来。", "舞腰歌版闲时按。", "一任傍人看。", "金炉应见旧残煤。", "莫使恩情容易、似寒灰。"]'),
('song-ci-481','虞美人','周邦彦','宋','宋词','song-ci','虞美人','[]','疏篱曲径田家小。',66,'宋词/ci.song.4000.json','["疏篱曲径田家小。", "云树开清晓。", "天寒山色有无中。", "野外一声钟起、送孤蓬。", "添衣策马寻亭堠。", "愁抱惟宜酒。", "菰蒲睡鸭占陂塘。", "纵被行人惊散、又成双。"]'),
('song-ci-482','虞美人','周邦彦','宋','宋词','song-ci','虞美人','[]','玉觞才掩朱弦悄。',66,'宋词/ci.song.4000.json','["玉觞才掩朱弦悄。", "弹指壶天晓。", "回头犹认倚墙花。", "只向小桥南畔、便天涯。", "银蟾依旧当窗满。", "顾影魂先断。", "凄风休飐半残灯。", "拟倩今宵归梦、到云屏。"]'),
('song-ci-483','玉团儿','周邦彦','宋','宋词','song-ci','玉团儿','[]','铅华淡伫新妆束。',64,'宋词/ci.song.4000.json','["铅华淡伫新妆束。", "好风韵、天然异俗。", "彼此知名，虽然初见，情分先熟。", "垆烟淡淡云屏曲。", "睡半醒、生香透肉。", "赖得相逢，若还虚过，生世不足。"]'),
('song-ci-484','玉团儿','周邦彦','宋','宋词','song-ci','玉团儿','[]','妍姿艳态腰如束。',64,'宋词/ci.song.4000.json','["妍姿艳态腰如束。", "笑无限、桃粗杏俗。", "玉体横陈，云鬟斜坠，春睡还熟。", "夕阳斗转阑干曲。", "乍醉起、馀霞衬肉。", "搦粉搓酥，剪云裁雾，比并不足。"]'),
('song-ci-485','粉蝶儿慢','周邦彦','宋','宋词','song-ci','粉蝶儿慢','[]','宿雾藏春，馀寒带雨，占得群芳开晚。',117,'宋词/ci.song.4000.json','["宿雾藏春，馀寒带雨，占得群芳开晚。", "艳初弄秀，倚东风娇懒。", "隔叶黄鹂传好音，唤入深丛中探。", "数枝新，比昨朝、又早红稀香浅。", "眷恋。", "重来倚槛。", "当韶华、未可轻辜双眼。", "赏心随分乐，有清尊檀板。", "每岁嬉游能几日，莫使一生歌欠。", "忍因循、片花飞、又成春减。"]'),
('song-ci-486','红窗迥','周邦彦','宋','宋词','song-ci','红窗迥','[]','几日来、真个醉。',72,'宋词/ci.song.4000.json','["几日来、真个醉。", "不知道、窗外乱红，已深半指。", "花影被风摇碎。", "拥春酲乍起。", "有个人人，生得济楚，来向耳畔，问道今朝醒未。", "情性儿、慢腾腾地。", "恼得人又醉。"]'),
('song-ci-487','念奴娇','周邦彦','宋','宋词','song-ci','念奴娇','[]','醉魂乍醒，听一声啼鸟，幽斋岑寂。',121,'宋词/ci.song.4000.json','["醉魂乍醒，听一声啼鸟，幽斋岑寂。", "淡日朦胧初破晓，满眼娇晴天色。", "最惜香梅，凌寒偷绽，漏泄春消息。", "池塘芳草，又还淑景催逼。", "因念旧日芳菲，桃花永巷，恰似初相识。", "荏苒时光，因惯却、觅雨寻云踪迹。", "奈有离拆，瑶台月下，回首频思忆。", "重愁叠恨，万般都在胸臆。"]'),
('song-ci-488','燕归梁','周邦彦','宋','宋词','song-ci','燕归梁','[]','帘底新霜一夜浓。',62,'宋词/ci.song.4000.json','["帘底新霜一夜浓。", "短烛散飞虫。", "曾经洛浦见惊鸿。", "关山隔、梦魂通。", "明星晃晃，回津路转，榆影步花骢。", "欲攀云驾倩西风。", "吹清血、寄玲珑。"]'),
('song-ci-489','南浦','周邦彦','宋','宋词','song-ci','南浦','[]','浅带一帆风，向晚来、扁舟稳下南浦。',126,'宋词/ci.song.4000.json','["浅带一帆风，向晚来、扁舟稳下南浦。", "迢递阻潇湘，衡皋迥，斜舣蕙兰汀渚。", "危樯影里，断云点点遥天暮。", "菡萏里风，偷送清香，时时微度。", "吾家旧有簪缨，甚顿作天涯，经岁羁旅。", "羌管怎知情，烟波上，黄昏万斛愁绪。", "无言对月，皓彩千里人何处。", "恨无凤翼身，只待而今，飞将归去。"]'),
('song-ci-490','醉落魄・一斛珠','周邦彦','宋','宋词','song-ci','醉落魄・一斛珠','[]','葺金细弱。',68,'宋词/ci.song.4000.json','["葺金细弱。", "秋风嫩、桂花初著。", "蕊珠宫里人难学。", "花染娇荑，羞映翠云幄。", "清香不与兰荪弱。", "一枝云鬓巧梳掠。", "夜凉轻撼蔷薇萼。", "香满衣襟，月在凤凰阁。"]'),
('song-ci-491','留客住','周邦彦','宋','宋词','song-ci','留客住','[]','嗟乌兔。',114,'宋词/ci.song.4000.json','["嗟乌兔。", "正茫茫、相催无定，只恁东生西没，半均寒暑。", "昨见花红柳绿，处处林茂。", "又睹霜前篱畔，菊散馀香，看看又还秋暮。", "忍思虑。", "念古往贤愚，终归何处。", "争似高堂，日夜笙歌齐举。", "选甚连宵彻昼，再三留住。", "待拟沈醉扶上马，怎生向、主人未肯交去。"]'),
('song-ci-492','长相思','周邦彦','宋','宋词','song-ci','长相思','[]','夜色澄明。',127,'宋词/ci.song.4000.json','["夜色澄明。", "天街如水，风力微冷帘旌。", "幽期再偶，坐久相看才喜，欲叹还惊。", "醉眼重醒。", "映雕阑修竹，共数流萤。", "细语轻盈。", "尽银台、挂蜡潜听。", "自初识伊来，便惜妖娆艳质，美眄柔情。", "桃溪换世，鸾驭凌空，有愿须成。", "游丝荡絮，任轻狂、相逐牵萦。", "但连环不解，流水长东，难负深盟。"]'),
('song-ci-493','看花回','周邦彦','宋','宋词','song-ci','看花回','[]','秀色芳容明眸，就中奇绝。',123,'宋词/ci.song.4000.json','["秀色芳容明眸，就中奇绝。", "细看艳波欲溜，最可惜微重，红绡轻帖。", "匀朱傅粉，几为严妆时涴睫。", "因个甚、底死嗔人，半饷斜眄费贴燮。", "斗帐里、浓欢意惬。", "带困眼、似开微合。", "曾倚高楼望远，似指笑频瞤，知他谁说。", "那日分飞，泪雨纵横光映颊。", "搵香罗，恐揉损，与他衫袖裛。"]'),
('song-ci-494','看花回','周邦彦','宋','宋词','song-ci','看花回','[]','蕙风初散轻暖，霁景微澄洁。',124,'宋词/ci.song.4000.json','["蕙风初散轻暖，霁景微澄洁。", "秀蕊乍开乍敛，带雨态烟痕，春思纡结。", "危弦弄响，来去惊人莺语滑。", "无赖处，丽日楼台，乱纷歧路思奇绝。", "何计解，黏花系月。", "叹冷落、顿辜佳节。", "犹有当时气味，挂一缕相思，不断如发。", "云飞帝国，人在天边心暗折。", "语东风，共流转，谩作匆匆别。"]'),
('song-ci-495','月下笛','周邦彦','宋','宋词','song-ci','月下笛','[]','小雨收尘，凉蟾莹彻，水光浮璧。',119,'宋词/ci.song.4000.json','["小雨收尘，凉蟾莹彻，水光浮璧。", "谁知怨抑。", "静倚官桥吹笛。", "映宫墙、风叶乱飞，品高调侧人未识。", "想开元旧谱，柯亭遗韵，尽传胸臆。", "阑干四绕，听折柳徘徊，数声终拍。", "寒灯陋馆，最感平阳孤客。", "夜沈沈、雁啼甚哀，片云尽卷清漏滴。", "暗凝魂，但觉龙吟万壑天籁息。"]'),
('song-ci-496','无闷','周邦彦','宋','宋词','song-ci','无闷','[]','云作轻阴，风逗细寒，小溪冰冻初结。',123,'宋词/ci.song.4000.json','["云作轻阴，风逗细寒，小溪冰冻初结。", "更听得、悲鸣雁度空阔。", "暮雀喧喧聚竹，听竹上清响风敲雪。", "洞户悄，时见香消翠楼，兽煤红爇。", "凄切。", "念旧欢聚，旧约至此，方惜轻别。", "又还是、离亭楚梅堪折。", "暗想莺时似梦，梦里又却是，似莺时节。", "要无闷，除是拥炉对酒，共谭风月。"]'),
('song-ci-497','相思引','周邦彦','宋','宋词','song-ci','相思引','[]','生碧香罗粉兰香。',54,'宋词/ci.song.4000.json','["生碧香罗粉兰香。", "冷绡缄泪倩谁将。", "故人何在，烟水隔潇湘。", "花落燕□春欲老，絮吹思浪日偏长。", "一些儿事，何处不思量。"]'),
('song-ci-498','青房并蒂莲','周邦彦','宋','宋词','song-ci','青房并蒂莲','[]','醉凝眸。',123,'宋词/ci.song.4000.json','["醉凝眸。", "正楚天秋晚，远岸云收。", "草绿莲红，□映小汀洲。", "芰荷香里鸳鸯浦，恨菱歌、惊起眠鸥。", "望去帆、一派湖光，棹声咿哑橹声柔。", "愁窥汴堤细柳，曾舞送莺时，锦缆龙舟。", "拥倾国纤腰皓齿，笑倚楼。", "空令五湖夜月，也羞照三十六宫秋。", "正浪吟、不觉回桡，水花风叶两悠悠。"]'),
('song-ci-499','满庭芳','周邦彦','宋','宋词','song-ci','满庭芳','[]','山崦笼春，江城吹雨，暮天烟淡云昏。',118,'宋词/ci.song.4000.json','["山崦笼春，江城吹雨，暮天烟淡云昏。", "酒旗渔市，冷落杏花村。", "苏小当年秀骨，萦蔓草、空想罗裙。", "潮声起，高楼喷笛，五两了无闻。", "凄凉，怀故国，朝钟暮鼓，十载红尘。", "似梦魂迢递，长到吴门。", "闻道花开陌上，歌旧曲、愁杀王孙。", "何时见、□□唤酒，同倒瓮头春。"]'),
('song-ci-500','满庭芳','周邦彦','宋','宋词','song-ci','满庭芳','[]','花扑鞭梢，风吹衫袖，马啼初趁轻装。',118,'宋词/ci.song.4000.json','["花扑鞭梢，风吹衫袖，马啼初趁轻装。", "都城渐远，芳树隐斜阳。", "未惯羁游况味，征鞍上、满目凄凉。", "今宵里，三更皓月，愁断九回肠。", "佳人，何处去，别时无计，同引离觞。", "但唯有相思，两处难忘。", "去即十分去也，如何向、千种思量。", "凝眸处，黄昏画角，天远路岐长。"]'),
('song-ci-501','满庭芳','周邦彦','宋','宋词','song-ci','满庭芳','[]','白玉楼高，广寒宫阙，暮云如幛褰开。',118,'宋词/ci.song.4000.json','["白玉楼高，广寒宫阙，暮云如幛褰开。", "银河一派，流出碧天来。", "无数星躔玉李，冰轮动、光满楼台。", "登临处，全胜瀛海，弱水浸蓬莱。", "云鬟，香雾湿，月娥韵压，云冻江梅。", "况餐花饮露，莫惜裴徊。", "坐看人间如掌，山河影、倒入琼杯。", "归来晚，笛声吹彻，九万里尘埃。"]'),
('song-ci-502','青玉案','周邦彦','宋','宋词','song-ci','青玉案','[]','良夜灯光簇如豆。',80,'宋词/ci.song.4000.json','["良夜灯光簇如豆。", "占好事、今宵有。", "酒罢歌阑人散后。", "琵琶轻放，语声低颤，灭烛来相就。", "玉体偎人情何厚。", "轻惜轻怜转唧𠺕。", "雨散云收眉儿皱。", "只愁彰露，那人知后。", "把我来僝僽。"]'),
('song-ci-503','一剪梅・一翦梅','周邦彦','宋','宋词','song-ci','一剪梅・一翦梅','[]','一剪梅花万样娇。',68,'宋词/ci.song.4000.json','["一剪梅花万样娇。", "斜插梅枝，略点眉梢。", "轻盈微笑舞低回，何事尊前拍误招。", "夜渐寒深酒渐消。", "袖里时闻玉钏敲。", "城头谁恁促残更，银漏何如，且慢明朝。"]'),
('song-ci-504','鹊桥仙令・鹊桥仙','周邦彦','宋','宋词','song-ci','鹊桥仙令・鹊桥仙','[]','浮花浪蕊，人间无数，开遍朱朱白白。',68,'宋词/ci.song.4000.json','["浮花浪蕊，人间无数，开遍朱朱白白。", "瑶池一朵玉芙蓉，秋露洗、丹砂真色。", "晚凉拜月，六铢衣动，应被姮娥认得。", "翩然欲上广寒宫，横玉度、一声天碧。"]'),
('song-ci-505','花心动','周邦彦','宋','宋词','song-ci','花心动','[]','帘卷青楼，东风暖，杨花乱飘晴昼。',127,'宋词/ci.song.4000.json','["帘卷青楼，东风暖，杨花乱飘晴昼。", "兰袂褪香，罗帐褰红，绣枕旋移相就。", "海棠花谢春融暖，偎人恁、娇波频溜。", "象床稳，鸳衾谩展，浪翻红绉。", "一夜情浓似酒。", "香汗渍鲛绡，几番微透。", "鸾困凤慵，娅姹双眉，画也画应难就。", "问伊可煞□人厚。", "梅萼露、胭脂檀口。", "从此后、纤腰为郎管瘦。"]'),
('song-ci-506','双头莲','周邦彦','宋','宋词','song-ci','双头莲','[]','一抹残霞，几行新雁，天染云断，红迷阵影，隐约望中，点破晚空澄碧。',126,'宋词/ci.song.4000.json','["一抹残霞，几行新雁，天染云断，红迷阵影，隐约望中，点破晚空澄碧。", "助秋色。", "门掩西风，桥横斜照，青翼未来，浓尘自起，咫尺凤帏，合有人相识。", "叹乖隔。", "知甚时恣与，同携欢适。", "度曲传觞，并鞯飞辔，绮陌画堂连夕。", "楼头千里，帐底三更，尽堪泪滴。", "怎生向，无聊但只听消息。"]'),
('song-ci-507','大有','周邦彦','宋','宋词','song-ci','大有','[]','仙骨清羸，沈腰憔悴，见傍人、惊怪消瘦。',122,'宋词/ci.song.4000.json','["仙骨清羸，沈腰憔悴，见傍人、惊怪消瘦。", "柳无言，双眉尽日齐斗。", "都缘薄幸赋情浅，许多时、不成欢偶。", "幸自也，总由他，何须负这心口。", "令人恨，行坐儿断了更思量，没心求守。", "前日相逢，又早见伊仍旧。", "却更被温存后。", "都忘了、当时僝僽。", "便搊撮、九百身心，依前待有。"]'),
('song-ci-508','丑奴儿・采桑子','周邦彦','宋','宋词','song-ci','丑奴儿・采桑子','[]','南枝度腊开全少，疏影当轩。',52,'宋词/ci.song.4000.json','["南枝度腊开全少，疏影当轩。", "一种宜寒。", "自共清蟾别有缘。", "江南风味依然在，玉貌韶颜。", "今夜凭阑。", "不似钗头子细看。"]'),
('song-ci-509','丑奴儿・采桑子','周邦彦','宋','宋词','song-ci','丑奴儿・采桑子','[]','香梅开后风传信，绣户先知。',52,'宋词/ci.song.4000.json','["香梅开后风传信，绣户先知。", "雾湿罗衣。", "冷艳须攀最远枝。", "高歌羌管吹遥夜，看即分披。", "已恨来迟。", "不见娉婷带雪时。"]'),
('song-ci-510','蝶恋花','周邦彦','宋','宋词','song-ci','蝶恋花','[]','鱼尾霞生明远树。',70,'宋词/ci.song.4000.json','["鱼尾霞生明远树。", "翠壁黏天，玉叶迎风举。", "一笑相逢蓬海路。", "人间风月如尘土。", "剪水双眸云鬓吐。", "醉倒天瓢，笑语生青雾。", "此会未阑须记取。", "桃花几度吹红雨。"]'),
('song-ci-511','蝶恋花','周邦彦','宋','宋词','song-ci','蝶恋花','[]','美盼低迷情宛转。',70,'宋词/ci.song.4000.json','["美盼低迷情宛转。", "爱雨怜云，渐觉宽金钏。", "桃李香苞秋不展。", "深心黯黯谁能见。", "宋玉墙高才一觇。", "絮乱丝繁，苦隔春风面。", "歌板未终风色便。", "梦为蝴蝶留芳甸。"]'),
('song-ci-512','蝶恋花','周邦彦','宋','宋词','song-ci','蝶恋花','[]','晚步芳塘新霁后。',70,'宋词/ci.song.4000.json','["晚步芳塘新霁后。", "春意潜来，迤逦通窗牖。", "午睡渐多浓似酒。", "韶华已入东君手。", "嫩绿轻黄成染透。", "烛下工夫，泄漏章台秀。", "拟插芳条须满首。", "管交风味还胜旧。"]'),
('song-ci-513','蝶恋花','周邦彦','宋','宋词','song-ci','蝶恋花','[]','叶底寻花春欲暮。',70,'宋词/ci.song.4000.json','["叶底寻花春欲暮。", "折遍柔枝，满手真珠露。", "不见旧人空旧处。", "对花惹起愁无数。", "却倚阑干吹柳絮。", "粉蝶多情，飞上钗头住。", "若遣郎身如蝶羽。", "芳时争肯抛人去。"]'),
('song-ci-514','蝶恋花','周邦彦','宋','宋词','song-ci','蝶恋花','[]','酒熟微红生眼尾。',70,'宋词/ci.song.4000.json','["酒熟微红生眼尾。", "半额龙香，冉冉飘衣袂。", "云压宝钗撩不起。", "黄金心字双垂耳。", "愁入眉痕添秀美。", "无限柔情，分付西流水。", "忽被惊风吹别泪。", "只应天也知人意。"]'),
('song-ci-515','减字木兰花','周邦彦','宋','宋词','song-ci','减字木兰花','[]','风鬟雾鬓。',52,'宋词/ci.song.4000.json','["风鬟雾鬓。", "便觉蓬莱三岛近。", "水秀山明。", "缥缈仙姿画不成。", "广寒丹桂。", "岂是夭桃尘俗世。", "只恐乘风。", "飞上琼楼玉宇中。"]'),
('song-ci-516','木兰花令','周邦彦','宋','宋词','song-ci','木兰花令','[]','歌时宛转饶风措。',64,'宋词/ci.song.4000.json','["歌时宛转饶风措。", "莺语清圆啼玉树。", "断肠归去月三更，薄酒醒来愁万绪。", "孤灯翳翳昏如雾。", "枕上依稀闻笑语。", "恶嫌春梦不分明，忘了与伊相见处。"]'),
('song-ci-517','蓦山溪','周邦彦','宋','宋词','song-ci','蓦山溪','[]','楼前疏柳，柳外无穷路。',102,'宋词/ci.song.4000.json','["楼前疏柳，柳外无穷路。", "翠色四天垂，数峰青、高城阔处。", "江湖病眼，偏向此山明，愁无语。", "空凝伫。", "两两昏鸦去。", "平康巷陌，往事如花雨。", "十载却归来，倦追寻、酒旗戏鼓。", "今宵幸有，人似月婵娟，霞袖举。", "杯深注。", "一曲黄金缕。"]'),
('song-ci-518','蓦山溪','周邦彦','宋','宋词','song-ci','蓦山溪','[]','江天雪意，夜色寒成阵。',102,'宋词/ci.song.4000.json','["江天雪意，夜色寒成阵。", "翠袖捧金蕉，酒红潮、香凝沁粉。", "帘波不动，新月淡笼明，香破豆，烛频花，减字歌声稳。", "恨眉羞敛，往事休重问。", "人去小庭空，有梅梢、一枝春信。", "檀心未展，谁为探芳丛，消瘦尽，洗妆匀，应更添风韵。"]'),
('song-ci-519','南柯子・南歌子','周邦彦','宋','宋词','song-ci','南柯子・南歌子','[]','宝合分时果，金盘弄赐冰。',62,'宋词/ci.song.4000.json','["宝合分时果，金盘弄赐冰。", "晓来阶下按新声。", "恰有一方明月、可中庭。", "露下天如水，风来夜气清。", "娇羞不肯傍人行。", "扬下扇儿拍手、引流萤。"]'),
('song-ci-520','南柯子・南歌子','周邦彦','宋','宋词','song-ci','南柯子・南歌子','[]','腻颈凝酥白，轻衫淡粉红。',64,'宋词/ci.song.4000.json','["腻颈凝酥白，轻衫淡粉红。", "碧油凉气透帘栊。", "指点庭花低映，云母屏风。", "恨逐瑶琴写，书劳玉指封。", "等闲赢得瘦仪容。", "何事不教云雨，略下巫峰。"]'),
('song-ci-521','关河令・清商怨','周邦彦','宋','宋词','song-ci','关河令・清商怨','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','秋阴时晴向暝，变一庭凄冷。',51,'宋词/ci.song.4000.json','["秋阴时晴向暝，变一庭凄冷。", "伫听寒声，云深无雁影。", "更深人去寂静。", "但照壁、孤灯相映。", "酒已都醒，如何消夜永。"]'),
('song-ci-522','长相思','周邦彦','宋','宋词','song-ci','长相思','[]','举离觞。',44,'宋词/ci.song.4000.json','["举离觞。", "掩洞房。", "箭水泠泠刻漏长。", "愁中看晓光。", "整罗裳。", "脂粉香。", "见扫门前车上霜。", "相持泣路傍。"]'),
('song-ci-523','长相思','周邦彦','宋','宋词','song-ci','长相思','[]','马如飞。',44,'宋词/ci.song.4000.json','["马如飞。", "归未归。", "谁在河桥见别离。", "修杨委地垂。", "掩面啼。", "人怎知。", "桃李成阴莺哺儿。", "闲行春尽时。"]'),
('song-ci-524','长相思','周邦彦','宋','宋词','song-ci','长相思','[]','好风浮。',44,'宋词/ci.song.4000.json','["好风浮。", "晚雨收。", "林叶阴阴映鹢舟。", "斜阳明倚楼。", "黯凝眸。", "忆旧游。", "艇子扁舟来莫愁。", "石城风浪秋。"]'),
('song-ci-525','长相思','周邦彦','宋','宋词','song-ci','长相思','[]','沙棠舟。',44,'宋词/ci.song.4000.json','["沙棠舟。", "小棹游。", "池水澄澄人影浮。", "锦鳞迟上钩。", "烟云愁。", "箫鼓休。", "再得来时已变秋。", "欲归须少留。"]'),
('song-ci-526','万里春','周邦彦','宋','宋词','song-ci','万里春','[]','千红万翠。',57,'宋词/ci.song.4000.json','["千红万翠。", "簇定清明天气。", "为怜他、种种清香，好难为不醉。", "我爱深如你。", "我心在、个人心里。", "便相看、老却春风，莫无些欢意。"]'),
('song-ci-527','鹤冲天','周邦彦','宋','宋词','song-ci','鹤冲天','[]','梅雨霁，暑风和。',57,'宋词/ci.song.4000.json','["梅雨霁，暑风和。", "高柳乱蝉多。", "小园台榭远池波。", "鱼戏动新荷。", "薄纱厨，轻羽扇。", "枕冷簟凉深院。", "此时情绪此时天。", "无事小神仙。"]'),
('song-ci-528','鹤冲天','周邦彦','宋','宋词','song-ci','鹤冲天','[]','白角簟，碧纱厨。',57,'宋词/ci.song.4000.json','["白角簟，碧纱厨。", "梅雨乍晴初。", "谢家池畔正清虚。", "香散嫩芙蕖。", "日流金，风解愠。", "一弄素琴歌舞。", "慢摇纨扇诉花笺。", "吟待晚凉天。"]'),
('song-ci-529','西河','周邦彦','宋','宋词','song-ci','西河','[]','长安道，潇洒西风时起。',126,'宋词/ci.song.4000.json','["长安道，潇洒西风时起。", "尘埃车马晚游行，霸陵烟水。", "乱鸦栖鸟夕阳中，参差霜树相倚。", "到此际。", "愁如苇。", "冷落关河千里。", "追思唐汉昔繁华，断碑残记。", "未央宫阙已成灰，终南依旧浓翠。", "对此景、无限愁思。", "绕天涯、秋蟾如水。", "转使客情如醉。", "想当时、万古雄名，尽作往来人、凄凉事。"]'),
('song-ci-530','瑞鹤仙','周邦彦','宋','宋词','song-ci','瑞鹤仙','[]','暖烟笼细柳。',127,'宋词/ci.song.4000.json','["暖烟笼细柳。", "弄万缕千丝，年年春色。", "晴风荡无际，浓於酒、偏醉情人调客。", "阑干倚处，度花香、微散酒力。", "对重门半掩，黄昏淡月，院宇深寂。", "愁极。", "因思前事，洞房佳宴，正值寒食。", "寻芳遍赏，金谷里，铜驼陌。", "到而今、鱼雁沈沈无信，天涯常是泪滴。", "早归来，云馆深处，那人正忆。"]'),
('song-ci-531','浪淘沙','周邦彦','宋','宋词','song-ci','浪淘沙','[]','万叶战，秋声露结，雁度砂碛。',164,'宋词/ci.song.4000.json','["万叶战，秋声露结，雁度砂碛。", "细草和烟尚绿，遥山向晚更碧。", "见隐隐、云边新月白。", "映落照、帘幕千家，听数声何处倚楼笛。", "装点尽秋色。", "脉脉。", "旅情暗自消释。", "念珠玉、临水犹悲感，何况天涯客。", "忆少年歌酒，当时踪迹。", "岁华易老，衣带宽、懊恼心肠终窄。", "飞散后、风流人阻，蓝桥约、怅恨路隔。", "马蹄过、犹嘶旧巷陌。", "叹往事、一一堪伤，旷望极。", "凝思又把阑干拍。"]'),
('song-ci-532','南乡子','周邦彦','宋','宋词','song-ci','南乡子','[]','秋气绕城闉。',66,'宋词/ci.song.4000.json','["秋气绕城闉。", "暮角寒鸦未掩门。", "记得佳人冲雨别，吟分。", "别绪多於雨后云。", "小棹碧溪津。", "恰似江南第一春。", "应是采莲闲伴侣，相寻。", "收取莲心与旧人。"]'),
('song-ci-533','南乡子','周邦彦','宋','宋词','song-ci','南乡子','[]','寒夜梦初醒。',66,'宋词/ci.song.4000.json','["寒夜梦初醒。", "行尽江南万里程。", "早是愁来无会处，时听。", "败叶相传细雨声。", "书信也无凭。", "万事由他别后情。", "谁信归来须及早，长亭。", "短帽轻衫走马迎。"]'),
('song-ci-534','南乡子','周邦彦','宋','宋词','song-ci','南乡子','[]','户外井桐飘。',66,'宋词/ci.song.4000.json','["户外井桐飘。", "淡月疏影共寂寥。", "恐怕霜寒初索被，中宵。", "已觉秋声引雁高。", "罗带束纤腰。", "自剪灯花试彩毫。", "收起一封江北信，明朝。", "为问江头早晚潮。"]'),
('song-ci-535','南乡子','周邦彦','宋','宋词','song-ci','南乡子','[]','轻软舞时腰。',66,'宋词/ci.song.4000.json','["轻软舞时腰。", "初学吹笙苦未调。", "谁遣有情知事早，相撩。", "暗举罗巾远见招。", "痴呆一团娇。", "自折长条拨燕巢。", "不道有人潜看著，从教。", "掉下鬟心与凤翘。"]'),
('song-ci-536','浣溪沙慢','周邦彦','宋','宋词','song-ci','浣溪沙慢','[]','水竹旧院落，樱笋新蔬果。',114,'宋词/ci.song.4000.json','["水竹旧院落，樱笋新蔬果。", "嫩英翠幄，红杏交榴火。", "心事暗卜，叶底寻双朵。", "深夜归青琐。", "灯尽酒醒时，晓窗明、钗横鬓亸。", "怎生那。", "被间阻时多。", "奈愁肠数叠，幽恨万端，好梦还惊破。", "可怪近来，传语也无个。", "莫是瞋人呵。", "真个若瞋人，却因何、逢人问我。"]'),
('song-ci-537','夜游宫','周邦彦','宋','宋词','song-ci','夜游宫','[]','一阵斜风横雨。',71,'宋词/ci.song.4000.json','["一阵斜风横雨。", "薄衣润、新添金缕。", "不谢铅华更清素。", "倚筠窗，弄么弦，娇欲语。", "小阁横香雾。", "正年少、小娥愁绪。", "莫是栽花被花妒。", "甚春来，病恹恹，无会处。"]'),
('song-ci-538','诉衷情','周邦彦','宋','宋词','song-ci','诉衷情','[]','当时选舞万人长。',54,'宋词/ci.song.4000.json','["当时选舞万人长。", "玉带小排方。", "喧传京国声价，年少最无量。", "花阁迥，酒筵香。", "想难忘。", "而今何事，佯向人前，不认周郎。"]'),
('song-ci-539','虞美人','周邦彦','宋','宋词','song-ci','虞美人','[]','淡云笼月松溪路。',66,'宋词/ci.song.4000.json','["淡云笼月松溪路。", "长记分携处。", "梦魂连夜绕松溪。", "此夜相逢恰似、梦中时。", "海山陡觉风光好。", "莫惜金尊倒。", "柳花吹雪燕飞忙。", "生怕扁舟归去、断人肠。"]'),
('song-ci-540','烛影摇红','周邦彦','宋','宋词','song-ci','烛影摇红','[]','芳脸匀红，黛眉巧画宫妆浅。',116,'宋词/ci.song.4000.json','["芳脸匀红，黛眉巧画宫妆浅。", "风流天付与精神，全在娇波眼。", "早是萦心可惯。", "向尊前、频频顾眄。", "几回相见，见了还休，争如不见。", "烛影摇红，夜阑饮散春宵短。", "当时谁会唱阳关，离恨天涯远。", "争奈云收雨散。", "凭阑干、东风泪满。", "海棠开后，燕子来时，黄昏深院。"]'),
('song-ci-541','失调名','周邦彦','宋','宋词','song-ci','失调名','[]','露夜烟梢寒色重，攒星低映小珠帘。',16,'宋词/ci.song.4000.json','["露夜烟梢寒色重，攒星低映小珠帘。"]'),
('song-ci-542','减字木兰花','陈瓘','宋','宋词','song-ci','减字木兰花','[]','世间拘碍。',52,'宋词/ci.song.4000.json','["世间拘碍。", "人不堪时渠不改。", "古有斯人。", "千载谁能继后尘。", "春风入手。", "乐事自应随处有。", "与众熙怡。", "何似幽居独乐时。"]'),
('song-ci-543','减字木兰花','陈瓘','宋','宋词','song-ci','减字木兰花','[]','结庐人境。',52,'宋词/ci.song.4000.json','["结庐人境。", "万事醉来都不醒。", "鸟倦云飞。", "两得无心总是归。", "古人逝矣。", "旧日南窗何处是。", "莫负青春。", "即是升平寄傲人。"]'),
('song-ci-544','满庭芳','陈瓘','宋','宋词','song-ci','满庭芳','[]','槁木形骸，浮云身世，一年两到京华。',118,'宋词/ci.song.4000.json','["槁木形骸，浮云身世，一年两到京华。", "又还乘兴，闲看洛阳花。", "闻道鞓红最好，春归后、终委泥沙。", "忘言处，花开花谢，不似我生涯。", "年华。", "留不住，饥飡困寝，触处为家。", "这一轮明月，本自无瑕。", "随分冬裘夏葛，都不会、赤水黄芽。", "谁知我，春风一拐，谈笑有丹砂。"]'),
('song-ci-545','卜算子','陈瓘','宋','宋词','song-ci','卜算子','[]','身如一叶舟，万事潮头起。',52,'宋词/ci.song.4000.json','["身如一叶舟，万事潮头起。", "水长船高一任伊，来往洪涛里。", "潮落又潮生，今古长如此。", "后夜开尊独酌时，月满人千里。"]'),
('song-ci-546','一落索','陈瓘','宋','宋词','song-ci','一落索','[]','体上衣裳云作缕。',57,'宋词/ci.song.4000.json','["体上衣裳云作缕。", "不论寒暑。", "世间多少老婆禅，犹苦问、台山路。", "堪笑庞翁无趣。", "临行却住。", "古人公案不须论，还了得、如今否。"]'),
('song-ci-547','减字木兰花','陈瓘','宋','宋词','song-ci','减字木兰花','[]','大江北去。',52,'宋词/ci.song.4000.json','["大江北去。", "未到沧溟终不住。", "淮水东流。", "日夜朝宗亦未休。", "香炉烟袅。", "浓淡卷舒终不老。", "寸碧千锺。", "人醉华胥月色中。"]'),
('song-ci-548','减字木兰花','陈瓘','宋','宋词','song-ci','减字木兰花','[]','华胥月色。',52,'宋词/ci.song.4000.json','["华胥月色。", "万水千山同一白。", "南北相望。", "独醉香山旧草堂。", "淮岑妙境。", "十载醺酣犹未醒。", "一腹便便。", "也读春秋也爱眠。"]'),
('song-ci-549','卜算子','陈瓘','宋','宋词','song-ci','卜算子','[]','只解劝人归，都不留人住。',52,'宋词/ci.song.4000.json','["只解劝人归，都不留人住。", "南北东西总是家，劝我归何处。", "去住总由天，天意人难阻。", "若得归时我自归，何必闲言语。"]'),
('song-ci-550','卜算子','陈瓘','宋','宋词','song-ci','卜算子','[]','黄了旧皮肤，最是风流处。',52,'宋词/ci.song.4000.json','["黄了旧皮肤，最是风流处。", "多少纷纷陌上人，不听春鹃语。", "触目是家山，到了须拈取。", "云散长空月满天，好个还乡路。"]'),
('song-ci-551','卜算子','陈瓘','宋','宋词','song-ci','卜算子','[]','梦里不知眠，觉后眠何在。',52,'宋词/ci.song.4000.json','["梦里不知眠，觉后眠何在。", "试问眠身与梦身，那个能祗对。", "醉后有人醒，醒了无人醉。", "要识三千与大千，不在微尘外。"]'),
('song-ci-552','青玉案','陈瓘','宋','宋词','song-ci','青玉案','[]','碧空暗淡同云绕。',81,'宋词/ci.song.4000.json','["碧空暗淡同云绕。", "渐枕上、风声峭。", "明透纱窗天欲晓。", "珠帘才卷，美人惊报，一夜青山老。", "使君留客金尊倒。", "正千里琼瑶未经扫。", "欺压梅花春信早。", "十分农事，满城和气，管取明年好。"]'),
('song-ci-553','蓦山溪','陈瓘','宋','宋词','song-ci','蓦山溪','[]','扁舟东去，极目沧波渺。',102,'宋词/ci.song.4000.json','["扁舟东去，极目沧波渺。", "千古送残红，到如今、东流未了。", "午潮方去，江月照还生，千帆起，玉绳低，枕上莺声晓。", "锦囊佳句，韵压池塘草。", "声遏去年云，恼离怀、馀音缭绕。", "倚楼看镜，此意与谁论，一重水，一重山，目断令人老。"]'),
('song-ci-554','减字木兰花','陈瓘','宋','宋词','song-ci','减字木兰花','[]','世间药院。',52,'宋词/ci.song.4000.json','["世间药院。", "只爱大黄甘草贱。", "急急加工。", "更靠硫黄与鹿茸。", "鹿茸吃了。", "却恨世间凉药少。", "冷热平均。", "须是松根白茯苓。"]'),
('song-ci-555','满庭芳','陈瓘','宋','宋词','song-ci','满庭芳','[]','扰扰匆匆，红尘满袖，自然心在溪山。',118,'宋词/ci.song.4000.json','["扰扰匆匆，红尘满袖，自然心在溪山。", "寻思百计，真个不如闲。", "浮世纷华梦影，嚣尘路、来往循环。", "江湖手，长安障日，何似把鱼竿。", "盘旋。", "那忍去，他邦纵好，终异乡关。", "向七峰回首，清泪班班。", "西望烟波万里，扁舟去、何日东还。", "分携处，相期痛饮，莫放酒杯悭。"]'),
('song-ci-556','满庭芳','陈瓘','宋','宋词','song-ci','满庭芳','[]','淮叶缤纷，江烟浓淡，别尊同倒寒晖。',118,'宋词/ci.song.4000.json','["淮叶缤纷，江烟浓淡，别尊同倒寒晖。", "未逢春信，霜露惹征衣。", "往事元无是处，无须待、回首知非。", "春鹃语，从来劝我，常道不如归。", "家山，何处近，江楼帘栋，夕卷朝飞。", "问西江笋蕨，何似鲈肥。", "且置华胥旧梦，忘言处、千古同时。", "君知我，平生心事，相契古来稀。"]'),
('song-ci-557','醉蓬莱','陈瓘','宋','宋词','song-ci','醉蓬莱','["\u5e90\u5c71"]','问东州何处，境胜人幽，两俱难得。',121,'宋词/ci.song.4000.json','["问东州何处，境胜人幽，两俱难得。", "狼山相望，有高堂千尺。", "妙曲轰空，彩云翻袖，乐奏壶天长日。", "笑我飘然，蓬窗竹户，只延山色。", "拟棹觥船，径冲花浪，直造雕筵，共醺仙液。", "仍乞蟠桃，向庐山亲植。", "未举江帆，早逢淮雁，问故人踪迹。", "远老池边，陶翁琴里，此情何极。"]'),
('song-ci-558','临江仙','陈瓘','宋','宋词','song-ci','临江仙','[]','闻道洛阳花正好，家家庭户春风。',70,'宋词/ci.song.4000.json','["闻道洛阳花正好，家家庭户春风。", "道人饮去百壶空。", "年年花下醉，看谢几番红。", "此别又从何处去，风萍一任西东。", "语声虽异笑声同。", "一轮深夜月，何处不相逢。"]'),
('song-ci-559','蝶恋花','陈瓘','宋','宋词','song-ci','蝶恋花','[]','海角芳菲留不住。',70,'宋词/ci.song.4000.json','["海角芳菲留不住。", "笔下风生，飞入青云去。", "仙箓有名天赐与。", "致君事业安排取。", "要识世间平坦路。", "当使人人，各有安心处。", "黑发便逢尧舜主。", "笑人白首归南亩。"]'),
('song-ci-560','卜算子','陈瓘','宋','宋词','song-ci','卜算子','[]','咄咄汝何人，眼在眉毛下。',52,'宋词/ci.song.4000.json','["咄咄汝何人，眼在眉毛下。", "明月相随万里来，何处分真假。", "问著总无言，有口番成哑。", "荆棘林中自在身，即是知音者。"]'),
('song-ci-561','蝶恋花','陈瓘','宋','宋词','song-ci','蝶恋花','[]','有个胡儿模样别。',70,'宋词/ci.song.4000.json','["有个胡儿模样别。", "满颔髭须，生得浑如漆。", "见说近来头也白。", "髭须那得长长黑。", "□□□□□□□。", "籋子镊来，须有千堆雪。", "莫向细君容易说。", "恐他嫌你将伊摘。"]'),
('song-ci-562','减字木兰花','陈瓘','宋','宋词','song-ci','减字木兰花','[]','一尊薄酒。',52,'宋词/ci.song.4000.json','["一尊薄酒。", "满酌劝君君举手。", "不是亲朋。", "谁肯相从寂寞滨。", "人生如梦。", "梦里惺惺何处用。", "盏到休辞。", "醉后全胜未醉时。"]'),
('song-ci-563','阮郎归','陈瓘','宋','宋词','song-ci','阮郎归','[]','从来多唱杜鹃辞。',56,'宋词/ci.song.4000.json','["从来多唱杜鹃辞。", "如今真个归。", "健帆笑里落湖西。", "回看江浪飞。", "说情话，复何疑。", "临流应赋诗。", "引觞自酌更何之。", "心闲光景迟。"]'),
('song-ci-564','失调名','陈瓘','宋','宋词','song-ci','失调名','[]','吴樯越橹，都是利名人。',11,'宋词/ci.song.4000.json','["吴樯越橹，都是利名人。"]'),
('song-ci-565','失调名','陈瓘','宋','宋词','song-ci','失调名','[]','彩衣长久。',13,'宋词/ci.song.4000.json','["彩衣长久。", "五世祥烟熏舞袖。"]'),
('song-ci-566','满庭芳','刘山老','宋','宋词','song-ci','满庭芳','[]','跛子年来，形容何似，俨然一部髭须。',118,'宋词/ci.song.4000.json','["跛子年来，形容何似，俨然一部髭须。", "世间许大，拐上做工夫。", "选甚南州北县，逢著处、酒满葫芦。", "醺醺醉，不知明日，何处度朝晡。", "洛阳，花看了，归来帝里，一事全无。", "又还与瓠羹，再作门徒。", "蓦地思量下水，浪网上、芦席横铺。", "呵呵笑，睢阳门外，有个大南湖。"]'),
('song-ci-567','望江南・忆江南','邵伯温','宋','宋词','song-ci','望江南・忆江南','[]','百尺长藤垂到地，千株乔木密参天。',22,'宋词/ci.song.4000.json','["百尺长藤垂到地，千株乔木密参天。", "只在郡城边。"]'),
('song-ci-568','调笑・调笑令','邵伯温','宋','宋词','song-ci','调笑・调笑令','[]','翻翻绣袖上红茵。',32,'宋词/ci.song.4000.json','["翻翻绣袖上红茵。", "舞姬犹是旧精神。", "坐中莫怪无欢意，我与将军是故人。"]'),
('song-ci-569','渔家傲','净端','宋','宋词','song-ci','渔家傲','["\u957f\u6c5f"]','斗转星移天渐晓。',72,'宋词/ci.song.4000.json','["斗转星移天渐晓。", "蓦然听得鹈鹕叫。", "山寺钟声人浩浩。", "木鱼噪。", "渡船过岸行官道。", "轻舟再奈长江讨。", "重添香饵为钩钓。", "钓得锦鳞船里跳。", "呵呵笑。", "思量天下渔家好。"]'),
('song-ci-570','渔家傲','净端','宋','宋词','song-ci','渔家傲','[]','浪静西溪澄似练。',72,'宋词/ci.song.4000.json','["浪静西溪澄似练。", "片帆高挂乘风便。", "始向波心通一线。", "群鱼见。", "当头谁敢先吞咽。", "闪烁锦鳞如闪电。", "灵光今古应无变。", "爱是憎非都已遣。", "回头转。", "一轮明月升苍弁。"]'),
('song-ci-571','渔家傲','净端','宋','宋词','song-ci','渔家傲','[]','七宝池中堪下钓。',72,'宋词/ci.song.4000.json','["七宝池中堪下钓。", "八功德水烟波渺。", "池底金沙齐布了。", "羡鱼鸟。", "周回旋绕为阶道。", "白鹤孔雀鹦鹉噪。", "弥陀接引毫光照。", "不是修行何得到。", "一般好。", "西方净土无烦恼。"]'),
('song-ci-572','渔家傲','净端','宋','宋词','song-ci','渔家傲','[]','一只孤舟巡海岸。',73,'宋词/ci.song.4000.json','["一只孤舟巡海岸。", "盘陀石上垂钩线。", "钓得锦鳞鲜又健。", "堪爱羡。", "龙王见了将珠换。", "钓罢归来莲苑看。", "满堂尽是真罗汉。", "便爇名香三五片。", "梵□献。", "原来佛不夺众生愿。"]'),
('song-ci-573','菩萨蛮','李','宋','宋词','song-ci','菩萨蛮','[]','城阴犹有松间雪。',52,'宋词/ci.song.4000.json','["城阴犹有松间雪。", "松间暗淡城头月。", "月下几枝梅。", "为谁今夜开。", "尊前簪素发。", "自拥繁枝折。", "疑是在瑶台。", "宝灯携手来。"]'),
('song-ci-574','虞美人令・虞美人','李','宋','宋词','song-ci','虞美人令・虞美人','[]','玉阑干外清江浦。',66,'宋词/ci.song.4000.json','["玉阑干外清江浦。", "渺渺天涯雨。", "好风如扇雨如帘。", "时见岸花汀草、涨痕添。", "青林枕上关山路。", "卧想乘鸾处。", "碧芜千里信悠悠。", "惟有霎时凉梦、到南州。"]'),
('song-ci-575','品令','李','宋','宋词','song-ci','品令','[]','唱歌须是，玉人檀口，皓齿冰肤。',59,'宋词/ci.song.4000.json','["唱歌须是，玉人檀口，皓齿冰肤。", "意传心事，语娇声颤，字如贯珠。", "老翁虽是解歌，无奈雪鬓霜须。", "大家且道，是伊模样，怎如念奴。"]'),
('song-ci-576','清平乐','李','宋','宋词','song-ci','清平乐','[]','落梅呜咽。',54,'宋词/ci.song.4000.json','["落梅呜咽。", "暗淡城头月。", "吹满江山惊梦蝶。", "唤起画楼伤别。", "帘风轻触银钩。", "梧桐玉露新秋。", "底事琐窗深夜，素娥常伴人愁。"]'),
('song-ci-577','水龙吟','孔夷','宋','宋词','song-ci','水龙吟','[]','岁穷风雪瓢零，望迷万里云垂冻。',126,'宋词/ci.song.4000.json','["岁穷风雪瓢零，望迷万里云垂冻。", "红绡碎翦，凝酥繁缀，烟深霜重。", "疏影沈波，暗香和月，横斜浮动。", "怅别来，欲把芳菲寄远，还羌管、吹三弄。", "寂寞玉人睡起，污残妆、不胜姣凤。", "盈盈山馆，纷纷客路，相思谁共。", "才与风流，赋称清艳，多情唯宋。", "算襄王，枉被梨花瘦损，又成春梦。"]'),
('song-ci-578','南浦','孔夷','宋','宋词','song-ci','南浦','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','风悲画角，听单于、三弄落谯门。',123,'宋词/ci.song.4000.json','["风悲画角，听单于、三弄落谯门。", "投宿骎骎征骑，飞雪满孤村。", "酒市渐闲灯火，正敲窗、乱叶舞纷纷。", "送数声惊雁，下离烟水，嘹唳度寒云。", "好在半胧溪月，到如今、无处不销魂。", "故国梅花归梦，愁损绿罗裙。", "为问暗香闲艳，也相思、万点付啼痕。", "算翠屏应是，两眉馀恨倚黄昏。"]'),
('song-ci-579','惜馀春慢・选冠子','孔夷','宋','宋词','song-ci','惜馀春慢・选冠子','[]','弄月馀花，团风轻絮，露湿池堂春草。',138,'宋词/ci.song.4000.json','["弄月馀花，团风轻絮，露湿池堂春草。", "莺莺恋友，燕燕将雏，惆怅睡残清晓。", "还似初相见时，携手旗亭，酒香梅小。", "向登临长是，伤春滋味，泪弹多少。", "因甚却、轻许风流，终非长久，又说分飞烦恼。", "罗衣瘦损，绣被香消，那更乱红如扫。", "门外无穷路岐，天若有情，和天须老。", "念高唐归梦，凄凉何处，水流云绕。"]'),
('song-ci-580','鼓笛慢・水龙吟','孔矩','宋','宋词','song-ci','鼓笛慢・水龙吟','[]','数枝凌雪乘冰，嫩英半吐琼酥点。',126,'宋词/ci.song.4000.json','["数枝凌雪乘冰，嫩英半吐琼酥点。", "南州故苑，何郎遗咏，风台月观。", "疏影横斜，暗香浮动，水寒云晚。", "笑浮花浪蕊，娇春万里，空零落、愁莺燕。", "游子寂寥暮景，向天边、几回相见。", "玉人纤手，殷勤攀赠，欲行微盼。", "越使归来，汉宫妆罢，昭华流怨。", "念湘江梦杳，窗前疑是，此情何限。"]'),
('song-ci-581','鹧鸪天','孔矩','宋','宋词','song-ci','鹧鸪天','[]','却月凌风度雪清。',64,'宋词/ci.song.4000.json','["却月凌风度雪清。", "何郎高咏照花明。", "一枝弄碧传幽信，半额涂黄拾晚荣。", "春思淡，暗香轻。", "江南雨冷若为情。", "犹胜远隔潇湘水，忽到窗前梦不成。"]'),
('song-ci-582','渔家傲','邹浩','宋','宋词','song-ci','渔家傲','[]','慧眼舒光无不见。',72,'宋词/ci.song.4000.json','["慧眼舒光无不见。", "尘中一一藏经卷。", "闻说大千摊已遍。", "门方便。", "法轮尽向毫端转。", "月挂烛笼知再见。", "西方可履休回盼。", "要与老岑同掣电。", "酬所愿。", "欣逢十二观音面。"]'),
('song-ci-583','临江仙','邹浩','宋','宋词','song-ci','临江仙','[]','有个头陀修苦行，头上头发毵毵。',68,'宋词/ci.song.4000.json','["有个头陀修苦行，头上头发毵毵。", "身披一副醦裙衫。", "紧缠双脚，苦苦要游南。", "闻说度牒朝夕到，并除颔下髭髯。", "钵中无粥住无庵。", "摩登伽处，只恐却重参。"]'),
('song-ci-584','失调名','曾诞','宋','宋词','song-ci','失调名','[]','草草山林职事，厌厌罢相情怀。',14,'宋词/ci.song.4000.json','["草草山林职事，厌厌罢相情怀。"]'),
('song-ci-585','风流子','李坦然','宋','宋词','song-ci','风流子','[]','东君虽不语，年华事、今岁恰如期。',135,'宋词/ci.song.4000.json','["东君虽不语，年华事、今岁恰如期。", "向寒雨望中，晓霜清处，领些春意，开两三枝。", "又不是、山桃红锦烂，溪柳绿摇丝。", "别是一般，孤高风韵，绛裁纤萼，冰剪芳蕤。", "清香还有意，轻飘度勾引，几句新诗。", "须是放怀追赏，莫恁轻离。", "更嫦娥为爱，寒光满地，故移疏影，来伴南枝。", "谁道寿阳妆浅，偏入时宜。"]'),
('song-ci-586','感皇恩','阮阅','宋','宋词','song-ci','感皇恩','[]','芝检下中天，春寒犹浅。',81,'宋词/ci.song.4000.json','["芝检下中天，春寒犹浅。", "馀闰银蟾许重看。", "满城灯火，又遍高楼深院。", "宝鞍催绣毂，香风软。", "憔悴慢翁，萧条古县。", "随分良辰试开宴。", "且倾芳酒，共听新声弦管。", "夜阑人未散，更筹转。"]'),
('song-ci-587','踏莎行','阮阅','宋','宋词','song-ci','踏莎行','[]','驿使初回，新阳才报。',68,'宋词/ci.song.4000.json','["驿使初回，新阳才报。", "时和倍觉青春早。", "华灯和月拥朱轓，花间万点寒星小。", "团扇歌清，重裀舞妙。", "游人只恐归来悄。", "明年亲侍辇舆行，未应肯记濡须好。"]'),
('song-ci-588','减字木兰花','阮阅','宋','宋词','song-ci','减字木兰花','[]','晓云舒瑞。',52,'宋词/ci.song.4000.json','["晓云舒瑞。", "寒影初回长日至。", "罗袜新成。", "更有何人继后尘。", "绮窗寒浅。", "尽道朝来添一线。", "秉烛须游。", "已减铜壶昨夜筹。"]'),
('song-ci-589','锦堂春・锦堂春慢','阮阅','宋','宋词','song-ci','锦堂春・锦堂春慢','[]','江入重关，山围翠巘，湖边自古巢阳。',65,'宋词/ci.song.4000.json','["江入重关，山围翠巘，湖边自古巢阳。", "正梅残林坞，冰泮池塘。", "闻道当年父老，记梅福、曾隐南昌。", "有长堤万柳，映□参差，尽是甘棠。", "共夸金斗。"]'),
('song-ci-590','洞仙歌','阮阅','宋','宋词','song-ci','洞仙歌','[]','赵家姊妹，合在昭阳殿。',103,'宋词/ci.song.4000.json','["赵家姊妹，合在昭阳殿。", "因甚人间有飞燕。", "见伊底，尽道独步江南，便江北、也何曾惯见。", "惜伊情性好，不解嗔人，长带桃花笑时脸。", "向尊前酒底，得见些时，似恁地、能得几回细看。", "待不眨眼儿、觑著伊，将眨眼底工夫，剩看几遍。"]'),
('song-ci-591','眼儿媚','阮阅','宋','宋词','song-ci','眼儿媚','[]','楼上黄昏杏花寒。',58,'宋词/ci.song.4000.json','["楼上黄昏杏花寒。", "斜月小栏干。", "一双燕子，两行征雁，画角声残。", "绮窗人在东风里，洒泪对春闲。", "也应似旧，盈盈秋水，淡淡春山。"]'),
('song-ci-592','失调名','赵企','宋','宋词','song-ci','失调名','[]','闻道南丹风土美。',61,'宋词/ci.song.4000.json','["闻道南丹风土美。", "流出溅溅五溪水。", "威仪尽识汉君臣，衣冠已变□番子。", "凯歌还、欢声载路。", "一曲春风里。", "不日万年觞，猺人北面朝天子。"]'),
('song-ci-593','感皇恩','赵企','宋','宋词','song-ci','感皇恩','[]','骑马踏红尘，长安重到。',81,'宋词/ci.song.4000.json','["骑马踏红尘，长安重到。", "人面依前似花好。", "旧欢才展，又被新愁分了。", "未成云雨梦，巫山晓。", "千里断肠，关山古道。", "回首高城似天杳。", "满怀离恨，付与落花啼鸟。", "故人何处也，青春老。"]'),
('song-ci-594','步蟾宫','汪存','宋','宋词','song-ci','步蟾宫','[]','玉京此去春犹浅。',66,'宋词/ci.song.4000.json','["玉京此去春犹浅。", "正雪絮、马头零乱。", "姮娥剪就绿云裳，待来步蟾宫与换。", "明年二月桃花岸。", "棹双浆、浪平烟暖。", "扬州十里小红楼，尽卷上珠帘一半。"]'),
('song-ci-595','蝶恋花','谢逸','宋','宋词','song-ci','蝶恋花','[]','豆蔻梢头春色浅。',70,'宋词/ci.song.4000.json','["豆蔻梢头春色浅。", "新试纱衣，拂袖东风软。", "红日三竿帘幕卷。", "画楼影里双飞燕。", "拢鬓步摇青玉碾。", "缺样花枝，叶叶蜂儿颤。", "独倚阑干凝望远。", "一川烟草平如剪。"]'),
('song-ci-596','踏莎行','谢逸','宋','宋词','song-ci','踏莎行','[]','柳絮风轻，梨花雨细。',68,'宋词/ci.song.4000.json','["柳絮风轻，梨花雨细。", "春阴院落帘垂地。", "碧溪影里小桥横，青帘市上孤烟起。", "镜约关情，琴心破睡。", "轻寒漠漠侵鸳被。", "酒醒霞散脸边红，梦回山蹙眉间翠。"]'),
('song-ci-597','菩萨蛮','谢逸','宋','宋词','song-ci','菩萨蛮','[]','暄风迟日春光闹。',52,'宋词/ci.song.4000.json','["暄风迟日春光闹。", "蒲萄水绿摇轻棹。", "两岸草烟低。", "青山啼子规。", "归来愁未寝。", "黛浅眉痕沁。", "花影转廊腰。", "红添酒面潮。"]'),
('song-ci-598','菩萨蛮','谢逸','宋','宋词','song-ci','菩萨蛮','[]','縠纹波面浮鸂鶒。',52,'宋词/ci.song.4000.json','["縠纹波面浮鸂鶒。", "蒲芽出水参差碧。", "满院落梅香。", "柳梢初弄黄。", "衣轻红袖皱。", "春困花枝瘦。", "睡起玉钗横。", "隔帘闻晓莺。"]'),
('song-ci-599','采桑子','谢逸','宋','宋词','song-ci','采桑子','[]','楚山削玉云中碧，影落沙汀。',52,'宋词/ci.song.4000.json','["楚山削玉云中碧，影落沙汀。", "秋水澄凝。", "一抹江天雁字横。", "金钱满地西风急，红蓼烟轻。", "帘外砧声。", "惊起青楼梦不成。"]'),
('song-ci-600','采桑子','谢逸','宋','宋词','song-ci','采桑子','[]','冰霜林里争先发，独压群花。',52,'宋词/ci.song.4000.json','["冰霜林里争先发，独压群花。", "风送清笳。", "更引轻烟淡淡遮。", "抱墙溪水弯环碧，月色清华。", "疏影横斜。", "恰似林逋处士家。"]'),
('song-ci-601','采桑子','谢逸','宋','宋词','song-ci','采桑子','[]','冷猿寒雁淮山远，风袅青帘。',52,'宋词/ci.song.4000.json','["冷猿寒雁淮山远，风袅青帘。", "飞雪廉纤。", "莫道空中是撒盐。", "到时乳鹊喧梧影，晓卷疏帘。", "彩服巡檐。", "索共梅花笑语添。"]'),
('song-ci-602','西江月','谢逸','宋','宋词','song-ci','西江月','[]','落寞寒香满院，扶疏清影侵门。',58,'宋词/ci.song.4000.json','["落寞寒香满院，扶疏清影侵门。", "雪消平野晚烟昏。", "睡起懒匀檀粉。", "皎皎风前玉树，盈盈月下冰魂。", "南枝春信夜来温。", "便觉肌肤瘦损。"]'),
('song-ci-603','西江月','谢逸','宋','宋词','song-ci','西江月','[]','花额上堆翠葆，远山横处星眸。',58,'宋词/ci.song.4000.json','["花额上堆翠葆，远山横处星眸。", "绛宫深锁暮云浮。", "月破黄昏时候。", "谁谓霞衣玉简，便孤彩凤秦楼。", "桃源不禁昔人游。", "曾是刘郎邂逅。"]'),
('song-ci-604','西江月','谢逸','宋','宋词','song-ci','西江月','[]','窄袖浅笼温玉，修眉淡扫遥岑。',58,'宋词/ci.song.4000.json','["窄袖浅笼温玉，修眉淡扫遥岑。", "行时云雾绕衣襟。", "步步莲生宫锦。", "菊与秋烟共晚，酒随人意俱深。", "尊前有客动琴心。", "醉后清狂不禁。"]'),
('song-ci-605','西江月','谢逸','宋','宋词','song-ci','西江月','[]','宝柱横云雁影，朱弦隔叶莺声。',58,'宋词/ci.song.4000.json','["宝柱横云雁影，朱弦隔叶莺声。", "风生玉脂晚寒清。", "官样轻黄袖冷。", "饮罢尚留馀意，曲终自有深情。", "归来江上数峰青。", "梅水横斜夜永。"]'),
('song-ci-606','西江月','谢逸','宋','宋词','song-ci','西江月','[]','滴滴金盘露冷，萧萧玉宇风清。',58,'宋词/ci.song.4000.json','["滴滴金盘露冷，萧萧玉宇风清。", "长庚入梦晓窗明。", "淡月微云耿耿。", "松竹五峰秋色，笙歌三市欢声。", "华堂开宴拥娉婷。", "天上人间共庆。"]'),
('song-ci-607','西江月','谢逸','宋','宋词','song-ci','西江月','[]','青锦缠条配剑，紫丝络辔飞骢。',58,'宋词/ci.song.4000.json','["青锦缠条配剑，紫丝络辔飞骢。", "入关意气喜生风。", "年少胸吞云梦。", "金阙日高露泣，东华尘软香红。", "争看荀氏第三龙。", "春暖桃花浪涌。"]'),
('song-ci-608','西江月','谢逸','宋','宋词','song-ci','西江月','[]','晓艳最便清露，晚红偏怯斜阳。',58,'宋词/ci.song.4000.json','["晓艳最便清露，晚红偏怯斜阳。", "移根栽近菊花傍。", "蜀锦翻成新样。", "坐客联挥玉麈，歌词细琢琼章。", "从今故事记溪堂。", "岁岁携壶共赏。"]'),
('song-ci-609','西江月','谢逸','宋','宋词','song-ci','西江月','[]','木末谁攀新萼，雪消自种前庭。',58,'宋词/ci.song.4000.json','["木末谁攀新萼，雪消自种前庭。", "莫嫌开过尚盈盈。", "似待诗人醉咏。", "霜后最添妍丽，风中更觉娉婷。", "影摇溪水一湾清。", "妆罢晓临鸾境。"]'),
('song-ci-610','西江月','谢逸','宋','宋词','song-ci','西江月','[]','密雪未知肤白，夜寒已觉香清。',58,'宋词/ci.song.4000.json','["密雪未知肤白，夜寒已觉香清。", "振芳堂下月盈庭。", "踏碎横斜疏影。", "且醉杯中绿蚁，休辞笛里清声。", "东君催促子青青。", "滋味要调金鼎。"]'),
('song-ci-611','南歌子','谢逸','宋','宋词','song-ci','南歌子','[]','雨洗溪光净，风掀柳带斜。',62,'宋词/ci.song.4000.json','["雨洗溪光净，风掀柳带斜。", "画楼朱户玉人家。", "帘外一眉新月、浸梨花。", "金鸭香凝袖，铜荷烛映纱。", "凤盘宫锦小屏遮。", "夜静寒生春笋、理琵琶。"]'),
('song-ci-612','虞美人','谢逸','宋','宋词','song-ci','虞美人','[]','碧梧翠竹交加影。',66,'宋词/ci.song.4000.json','["碧梧翠竹交加影。", "角簟纱厨冷。", "疏云淡月媚横塘。", "一阵荷花风起、隔帘香。", "雁横天末无消息。", "水阔吴山碧。", "刺桐花上蝶翩翩。", "唯有夜深清梦、到郎边。"]'),
('song-ci-613','虞美人','谢逸','宋','宋词','song-ci','虞美人','[]','角声吹散梅梢雪。',66,'宋词/ci.song.4000.json','["角声吹散梅梢雪。", "疏影黄昏月。", "落英点点拂阑干。", "风送清香满院、作轻寒。", "花瓷羯鼓催行酒。", "红袖掺掺手。", "曲声未彻宝杯空。", "饮罢香薰翠被、锦屏中。"]'),
('song-ci-614','虞美人','谢逸','宋','宋词','song-ci','虞美人','[]','风前玉树瑲金韵。',66,'宋词/ci.song.4000.json','["风前玉树瑲金韵。", "碧落佳期近。", "疏云影里鹊桥低。", "檐外一弯新月、印修眉。", "星河渐晓铜壶噎。", "又是经年别。", "此情莫与玉人知。", "引起旧家离恨、泪珠垂。"]'),
('song-ci-615','谒金门','谢逸','宋','宋词','song-ci','谒金门','[]','帘外雨。',53,'宋词/ci.song.4000.json','["帘外雨。", "洗尽楚乡残暑。", "白露影边霞一缕。", "绀碧江天暮。", "沈水烟横香雾。", "茗碗浅浮琼乳。", "卧听鹧鸪啼竹坞。", "竹风清院宇。"]'),
('song-ci-616','如梦令','谢逸','宋','宋词','song-ci','如梦令','[]','花落莺啼春暮。',40,'宋词/ci.song.4000.json','["花落莺啼春暮。", "陌上绿杨飞絮。", "金鸭晚香寒，人在洞房深处。", "无语。", "无语。", "叶上数声疏雨。"]'),
('song-ci-617','如梦令','谢逸','宋','宋词','song-ci','如梦令','[]','门外落花流水。',40,'宋词/ci.song.4000.json','["门外落花流水。", "日暖杜鹃声碎。", "蕃马小屏风，一枕画堂春睡。", "如醉。", "如醉。", "正是困人天气。"]'),
('song-ci-618','青玉案','谢逸','宋','宋词','song-ci','青玉案','[]','芦花飘雪迷洲渚。',80,'宋词/ci.song.4000.json','["芦花飘雪迷洲渚。", "送秋水、连天去。", "一叶小舟横别浦。", "数声鸿雁，两行鸥鹭。", "天淡潇湘暮。", "蓬窗醉梦惊箫鼓。", "回首青楼在何处。", "柳岸风轻吹残暑。", "菊开青蕊，叶飞红树。", "江上潇潇雨。"]'),
('song-ci-619','好事近','谢逸','宋','宋词','song-ci','好事近','[]','疏雨洗烟波，雨过满江秋色。',53,'宋词/ci.song.4000.json','["疏雨洗烟波，雨过满江秋色。", "风起白鸥零乱，破岚光深碧。", "荻花枫叶只供愁，清吟写岑寂。", "吟罢倚阑无语，听一声羌笛。"]'),
('song-ci-620','临江仙','谢逸','宋','宋词','song-ci','临江仙','[]','木落江寒秋色晚，飕飕吹帽风轻。',68,'宋词/ci.song.4000.json','["木落江寒秋色晚，飕飕吹帽风轻。", "丹枫楼外捣衣声。", "登高怀远，山影雁边横。", "露染宫黄庭菊浅，茱萸烟拂红轻。", "尊前谁整醉冠倾。", "酒香薰脸，落日断霞明。"]'),
('song-ci-621','临江仙','谢逸','宋','宋词','song-ci','临江仙','[]','玉树临风宾欲散，黄昏约马嘶庭。',70,'宋词/ci.song.4000.json','["玉树临风宾欲散，黄昏约马嘶庭。", "幽欢未尽有馀清。", "琼糜方一啜，银烛已双擎。", "坐久香津生齿颊，何须五斗消酲。", "艳歌声里醉魂醒。", "明年思此会，旌旆想登瀛。"]'),
('song-ci-622','减字木兰花','谢逸','宋','宋词','song-ci','减字木兰花','[]','荷花风细。',52,'宋词/ci.song.4000.json','["荷花风细。", "乞巧楼中凉似水。", "天幕低垂。", "新月弯环浅晕眉。", "桥横乌鹊。", "不负年年云外约。", "残漏疏钟。", "肠断朝霞一缕红。"]'),
('song-ci-623','减字木兰花','谢逸','宋','宋词','song-ci','减字木兰花','[]','疏疏密密。',52,'宋词/ci.song.4000.json','["疏疏密密。", "薝卜林中飞玉出。", "妒舞欺梅。", "悠扬随风去却回。", "遥岑玉刻。", "不见云中浮寸碧。", "夜色清妍。", "庭下交光月午天。"]'),
('song-ci-624','渔家傲','谢逸','宋','宋词','song-ci','渔家傲','[]','秋水无痕清见底。',72,'宋词/ci.song.4000.json','["秋水无痕清见底。", "蓼花汀上西风起。", "一叶小舟烟雾里。", "兰棹舣。", "柳条带雨穿双鲤。", "自叹直钩无处使。", "笛声吹彻云山翠。", "脍落霜刀红缕细。", "新酒美。", "醉来独枕莎衣睡。"]'),
('song-ci-625','清平乐','谢逸','宋','宋词','song-ci','清平乐','[]','晓风残角。',54,'宋词/ci.song.4000.json','["晓风残角。", "月里梅花落。", "宿酒醒时滋味恶。", "翠被轻寒漠漠。", "梦回一点相思。", "远山暗蹙双眉。", "不觉肌肤瘦玉，但知带减腰围。"]'),
('song-ci-626','清平乐','谢逸','宋','宋词','song-ci','清平乐','[]','花边柳际。',54,'宋词/ci.song.4000.json','["花边柳际。", "已渐知春意。", "归信不知何日是。", "旧恨欲拚无计。", "故人零落西东。", "题诗待倩归鸿。", "惟有多情芳草，年年处处相逢。"]'),
('song-ci-627','蓦山溪','谢逸','宋','宋词','song-ci','蓦山溪','[]','霜清木落，深院帘栊静。',102,'宋词/ci.song.4000.json','["霜清木落，深院帘栊静。", "池面卷烟波，莹香水、一奁明镜。", "修筠拂槛，疏翠挽婵娟，山雾敛，水云收，野阔江天迥。", "红消醉玉，酒面风前醒。", "罗幕护轻寒，锦屏空、金炉烬冷。", "星横参昴，梅径月黄昏，清梦觉，浅眉颦，窗外横斜影。"]'),
('song-ci-628','玉楼春','谢逸','宋','宋词','song-ci','玉楼春','[]','弄晴数点梨梢雨。',64,'宋词/ci.song.4000.json','["弄晴数点梨梢雨。", "门外画桥寒食路。", "杜鹃飞破草间烟，蛱蝶惹残花底露。", "东君著意怜樊素。", "一段韶华都付与。", "妆成不管露桃嗔，舞罢从教风柳妒。"]'),
('song-ci-629','玉楼春','谢逸','宋','宋词','song-ci','玉楼春','[]','横塘晕浅琉璃莹。',64,'宋词/ci.song.4000.json','["横塘晕浅琉璃莹。", "绿叶阴浓庭院静。", "樱桃熟后麦秋凉，芍药开时槐夏永。", "蓬莱阁下红尘境。", "青羽扇低摇凤影。", "庭前玉树一枝春，香雾和烟新月冷。"]'),
('song-ci-630','玉楼春','谢逸','宋','宋词','song-ci','玉楼春','[]','个中怀抱谁排遣。',64,'宋词/ci.song.4000.json','["个中怀抱谁排遣。", "恻恻轻寒风剪剪。", "细丝梅蕊晚香浓，争似柳梢春色浅。", "娇叱道字歌声软。", "醉后微涡回笑魇。", "更无卓氏白头吟，只有卢郎年少恨。"]'),
('song-ci-631','玉楼春','谢逸','宋','宋词','song-ci','玉楼春','[]','青钱点水圆荷绿。',64,'宋词/ci.song.4000.json','["青钱点水圆荷绿。", "解箨新篁森嫩玉。", "轻风冉冉楝花香，小雨丝丝梅子熟。", "华堂烛烬零金粟。", "人在洞天三十六。", "昭华吹彻管声寒，声入寿觞红浪蹙。"]'),
('song-ci-632','武陵春','谢逸','宋','宋词','song-ci','武陵春','[]','画烛笼纱红影乱，门外紫骝嘶。',56,'宋词/ci.song.4000.json','["画烛笼纱红影乱，门外紫骝嘶。", "分破云团月影亏。", "雪浪皱清漪。", "捧碗纤纤春笋瘦，乳雾泛冰瓷。", "两袖清风拂袖飞。", "归去酒醒时。"]'),
('song-ci-633','武陵春','谢逸','宋','宋词','song-ci','武陵春','[]','拍岸蒲萄江水碧，柳带挽归艎。',56,'宋词/ci.song.4000.json','["拍岸蒲萄江水碧，柳带挽归艎。", "破闷琴风绕袖凉。", "蔌蔌楝花香。", "淡烟疏雨随宜好，何处不潇湘。", "愿作双飞老凤皇。", "莫学野鸳鸯。"]'),
('song-ci-634','浪淘沙','谢逸','宋','宋词','song-ci','浪淘沙','[]','料峭小桃风。',64,'宋词/ci.song.4000.json','["料峭小桃风。", "凝淡春容。", "宝灯山列半天中。", "丽服靓妆携手处，笑语匆匆。", "酒滴小槽红。", "一饮千锺。", "铜荷擎烛绛纱笼。", "归去笙歌暄院落，月照帘栊。"]'),
('song-ci-635','鹧鸪天','谢逸','宋','宋词','song-ci','鹧鸪天','[]','桐叶成阴拂画檐。',64,'宋词/ci.song.4000.json','["桐叶成阴拂画檐。", "清风凉处卷疏帘。", "红绡舞袖萦腰柳，碧玉眉心媚脸莲。", "愁满眼，水连天。", "香笺小字倩谁传。", "梅黄楚岸垂垂雨，草碧吴江淡淡烟。"]'),
('song-ci-636','鹧鸪天','谢逸','宋','宋词','song-ci','鹧鸪天','[]','金节平分院落凉。',64,'宋词/ci.song.4000.json','["金节平分院落凉。", "黄昏帘幕卷西厢。", "冰轮碾碎粼粼碧，玉斧修成练练光。", "低照户，巧侵床。", "锦袍起舞谪仙狂。", "鹊飞影里觥筹乱，桂子风前笑语香。"]'),
('song-ci-637','鹧鸪天','谢逸','宋','宋词','song-ci','鹧鸪天','[]','红晕香腮粉末匀。',64,'宋词/ci.song.4000.json','["红晕香腮粉末匀。", "梳妆闲淡稳精神。", "谁知碧嶂清溪畔，也有姚家一朵春。", "眉黛浅，谁为颦。", "莫将心事付朝云。", "坐中有客肠应断，忘了酴醿架下人。"]'),
('song-ci-638','鹧鸪天','谢逸','宋','宋词','song-ci','鹧鸪天','[]','水阔天低雁字横。',64,'宋词/ci.song.4000.json','["水阔天低雁字横。", "小春时节晚寒清。", "梅梢月上纷纷白，竹坞风来冉冉轻。", "人似玉，酒如渑。", "入关意气喜风生。", "坐中有客联镳去，谁唱阳关第四声。"]'),
('song-ci-639','浣溪沙','谢逸','宋','宋词','song-ci','浣溪沙','[]','楼阁帘垂乳燕飞。',48,'宋词/ci.song.4000.json','["楼阁帘垂乳燕飞。", "圆荷细细点清溪。", "薰风破闷晚凉时。", "玉轸琴边兰思远，霜纨扇里翠眉低。", "揉蓝衫子闹蜂儿。"]'),
('song-ci-640','燕归梁','谢逸','宋','宋词','song-ci','燕归梁','[]','六曲阑干翠幕垂。',62,'宋词/ci.song.4000.json','["六曲阑干翠幕垂。", "香烬冷金猊。", "日高花外啭黄鹂。", "春睡觉、酒醒时。", "草青南浦，云横西塞，锦字杳无期。", "东风只送柳绵飞。", "全不管、寄相思。"]'),
('song-ci-641','千秋岁','谢逸','宋','宋词','song-ci','千秋岁','[]','楝花飘砌。',87,'宋词/ci.song.4000.json','["楝花飘砌。", "蔌蔌清香细。", "梅雨过，苹风起。", "情随湘水远，梦绕吴峰翠。", "琴书倦，鹧鸪唤起南窗睡。", "密意无人寄。", "幽恨凭谁洗。", "修竹畔，疏帘里。", "歌馀尘拂扇，舞罢风掀袂。", "人散后，一钩淡月天如水。"]'),
('song-ci-642','南乡子','谢逸','宋','宋词','song-ci','南乡子','[]','浅色染春衣。',66,'宋词/ci.song.4000.json','["浅色染春衣。", "衣上双双小雁飞。", "袖卷藕丝寒玉瘦，弹棋。", "赢得尊前酒一卮。", "冰雪拂胭脂。", "绛蜡香融落日西。", "唱彻阳关人欲去，依依。", "醉眼横波翠黛低。"]'),
('song-ci-643','醉落魄・一斛珠','谢逸','宋','宋词','song-ci','醉落魄・一斛珠','[]','霜砧声急。',67,'宋词/ci.song.4000.json','["霜砧声急。", "潇潇疏雨梧桐湿。", "无言独倚阑干立。", "帘卷黄昏，一阵西风入。", "年时画阁佳宾集。", "玉人檀板当筵执。", "银瓶已断丝绳汲。", "莫话前欢，忍对屏山泣。"]'),
('song-ci-644','鹊桥仙','谢逸','宋','宋词','song-ci','鹊桥仙','[]','蝶飞烟草，莺啼云树，满院垂杨阴绿。',68,'宋词/ci.song.4000.json','["蝶飞烟草，莺啼云树，满院垂杨阴绿。", "轻风飘散杏梢红，更吹皱、池波如縠。", "珠帘日晚，银屏人散，楼上醉横霜竹。", "一春若道不相思，缘底事、红绡褪玉。"]'),
('song-ci-645','江神子・江城子','谢逸','宋','宋词','song-ci','江神子・江城子','[]','一江秋水碧湾湾。',86,'宋词/ci.song.4000.json','["一江秋水碧湾湾。", "绕青山。", "玉连环。", "帘幕低垂，人在画图间。", "闲抱琵琶寻旧曲，弹未了，意阑珊。", "飞鸿数点拂云端。", "倚阑看。", "楚天寒。", "拟倩东风，吹梦到长安。", "恰似梨花春带雨，愁满眼，泪阑干。"]'),
('song-ci-646','江神子・江城子','谢逸','宋','宋词','song-ci','江神子・江城子','[]','杏花村馆酒旗风。',86,'宋词/ci.song.4000.json','["杏花村馆酒旗风。", "水溶溶。", "扬残红。", "野渡舟横，杨柳绿阴浓。", "望断江南山色远。", "人不见，草连空。", "夕阳楼外晚烟笼。", "粉香融。", "淡眉峰。", "记得年时，相见画屏中。", "只有关山今夜月，千里外，素光同。"]'),
('song-ci-647','点绛唇','谢逸','宋','宋词','song-ci','点绛唇','[]','九日登高，倚楼人在秋空半。',50,'宋词/ci.song.4000.json','["九日登高，倚楼人在秋空半。", "汝江如练。", "碧影涵云巘。", "醉看茱萸，定是明年健。", "清尊满。", "菊花黄浅。", "偏入陶潜眼。"]'),
('song-ci-648','点绛唇','谢逸','宋','宋词','song-ci','点绛唇','[]','金气秋分，风清露冷秋期半。',50,'宋词/ci.song.4000.json','["金气秋分，风清露冷秋期半。", "凉蟾光满。", "桂子飘香远。", "素练宽衣，仙仗明飞观。", "霓裳乱。", "银桥人散。", "吹彻昭华管。"]'),
('song-ci-649','七娘子','谢逸','宋','宋词','song-ci','七娘子','[]','风剪冰花飞零乱。',72,'宋词/ci.song.4000.json','["风剪冰花飞零乱。", "映梅梢、素影摇清浅。", "绣幄寒轻，兰薰烟暖。", "艳歌催得金荷卷。", "游梁已觉相如倦。", "忆去年、舟渡淮南岸。", "别后销魂，冷猿寒雁。", "角声只送黄昏怨。"]'),
('song-ci-650','卜算子','谢逸','宋','宋词','song-ci','卜算子','[]','烟雨幂横塘，绀色涵清浅。',52,'宋词/ci.song.4000.json','["烟雨幂横塘，绀色涵清浅。", "谁把并州快剪刀，剪取吴江半。", "隐几岸乌巾，细葛含风软。", "不见柴桑避俗翁，心共孤云远。"]'),
('song-ci-651','醉桃源・阮郎归','谢逸','宋','宋词','song-ci','醉桃源・阮郎归','[]','花枝破蕾柳梢青。',56,'宋词/ci.song.4000.json','["花枝破蕾柳梢青。", "春寒拂面轻。", "一眉新月影三星。", "铜荷烛烬零。", "低凤扇，袅霓旌。", "珊珊环佩声。", "坐间谁识许飞琼。", "对郎仙骨清。"]'),
('song-ci-652','醉桃源・阮郎归','谢逸','宋','宋词','song-ci','醉桃源・阮郎归','[]','风飘万点落花飞。',56,'宋词/ci.song.4000.json','["风飘万点落花飞。", "残红枝上稀。", "平芜叶上淡烟迷。", "那堪春鸟啼。", "风细细，日迟迟。", "轻纱叠雪衣。", "多情多病懒追随。", "玉人应恨伊。"]'),
('song-ci-653','醉桃源・阮郎归','谢逸','宋','宋词','song-ci','醉桃源・阮郎归','[]','晨光晓色扫檐晶。',56,'宋词/ci.song.4000.json','["晨光晓色扫檐晶。", "寒斋蝶梦惊。", "乱飘鸳瓦细无声。", "游扬柳丝轻。", "书幌冷，竹窗明。", "柴门只独扃。", "一尊浊酒为谁倾。", "梅花相对清。"]'),
('song-ci-654','望江南・忆江南','谢逸','宋','宋词','song-ci','望江南・忆江南','[]','临川好，柳岸转平沙。',64,'宋词/ci.song.4000.json','["临川好，柳岸转平沙。", "门外澄江丞相宅，坛前乔木列仙家。", "春到满城花。", "行乐处，舞袖卷轻纱。", "谩摘青梅尝煮酒，旋煎白雪试新茶。", "明月上檐牙。"]'),
('song-ci-655','望江南・忆江南','谢逸','宋','宋词','song-ci','望江南・忆江南','[]','临川好，山影碧波摇。',64,'宋词/ci.song.4000.json','["临川好，山影碧波摇。", "鱼跃冰池飞玉尺，云横石廪拂鲛绡。", "高树竹萧萧。", "寒食近，湖水绿平桥。", "繁杏梢头张锦旆，垂杨阴里系兰桡。", "游客解金貂。"]'),
('song-ci-656','柳梢青','谢逸','宋','宋词','song-ci','柳梢青','[]','香肩轻拍。',61,'宋词/ci.song.4000.json','["香肩轻拍。", "尊前忍听，一声将息。", "昨夜浓欢，今朝别酒，明日行客。", "后回来则须来，便去也、如何去得。", "无限离情，无穷江水，无边山色。"]'),
('song-ci-657','减字木兰花','夏倪','宋','宋词','song-ci','减字木兰花','[]','江涵晓日。',52,'宋词/ci.song.4000.json','["江涵晓日。", "荡漾波光摇桨入。", "笑指浯溪。", "漫叟雄文锁翠微。", "休嗟不偶。", "归到中州何处有。", "独立风烟。", "湘水浯台总接天。"]'),
('song-ci-658','汉宫春','晁冲之','宋','宋词','song-ci','汉宫春','[]','黯黯离怀，向东门系马，南浦移舟。',118,'宋词/ci.song.4000.json','["黯黯离怀，向东门系马，南浦移舟。", "薰风乱飞燕子，时下轻鸥。", "无情渭水，问谁教、日日东流。", "常是送、行人去后，烟波一向离愁。", "回首旧游如梦，记踏青殢饮，拾翠狂游。", "无端彩云易散，覆水难收。", "风流未老，拚千金，重入扬州。", "应又是、当年载酒，依前名占青楼。"]'),
('song-ci-659','玉蝴蝶','晁冲之','宋','宋词','song-ci','玉蝴蝶','[]','目断江南千里，灞桥一望，烟水微茫。',124,'宋词/ci.song.4000.json','["目断江南千里，灞桥一望，烟水微茫。", "尽锁重门，人去暗度流光。", "雨轻轻，梨花院落，风淡淡、杨柳池塘。", "恨偏长。", "佩沈湘浦，云散高唐。", "清狂。", "重来一梦，手搓梅子，煮酒初尝。", "寂寞经春，小桥依旧燕飞忙。", "玉钩栏、凭多渐暖，金缕枕、别久犹香。", "最难忘。", "看花南陌，待月西厢。"]'),
('song-ci-660','感皇恩','晁冲之','宋','宋词','song-ci','感皇恩','[]','小阁倚晴空，数声钟定。',82,'宋词/ci.song.4000.json','["小阁倚晴空，数声钟定。", "斗柄寒垂暮天净。", "向来残酒，尽被晓风吹醒。", "眼前还认得，当时景。", "旧恨与新愁，不堪重省。", "自叹多情更多病。", "绮窗犹在，敲遍阑干谁应。", "断肠明月下，梅摇影。"]'),
('song-ci-661','感皇恩','晁冲之','宋','宋词','song-ci','感皇恩','[]','蝴蝶满西园，啼莺无数。',83,'宋词/ci.song.4000.json','["蝴蝶满西园，啼莺无数。", "水阁桥南路。", "凝伫。", "两行烟柳，吹落一池飞絮。", "秋千斜挂起，人何处。", "把酒劝君，闲愁莫诉。", "留取笙歌住。", "休去。", "几多春色，禁得许多风雨。", "海棠花谢也，君知否。"]'),
('song-ci-662','感皇恩','晁冲之','宋','宋词','song-ci','感皇恩','[]','寒食不多时，牡丹初卖。',81,'宋词/ci.song.4000.json','["寒食不多时，牡丹初卖。", "小院重帘燕飞碍。", "昨宵风雨，只有一分春在，今朝犹自得，阴晴快。", "熟睡起来，宿酲微带。", "不惜罗襟搵眉黛，日高梳洗，看著花阴移改。", "笑摘双杏子，连枝戴。"]'),
('song-ci-663','临江仙','晁冲之','宋','宋词','song-ci','临江仙','[]','双舸亭亭横晚渚，城中飞观嵯峨。',70,'宋词/ci.song.4000.json','["双舸亭亭横晚渚，城中飞观嵯峨。", "画桥灯火照清波。", "玉钩平浸水，金锁半沈河。", "试问无情堤上柳，也应厌听离歌。", "人生无奈别离何。", "夜长嫌梦短，泪少怕愁多。"]'),
('song-ci-664','临江仙','晁冲之','宋','宋词','song-ci','临江仙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','忆昔西池池上饮，年年多少欢娱。',70,'宋词/ci.song.4000.json','["忆昔西池池上饮，年年多少欢娱。", "别来不寄一行书。", "寻常相见了，犹道不如初。", "安稳锦屏今夜梦，月明好度江湖。", "相思休问定何如。", "情知春去后，管得落花无。"]'),
('song-ci-665','临江仙','晁冲之','宋','宋词','song-ci','临江仙','[]','谩道追欢惟九日，年年此恨偏浓。',70,'宋词/ci.song.4000.json','["谩道追欢惟九日，年年此恨偏浓。", "今朝吹帽与谁同。", "黄花都未拆，和泪泣西风。", "应恐登临肠更断，故交烟雨迷空。", "为君一曲送飞鸿。", "谁能推毂我，深入醉乡中。"]'),
('song-ci-666','渔家傲','晁冲之','宋','宋词','song-ci','渔家傲','[]','浦口潮来沙尾涨。',72,'宋词/ci.song.4000.json','["浦口潮来沙尾涨。", "危樯半落帆游漾，水调不知何处唱。", "风淡荡。", "鳜鱼吹起桃花浪。", "雪尽小桥梅总放。", "层楼一任愁人上。", "万里长安回首望。", "山四向。", "澄江日色如春酿。"]'),
('song-ci-667','传言玉女','晁冲之','宋','宋词','song-ci','传言玉女','[]','一夜东风，吹散柳梢残雪。',91,'宋词/ci.song.4000.json','["一夜东风，吹散柳梢残雪。", "御楼烟暖，正鳌山对结。", "箫鼓向晚，凤辇初归宫阙。", "千门灯火，九街风月。", "绣阁人人，乍喜游、困又歇。", "笑匀妆面，把朱帘半揭。", "娇波向人，手拈玉梅低说。", "相逢常是，上元时节。"]'),
('song-ci-668','如梦令','晁冲之','宋','宋词','song-ci','如梦令','[]','帘外新来双燕。',40,'宋词/ci.song.4000.json','["帘外新来双燕。", "珠阁琼楼穿遍。", "香径得泥归，飞蹙池塘波面。", "谁见。", "谁见。", "春晚昭阳宫殿。"]'),
('song-ci-669','如梦令','晁冲之','宋','宋词','song-ci','如梦令','[]','墙外辘轳金并。',40,'宋词/ci.song.4000.json','["墙外辘轳金并。", "惊梦瞢腾初省。", "深院闭斜阳，燕入阴阴帘影。", "人静。", "人静。", "花落鸟啼风定。"]'),
('song-ci-670','如梦令','晁冲之','宋','宋词','song-ci','如梦令','[]','门在垂杨阴里。',40,'宋词/ci.song.4000.json','["门在垂杨阴里。", "楼枕曲江春水。", "一阵牡丹风，香压满园花气。", "沈醉。", "沈醉。", "不记绿窗先睡。"]'),
('song-ci-671','上林春慢','晁冲之','宋','宋词','song-ci','上林春慢','[]','帽落宫花，衣惹御香，凤辇晚来初过。',127,'宋词/ci.song.4000.json','["帽落宫花，衣惹御香，凤辇晚来初过。", "鹤降诏飞，龙擎烛戏，端门万枝灯火。", "满城车马，对明月、有谁闲坐。", "任狂游，更许傍禁街，不局金锁。", "玉楼人、暗中掷果。", "珍帘下、笑著春衫袅娜。", "素蛾绕钗，轻蝉扑鬓，垂垂柳丝梅朵。", "夜阑饮散，但赢得、翠翘双亸。", "醉归来，又重向、晓窗梳裹。"]'),
('song-ci-672','汉宫春','晁冲之','宋','宋词','song-ci','汉宫春','[]','潇洒江梅，向竹梢稀处，横两三枝。',118,'宋词/ci.song.4000.json','["潇洒江梅，向竹梢稀处，横两三枝。", "东君也不爱惜，雪压风欺。", "无情燕子，怕春寒、轻失佳期。", "惟是有、南来归雁，年年长见开时。", "清浅小溪如练，问玉堂何似，茅舍疏篱。", "伤心故人去后，冷落新诗。", "微云淡月，对孤芳、分付他谁。", "空自倚，清香未减，风流不在人知。"]'),
('song-ci-673','小重山','晁冲之','宋','宋词','song-ci','小重山','[]','碧水浮瓜纹簟前。',70,'宋词/ci.song.4000.json','["碧水浮瓜纹簟前。", "只知闲枕手，不成眠。", "晚云如火雨晴天。", "轻云远，亭外一声蝉。", "池馆几年年。", "倚阑催小艇，采新莲。", "多情还到芰荷边。", "应相忆，折藕看丝牵。"]'),
('song-ci-674','临江仙','苏庠','宋','宋词','song-ci','临江仙','[]','本是白苹洲畔客，虎符卧镇江城。',70,'宋词/ci.song.4000.json','["本是白苹洲畔客，虎符卧镇江城。", "归来犹得趁鸥盟。", "柳丝摇晓市，杜若遍芳汀。", "莫惜飞觞仍堕帻，柳边依约莺声。", "水秋鲈熟正关情。", "只愁宣室召，未许钓船轻。"]'),
('song-ci-675','临江仙','苏庠','宋','宋词','song-ci','临江仙','[]','猎猎风蒲初暑过，萧然庭户秋清。',70,'宋词/ci.song.4000.json','["猎猎风蒲初暑过，萧然庭户秋清。", "野航渡口带烟横。", "晚山千万叠，别鹤两三声。", "秋水芙蓉聊荡桨，一樽同破愁城。", "蓼花滩上白鸥明。", "暮云连极浦，急雨暗长汀。"]'),
('song-ci-676','如梦令','苏庠','宋','宋词','song-ci','如梦令','[]','叠嶂晓埋烟雨。',40,'宋词/ci.song.4000.json','["叠嶂晓埋烟雨。", "忽作飞花无数。", "整整复斜斜，来伴南枝清苦。", "日暮。", "日暮。", "何许云林烟树。"]'),
('song-ci-677','虞美人','苏庠','宋','宋词','song-ci','虞美人','[]','军书未息梅仍破。',66,'宋词/ci.song.4000.json','["军书未息梅仍破。", "穿市溪流过。", "病来无处不关情。", "一夜鸣榔急雨、杂滩声。", "飘零无复还山梦。", "云屋春寒重。", "山连积水水连空。", "溪上青蒲短短、柳重重。"]'),
('song-ci-678','浣溪沙','苏庠','宋','宋词','song-ci','浣溪沙','[]','水榭风微玉枕凉。',48,'宋词/ci.song.4000.json','["水榭风微玉枕凉。", "牙床角簟藕花香。", "野塘烟雨罩鸳鸯。", "红蓼渡头青嶂远，绿苹波上白鸥双。", "淋浪淡墨水云乡。"]'),
('song-ci-679','谒金门','苏庠','宋','宋词','song-ci','谒金门','[]','何处所。',53,'宋词/ci.song.4000.json','["何处所。", "门外冷云堆浦。", "竹里江梅寒未吐。", "茅屋疏疏雨。", "谁遣愁来如许。", "小立野塘官渡。", "手种凌霄今在否。", "柳浪迷烟渚。"]'),
('song-ci-680','谒金门','苏庠','宋','宋词','song-ci','谒金门','[]','杨柳渡。',53,'宋词/ci.song.4000.json','["杨柳渡。", "醉著青鞋归去。", "点点沙鸥何处所。", "十里菰蒲雨。", "抖擞向来尘土。", "卧看碧山云度。", "寄语故时猿鹤侣。", "未见心先许。"]'),
('song-ci-681','鹧鸪天','苏庠','宋','宋词','song-ci','鹧鸪天','[]','枫落河梁野水秋。',64,'宋词/ci.song.4000.json','["枫落河梁野水秋。", "澹烟衰草接郊丘。", "醉眠小坞黄茅店，梦倚高城赤叶楼。", "天杳杳，路悠悠。", "钿筝歌扇等闲休。", "灞桥杨柳年年恨，鸳浦芙蓉叶叶愁。"]'),
('song-ci-682','鹧鸪天','苏庠','宋','宋词','song-ci','鹧鸪天','[]','梅妒晨妆雪妒轻。',64,'宋词/ci.song.4000.json','["梅妒晨妆雪妒轻。", "远山依约学眉青。", "樽前无复歌金缕，梦觉空馀月满林。", "鱼与雁，两浮沈。", "浅颦微笑总关心。", "相思恰似江南柳，一夜春风一夜深。"]'),
('song-ci-683','鹧鸪天','苏庠','宋','宋词','song-ci','鹧鸪天','[]','秋入蒹葭小雁行。',64,'宋词/ci.song.4000.json','["秋入蒹葭小雁行。", "参差飞堕水云乡。", "直须银甲供春笋，且滴糟床覆羽觞。", "风压幕，月侵廊。", "江南江北夜茫茫。", "悬知上马啼鹃梦，一夜惊飞宝鸭香。"]'),
('song-ci-684','诉衷情','苏庠','宋','宋词','song-ci','诉衷情','[]','杖头挑得布囊行。',54,'宋词/ci.song.4000.json','["杖头挑得布囊行。", "活计有谁争。", "不肯侯家五鼎，碧涧一杯羹。", "溪上月，岭头云。", "不劳耕。", "瓮中春色，枕上华胥，便是长生。"]'),
('song-ci-685','诉衷情','苏庠','宋','宋词','song-ci','诉衷情','[]','倦投林樾当诛茅。',54,'宋词/ci.song.4000.json','["倦投林樾当诛茅。", "鸿雁响寒郊。", "溪上晚来杨柳，月露洗烟梢。", "霜后渚，水分槽。", "尚平桥。", "客床归梦，何必江南，门接云涛。"]'),
('song-ci-686','阮郎归','苏庠','宋','宋词','song-ci','阮郎归','[]','西园风暖落花时。',56,'宋词/ci.song.4000.json','["西园风暖落花时。", "绿阴莺乱啼。", "倚阑无语惜芳菲。", "絮飞蝴蝶飞。", "缘底事，减腰围。", "遣愁愁著眉。", "波连春渚暮天垂。", "燕归人未归。"]'),
('song-ci-687','点绛唇','苏庠','宋','宋词','song-ci','点绛唇','[]','冰勒轻飔，绿痕初涨回塘水。',50,'宋词/ci.song.4000.json','["冰勒轻飔，绿痕初涨回塘水。", "柳洲烟际。", "白鹭翘沙嘴。", "箬笠青蓑，未减貂蝉贵。", "云涛里。", "醉眠篷底。", "不属人间世。"]'),
('song-ci-688','菩萨蛮','苏庠','宋','宋词','song-ci','菩萨蛮','[]','北风振野云平屋。',52,'宋词/ci.song.4000.json','["北风振野云平屋。", "寒溪淅淅流冰谷。", "落日送归鸿。", "夕岚千万重。", "荒坡垂斗柄。", "直北乡山近。", "何必苦言归。", "石亭春满枝。"]'),
('song-ci-689','菩萨蛮','苏庠','宋','宋词','song-ci','菩萨蛮','[]','园林寂寂春归去。',52,'宋词/ci.song.4000.json','["园林寂寂春归去。", "濛濛柳下飞香絮。", "野水接云横。", "绿烟啼晓莺。", "江南鶗鴂梦。", "山色朝来重。", "小艇小湾头。", "苹花苹叶洲。"]'),
('song-ci-690','菩萨蛮','苏庠','宋','宋词','song-ci','菩萨蛮','[]','短船谁泊蒹葭渚。',52,'宋词/ci.song.4000.json','["短船谁泊蒹葭渚。", "夜深远火明渔浦。", "却忆槿花篱。", "春声穿竹溪。", "云山如昨好。", "人自垂垂老。", "心事有谁知。", "月明霜满枝。"]'),
('song-ci-691','菩萨蛮','苏庠','宋','宋词','song-ci','菩萨蛮','[]','眼中叠叠烟中树。',52,'宋词/ci.song.4000.json','["眼中叠叠烟中树。", "晚云点点翻荷雨。", "鸥泛渚边烟。", "绿蒲秋满川。", "未成江海去。", "聊作林塘主。", "客恨阔无津。", "风斜白氎巾。"]'),
('song-ci-692','菩萨蛮','苏庠','宋','宋词','song-ci','菩萨蛮','[]','年时忆著花前醉。',52,'宋词/ci.song.4000.json','["年时忆著花前醉。", "而今花落人憔悴。", "麦浪卷晴川。", "杜鹃声可怜。", "有书无雁寄。", "初夏槐风细。", "家在落霞边。", "愁逢江月圆。"]'),
('song-ci-693','菩萨蛮','苏庠','宋','宋词','song-ci','菩萨蛮','[]','照溪梅雪和烟堕。',52,'宋词/ci.song.4000.json','["照溪梅雪和烟堕。", "寒林漠漠愁烟锁。", "客恨渺无涯。", "雁来人忆家。", "远山疑带雨。", "一线云间语。", "霜月又婵娟。", "江南若个边。"]'),
('song-ci-694','菩萨蛮','苏庠','宋','宋词','song-ci','菩萨蛮','[]','春波滟滟浮春渚。',52,'宋词/ci.song.4000.json','["春波滟滟浮春渚。", "绿阴一径风兼雨。", "又作去年时。", "绿深垂蔓篱。", "故山归兴动。", "江北江南梦。", "白发故相欺。", "星星如有期。"]'),
('song-ci-695','木兰花・玉楼春','苏庠','宋','宋词','song-ci','木兰花・玉楼春','[]','江云叠叠遮鸳浦。',64,'宋词/ci.song.4000.json','["江云叠叠遮鸳浦。", "江水无情留薄暮。", "归帆初张苇边风，客梦不禁篷背雨。", "渚花不解留人住。", "只作深愁无尽处。", "白沙烟树有无中，雁落沧洲何处所。"]'),
('song-ci-696','清平乐','苏庠','宋','宋词','song-ci','清平乐','[]','断崖流水。',54,'宋词/ci.song.4000.json','["断崖流水。", "香度青林底。", "元配骚人兰与芷。", "不数春风桃李。", "淮南丛桂小山。", "诗翁合得攀翻。", "身到十洲三岛，心游万壑千岩。"]'),
('song-ci-697','小重山','祖可','宋','宋词','song-ci','小重山','[]','谁向江头遣恨浓。',70,'宋词/ci.song.4000.json','["谁向江头遣恨浓。", "碧波流不断，楚山重。", "柳烟和雨隔疏钟。", "黄昏后，罗幕更朦胧。", "桃李小园空。", "阿谁犹笑语，拾残红。", "珠帘卷尽落花风。", "人不见，春在绿芜中。"]'),
('song-ci-698','菩萨蛮','祖可','宋','宋词','song-ci','菩萨蛮','[]','西风簌簌低红叶。',52,'宋词/ci.song.4000.json','["西风簌簌低红叶。", "梧桐影里银河匝。", "梦破画帘垂。", "月明乌鹊飞。", "新愁知几许。", "欲似丝千缕。", "雁已不堪闻。", "砧声何处村。"]'),
('song-ci-699','菩萨蛮','祖可','宋','宋词','song-ci','菩萨蛮','[]','谁能画取沙边雨。',52,'宋词/ci.song.4000.json','["谁能画取沙边雨。", "和烟澹扫蒹葭渚。", "别岸却斜晖。", "采莲人未归。", "鸳鸯如解语。", "对浴红衣去。", "去了更回头。", "教侬特地愁。"]'),
('song-ci-700','失调名','蔡','宋','宋词','song-ci','失调名','[]','扇开仙掌。',5,'宋词/ci.song.4000.json','["扇开仙掌。"]'),
('song-ci-701','声声慢','张阁','宋','宋词','song-ci','声声慢','[]','长天霞散，远浦潮平，危阑注目江皋。',118,'宋词/ci.song.4000.json','["长天霞散，远浦潮平，危阑注目江皋。", "长记年年荣遇，同是今朝。", "金銮两回命相，对清光、频许挥毫。", "雍容久，正茶杯初赐，香袖时飘。", "归去玉堂深夜，泥封罢，金莲一寸才烧。", "帝语丁宁，曾被华衮亲褒。", "如今谩劳梦想，叹尘踪、杳隔仙鳌。", "无聊意，强当歌对酒怎消。"]'),
('song-ci-702','水调歌头','毛滂','宋','宋词','song-ci','水调歌头','[]','九金增宋重，八玉变秦馀。',114,'宋词/ci.song.4000.json','["九金增宋重，八玉变秦馀。", "千年清浸，洗净河洛出图书。", "一段升平光景，不但五星循轨，万点共连珠。", "垂衣本神圣，补衮妙工夫。", "朝元去，锵环佩，冷云衢。", "芝房雅奏，仪凤矫首听笙竽。", "天近黄麾仗晓，春早红鸾扇暖，迟日上金铺。", "万岁南山色，不老对唐虞。"]'),
('song-ci-703','绛都春','毛滂','宋','宋词','song-ci','绛都春','[]','馀寒尚峭。',118,'宋词/ci.song.4000.json','["馀寒尚峭。", "早凤沼冻开，芝田春到。", "茂对诞期，天与公春向廊庙。", "元工开物争春妙。", "付与秾华多少。", "召还和气，拂开霁色，未妨谈笑。", "缥缈。", "五云乱处，种雕菰向熟，碧桃犹小。", "雨露在门，光采充闾乌亦好。", "宝熏郁雾城南道。", "天自锡公难老。", "看公身任安危，二十四考。"]'),
('song-ci-704','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','九重寒少。',54,'宋词/ci.song.4000.json','["九重寒少。", "烟暖丰瑶草。", "金井碧梧雏凤矫。", "南极人来最老。", "衣冠远换裘毡。", "德随和气蝉连。", "万里同开寿域，一年三秀芝田。"]'),
('song-ci-705','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','重芳叠秀。',54,'宋词/ci.song.4000.json','["重芳叠秀。", "风约仙云皱。", "椿不争年松与寿。", "共出皇家忠孝。", "仁深枯冷皆蒙。", "托根不倚东风。", "日照恩光万里，暖生塞草丛中。"]'),
('song-ci-706','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','镂烟翦雾。',54,'宋词/ci.song.4000.json','["镂烟翦雾。", "𩉾鞢无层数。", "苜蓿青深烦雪兔。", "引到祥华开处。", "仙人手翳朝阳。", "清都绛阙相将。", "来覆东封翠辇，好遮化日舒长。"]'),
('song-ci-707','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','九茎为寿。',54,'宋词/ci.song.4000.json','["九茎为寿。", "千叶前无有。", "叶叶年年看不朽。", "天与君主意厚。", "君恩雨露无边。", "玉筵暖接非烟。", "马向华山烽冷，人安草亦千年。"]'),
('song-ci-708','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','绛河千岁。',54,'宋词/ci.song.4000.json','["绛河千岁。", "一照升平事。", "万里青铜开碧霁。", "俯见南山晚翠。", "绀寒不翅湘酃。", "清於练静江澄。", "流向万年觞里，玉波可但如渑。"]'),
('song-ci-709','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','银河秋浪。',54,'宋词/ci.song.4000.json','["银河秋浪。", "遥出昆仑上。", "忽变澄澜添碧涨。", "可道升平无象。", "黄云浊雾初开。", "荣光休气徘徊。", "试觅当时五老，金泥玉检将来。"]'),
('song-ci-710','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','天连翠潋。',54,'宋词/ci.song.4000.json','["天连翠潋。", "九折玻璃软。", "回抱金堤清宛转。", "疑共蓬莱清浅。", "吾君欲济如何。", "唐虞风顺无多。", "自有松舟桧楫，一帆三代同波。"]'),
('song-ci-711','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','娟娟月满。',54,'宋词/ci.song.4000.json','["娟娟月满。", "冉冉梅花暖。", "春意初长寒力浅。", "渐拟芳菲满眼。", "当时吉梦重重。", "间生天子三公。", "付与人间桃李，年年管领春风。"]'),
('song-ci-712','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','瀛洲春酒。',54,'宋词/ci.song.4000.json','["瀛洲春酒。", "满酌公眉寿。", "日照沙堤春傍柳。", "恩暖朝天衮绣。", "东君著意丁宁。", "芳酸先许梅英。", "要就生平滋味，待公来进君羹。"]'),
('song-ci-713','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','雪馀寒退。',54,'宋词/ci.song.4000.json','["雪馀寒退。", "唯有青松在。", "春不加荣寒不悴。", "用舍如公都耐。", "流肪磊硌龟蛇。", "会留红日西斜。", "欲助我公寿骨，蟠桃等见开花。"]'),
('song-ci-714','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','流光电急。',54,'宋词/ci.song.4000.json','["流光电急。", "又过书云日。", "旧是天津花下客。", "老对山青水碧。", "而今转惜年华。", "迟阳为缓西斜。", "试问东君音信，晓寒犹压梅花。"]'),
('song-ci-715','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','云峰秀叠。',54,'宋词/ci.song.4000.json','["云峰秀叠。", "露冷琉璃叶。", "北畔娑罗花弄雪。", "香度小桥淡月。", "与君踏月寻花。", "玉人双捧流霞。", "吸尽杯中花月，仙风相送还家。"]'),
('song-ci-716','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','东风桂影。',54,'宋词/ci.song.4000.json','["东风桂影。", "低拂姮娥镜。", "镜里妆寒酥粉莹。", "越恁十分端正。", "素光行处随人。", "柳边照见青春。", "一片笙箫何处，花阴定有遗簪。"]'),
('song-ci-717','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','曲房青琐。',54,'宋词/ci.song.4000.json','["曲房青琐。", "浅笑樱桃破。", "睡起三竿红日过。", "冷了沈香残火。", "东风偏管伊家。", "剩教那与秾华。", "谁送一怀春思，玉台燕拂菱花。"]'),
('song-ci-718','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','杏花时候。',54,'宋词/ci.song.4000.json','["杏花时候。", "庭下双梅瘦。", "天上流霞凝碧袖。", "起舞与君为寿。", "两桥风月同来。", "东堂且没尘埃。", "烟艇何时重理，更凭风月相催。"]'),
('song-ci-719','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','兰堂灯灺。',54,'宋词/ci.song.4000.json','["兰堂灯灺。", "春入流苏夜。", "衣褪轻红闻水麝。", "云重宝钗未卸。", "知君不奈情何。", "时时慢转横波。", "一饷花柔柳困，枕前特地春多。"]'),
('song-ci-720','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','风摇灺烬。',54,'宋词/ci.song.4000.json','["风摇灺烬。", "吹下桃花影。", "醉倒碧铺眠碎锦。", "谁伴香迷酒凝。", "少年不解孤春。", "年来减尽春心。", "犹下绣帘遮定，不教风雨侵凌。"]'),
('song-ci-721','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','桃夭杏好。',54,'宋词/ci.song.4000.json','["桃夭杏好。", "似个人人好。", "淡抹胭脂眉不扫。", "笑里知春占了。", "此情没个人知。", "灯前仔细看伊。", "恰似云屏半醉，不言不语多时。"]'),
('song-ci-722','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','杯深莫厌。',54,'宋词/ci.song.4000.json','["杯深莫厌。", "强看桃花面。", "记约阳和初一线。", "便恁芳菲满眼。", "明年春色重来。", "东堂花为谁开。", "我在芦花深处，钓矶雨绿莓苔。"]'),
('song-ci-723','清平乐','毛滂','宋','宋词','song-ci','清平乐','[]','锦屏夜夜。',54,'宋词/ci.song.4000.json','["锦屏夜夜。", "绣被熏兰麝。", "帐卷芙蓉长不下。", "垂尽银台蜡灺。", "脸痕微著流霞。", "瞢腾越恁秾华。", "破睡半残妆粉，月随雪到梅花。"]'),
('song-ci-724','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','碧雾朦胧郁宝熏。',48,'宋词/ci.song.4000.json','["碧雾朦胧郁宝熏。", "和风容曳舞帘旌。", "花间千骑两朱轮。", "金马天材文作锦，玉堂仙骨气如冰。", "湖山何似使君清。"]'),
('song-ci-725','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','曾向瑶台月下逢。',48,'宋词/ci.song.4000.json','["曾向瑶台月下逢。", "为谁回首矮墙东。", "春风吹酒退腮红。", "庾岭殷勤通远信，梅家潇洒有仙风。", "晚香都在玉杯中。"]'),
('song-ci-726','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','谢女清吟压郢楼。',48,'宋词/ci.song.4000.json','["谢女清吟压郢楼。", "楼前风转柳花球。", "学成舞态却多羞。", "半落琼瑶天又惜，稍侵桃李蝶应愁。", "酒家先当翠云裘。"]'),
('song-ci-727','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','小圃韶光不待邀。',48,'宋词/ci.song.4000.json','["小圃韶光不待邀。", "早通消耗与含桃。", "晚来芳意半寒梢。", "含笑不言春淡淡，试妆未遍雨萧萧。", "东家小女可怜娇。"]'),
('song-ci-728','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','日照遮檐绣凤凰。',48,'宋词/ci.song.4000.json','["日照遮檐绣凤凰。", "博山金暖一帘香。", "尊前光景为君长。", "不信腊寒雕鬓影，渐匀春意上妆光。", "梅花长共占年芳。"]'),
('song-ci-729','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','花市东风卷笑声。',48,'宋词/ci.song.4000.json','["花市东风卷笑声。", "柳溪人影乱於云。", "梅花何处暗香闻。", "露湿翠云裘上月，烛摇红锦帐前春。", "瑶台有路渐无尘。"]'),
('song-ci-730','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','月样婵娟雪样清。',48,'宋词/ci.song.4000.json','["月样婵娟雪样清。", "索强先占百花春。", "於中烛底好精神。", "多恨肌肤元自瘦，半残妆粉不忺匀。", "十分全似那人人。"]'),
('song-ci-731','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','水北烟寒雪似梅。',48,'宋词/ci.song.4000.json','["水北烟寒雪似梅。", "水南梅闹雪千堆。", "月明南北两瑶台。", "云近恰如天上坐，魂清疑向斗边来。", "梅花多处载春回。"]'),
('song-ci-732','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','小雨初收蝶做团。',48,'宋词/ci.song.4000.json','["小雨初收蝶做团。", "和风轻拂燕泥乾。", "秋千院落落花寒。", "莫对清尊追往事，更催新火续馀欢。", "一春心绪倚阑干。"]'),
('song-ci-733','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','魏紫姚黄欲占春。',48,'宋词/ci.song.4000.json','["魏紫姚黄欲占春。", "不教桃杏见清明。", "残红吹尽恰才晴。", "芳草池塘新涨绿，官桥杨柳半拖青。", "秋千院落管弦声。"]'),
('song-ci-734','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','晚色寒清如四檐。',48,'宋词/ci.song.4000.json','["晚色寒清如四檐。", "梧桐冷碧到疏帘。", "小花未了烛花偏。", "瑶瓮孛堆春这里，锦屏屈曲梦谁边。", "熏笼香暖索衣添。"]'),
('song-ci-735','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','碧浸澄沙上下天。',48,'宋词/ci.song.4000.json','["碧浸澄沙上下天。", "曲堤疏柳短长烟。", "月明不待十分圆。", "凿落未空牙板闹，阑干久凭夹衣寒。", "婵娟薄幸冷相看。"]'),
('song-ci-736','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','碧户珠窗小洞房。',48,'宋词/ci.song.4000.json','["碧户珠窗小洞房。", "玉醅新压嫩鹅黄。", "半青橙子可怜香。", "风露满帘清似水，笙箫一片醉为乡。", "芙蓉绣冷夜初长。"]'),
('song-ci-737','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','松菊秋来好在无。',48,'宋词/ci.song.4000.json','["松菊秋来好在无。", "寄声猿鹤莫情疏。", "渊明不老久踟蹰。", "打鼓枫林谁作社，枕溪茅屋忆吾庐。", "去年醉倒倩人扶。"]'),
('song-ci-738','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','本是青门学灌园。',48,'宋词/ci.song.4000.json','["本是青门学灌园。", "生涯浑在乱山前。", "一犁春雨种瓜田。", "别后倩云遮鹤帐，来时和月寄渔船。", "旁人莫做长官看。"]'),
('song-ci-739','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','晚色轻凉入画船。',48,'宋词/ci.song.4000.json','["晚色轻凉入画船。", "云峰飞尽玉为天。", "疏飙自为月褰帘。", "细酌流霞君且住，更深风月更清妍。", "为谁凄断小桥边。"]'),
('song-ci-740','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','锦里无端无素书。',48,'宋词/ci.song.4000.json','["锦里无端无素书。", "长安秋晚忆家无。", "故人来此尚踟蹰。", "旧事殷勤休忘了，老来凄断恶消除。", "小楼雪夜记当初。"]'),
('song-ci-741','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','记得山翁往少年。',48,'宋词/ci.song.4000.json','["记得山翁往少年。", "青楼一笑万金钱。", "宝鞍逐月玉鞭寒。", "老对冻醪留客话，醉爬短发枕书眠。", "伴人松雨隔疏帘。"]'),
('song-ci-742','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','烟柳风蒲冉冉斜。',48,'宋词/ci.song.4000.json','["烟柳风蒲冉冉斜。", "小窗不用著帘遮。", "载将山影转湾沙。", "略彴断时分岸色，蜻蜓立处过汀花。", "此情此水共天涯。"]'),
('song-ci-743','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','蕙炷犹熏百和秾。',48,'宋词/ci.song.4000.json','["蕙炷犹熏百和秾。", "兰膏正烂五枝红。", "风流云散太匆匆。", "仙草已添君胜爽，醉乡肯为我从容。", "剩风残月小庭空。"]'),
('song-ci-744','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','银字笙箫小小童。',48,'宋词/ci.song.4000.json','["银字笙箫小小童。", "梁洲吹过柳桥风。", "阿谁劝我玉杯空。", "小醉径须眠锦瑟，夜归不用照纱笼。", "画船帘卷月明中。"]'),
('song-ci-745','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','滟滟金波暖做春。',48,'宋词/ci.song.4000.json','["滟滟金波暖做春。", "疏疏烟柳瘦於人。", "柳边半醉不胜情。", "未解画船留待月，缓歌金缕细留云。", "将云带月入东门。"]'),
('song-ci-746','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','蜡烛花中月满窗。',48,'宋词/ci.song.4000.json','["蜡烛花中月满窗。", "楚梅初试寿阳妆。", "麒麟为脯玉为浆。", "花影烛光相动荡，抱持春色入金觞。", "鸭炉从冷醉魂香。"]'),
('song-ci-747','天香','毛滂','宋','宋词','song-ci','天香','[]','进止详华，文章尔雅，金銮恩异群彦。',118,'宋词/ci.song.4000.json','["进止详华，文章尔雅，金銮恩异群彦。", "尘断银台，天低鳌禁，最是玉皇香案。", "燕公视草，星斗动、昭回云汉。", "对罢宵分，又是金莲，烛引归院。", "年来偃藩江畔。", "赖湖山、慰公心眼。", "碧瓦千家，少借裤襦馀暖。", "黄气珠庭渐满。", "望红日、长安殊不远。", "缓辔端门，青春未晚。"]'),
('song-ci-748','小重山','毛滂','宋','宋词','song-ci','小重山','[]','碧瓦朱甍紫翠深。',70,'宋词/ci.song.4000.json','["碧瓦朱甍紫翠深。", "玻璃屏障里，锦为城。", "子胥英爽海涛横。", "玉堂人，於此劝春耕。", "五月政当成。", "岩廊将去路，肯留行。", "江山雄胜为公倾。", "公惜醉，风月若为情。"]'),
('song-ci-749','小重山','毛滂','宋','宋词','song-ci','小重山','[]','谁劝东风腊里来。',70,'宋词/ci.song.4000.json','["谁劝东风腊里来。", "不知天待雪，恼江梅。", "东郊寒色尚徘徊。", "双彩燕，飞傍鬓云堆。", "玉冷晓妆台。", "宜春金缕字，拂香腮。", "红罗先绣踏青鞋。", "春犹浅，花信更须催。"]'),
('song-ci-750','小重山','毛滂','宋','宋词','song-ci','小重山','[]','门外东风糁玉尘。',70,'宋词/ci.song.4000.json','["门外东风糁玉尘。", "曲房花气蔼，博山春。", "小槽珠滴桂椒芬。", "梅蕊绽，谁共醉中闻。", "睡起静无人。", "曲屏横远翠，锦为邻。", "十年旧事梦如新。", "红蕤枕，犹暖楚峰云。"]'),
('song-ci-751','小重山','毛滂','宋','宋词','song-ci','小重山','[]','鹤舞青青雪里松。',70,'宋词/ci.song.4000.json','["鹤舞青青雪里松。", "冰开龟在藻，绿蒙茸。", "一成不记蕊珠宫。", "蟠桃熟，应待几东风。", "玉酒紫金锺。", "非烟罗幕暖，宝熏秾。", "赠君春色腊寒中。", "君留取，长伴脸边红。"]'),
('song-ci-752','满庭芳','毛滂','宋','宋词','song-ci','满庭芳','[]','烁石炎曦，过云急雨，院落槐午阴清。',118,'宋词/ci.song.4000.json','["烁石炎曦，过云急雨，院落槐午阴清。", "藕花开遍，绿细一池萍。", "槽下真珠溜溜，龙团破、河朔馀酲。", "阑干外，梧桐叶底，金井辘轳声。", "盈盈。", "开雾帐，珊瑚连枕，云母围屏。", "对肌肤冰雪，自有凉生。", "翠袖风回画扇，拂香篆、虬尾斜横。", "北窗晚，娟娟静色，竹影上帘旌。"]'),
('song-ci-753','满庭芳','毛滂','宋','宋词','song-ci','满庭芳','[]','马络青丝，障开红锦，小晴初断香尘。',118,'宋词/ci.song.4000.json','["马络青丝，障开红锦，小晴初断香尘。", "芳醪满载，持烛有佳人。", "飞盖西园午夜，花梢冷、云月胧明。", "折还惜，留花伴月，占定可怜春。", "佳人。", "争插帽，已残芳树，犹缀馀英。", "任红辞香散，蝶恨蜂嗔。", "醉也和春戴去，深院落、初馥炉熏。", "玉台畔，未教卸了，留映晚妆新。"]'),
('song-ci-754','摊声浣溪沙・浣溪沙','毛滂','宋','宋词','song-ci','摊声浣溪沙・浣溪沙','[]','日照门前千万峰。',56,'宋词/ci.song.4000.json','["日照门前千万峰。", "晴飙先扫冻云空。", "谁作素涛翻玉手，小团龙。", "定国精明过少壮，次公烦碎本雍容。", "听讼阴中苔自绿，舞衣红。"]'),
('song-ci-755','摊声浣溪沙・浣溪沙','毛滂','宋','宋词','song-ci','摊声浣溪沙・浣溪沙','[]','日转堂阴一线添。',56,'宋词/ci.song.4000.json','["日转堂阴一线添。", "使君和气作春妍。", "祗有北山轻带雪，见丰年。", "残月夜来收不尽，行云早起更留连。", "急翦垂杨迎秀色，到窗前。"]'),
('song-ci-756','摊声浣溪沙・浣溪沙','毛滂','宋','宋词','song-ci','摊声浣溪沙・浣溪沙','[]','雨色流香绕坐中。',56,'宋词/ci.song.4000.json','["雨色流香绕坐中。", "映阶疏竹一丛丛。", "不奈晚来萧瑟意，子猷风。", "潋滟满倾金凿落，淋漓从湿绣芙蓉。", "吸尽百川天上去，看长虹。"]'),
('song-ci-757','踏莎行','毛滂','宋','宋词','song-ci','踏莎行','[]','天质婵娟，妆光荡漾。',68,'宋词/ci.song.4000.json','["天质婵娟，妆光荡漾。", "御酥做出花模样。", "夭桃繁杏本妖妍，文鸳彩凤能偎傍。", "艾绿浓香，鹅黄新酿。", "缘云清切歌声上。", "夜寒不近绣芙蓉，醉中祗觉春相向。"]'),
('song-ci-758','踏莎行','毛滂','宋','宋词','song-ci','踏莎行','[]','映竹幽妍，临池娟靓。',68,'宋词/ci.song.4000.json','["映竹幽妍，临池娟靓。", "芳苞先暖香初娠。", "南枝微弄雪精神，东君早寄春音信。", "奔月仙标，乘烟远韵。", "玉台粉点和酥凝。", "从来清瘦可禁寒，为谁早把霞衣褪。"]'),
('song-ci-759','踏莎行','毛滂','宋','宋词','song-ci','踏莎行','[]','粟玉玲珑，雍酥浮动。',68,'宋词/ci.song.4000.json','["粟玉玲珑，雍酥浮动。", "芳跗染得胭脂重。", "风前兰麝作香寒，枝头烟雪和春冻。", "蜂翅初开，蜜房香弄。", "佳人寒睡愁和梦。", "鹅黄衫子茜罗裙，风流不与江梅共。"]'),
('song-ci-760','踏莎行','毛滂','宋','宋词','song-ci','踏莎行','[]','景泮冰檐，情回瑶草。',68,'宋词/ci.song.4000.json','["景泮冰檐，情回瑶草。", "副能守得春来到。", "管曾独自索春怜，而今觑著东风笑。", "粉凝酥寒，云房睡觉。", "胭脂也不添些小。", "天真要与此花争，是伊占得春多少。"]'),
('song-ci-761','踏莎行','毛滂','宋','宋词','song-ci','踏莎行','[]','拨雪寻春，烧灯续昼。',68,'宋词/ci.song.4000.json','["拨雪寻春，烧灯续昼。", "暗香院落梅开后。", "无端夜色欲遮春，天教月上官桥柳。", "花市无尘，朱门如绣。", "娇云瑞雾笼星斗。", "沈香火冷小妆残，半衾轻梦浓如酒。"]'),
('song-ci-762','踏莎行','毛滂','宋','宋词','song-ci','踏莎行','[]','阶影红迟，柳苞黄遍。',68,'宋词/ci.song.4000.json','["阶影红迟，柳苞黄遍。", "纤云弄日阴晴半。", "重帘不卷篆香横，小花初破春丛浅。", "凤绣犹重，鸭炉长暖。", "屏山翠入江南远。", "醉轻梦短枕闲敧，绿窗窈窕风光转。"]'),
('song-ci-763','踏莎行','毛滂','宋','宋词','song-ci','踏莎行','[]','芳气霏微，薄衣料峭。',68,'宋词/ci.song.4000.json','["芳气霏微，薄衣料峭。", "何人正倚桃花笑。", "流红不出武陵溪，这回空与春风到。", "尊俎全稀，风情终较。", "安仁老也谁知道。", "碧云无信失秦楼，旧时明月犹相照。"]'),
('song-ci-764','踏莎行','毛滂','宋','宋词','song-ci','踏莎行','[]','碧树阴圆，绿阶露满。',68,'宋词/ci.song.4000.json','["碧树阴圆，绿阶露满。", "金波潋滟堆瑶盏。", "行云会事不飞来，长空一片琉璃浅。", "玉燕钗寒，藕丝袖冷。", "只应未倚阑干遍。", "随人全不似婵娟，桂花影里年年见。"]'),
('song-ci-765','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','[]','西风吹冷沈香篆。',64,'宋词/ci.song.4000.json','["西风吹冷沈香篆。", "门掩小晴红叶院。", "卧看黄菊送重阳，露重烟寒花未遍。", "衰翁病怯琉璃簟。", "日日愁侵霜鬓短。", "一杯菊叶小云团，满眼萧萧松竹晚。"]'),
('song-ci-766','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','[]','泥银四壁盘蜗篆。',64,'宋词/ci.song.4000.json','["泥银四壁盘蜗篆。", "明月一庭秋满院。", "不知陶菊总开无，但见杜苔新雨遍。", "去年醉倒云为簟。", "未尽百壶惊日短。", "小云今夜伴牢愁，好在凤凰春未晚。"]'),
('song-ci-767','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','[]','三衢太守文章伯。',64,'宋词/ci.song.4000.json','["三衢太守文章伯。", "七月政成如戏剧。", "坐中咳唾落珠玑，笔下神明飞霹雳。", "才高莫恨溪山窄。", "且与燕公添秀发。", "风流前辈渐无多，好在魏公门下客。"]'),
('song-ci-768','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','[]','一年滴尽莲花漏。',64,'宋词/ci.song.4000.json','["一年滴尽莲花漏。", "碧井酴酥沈冻酒。", "晓寒料峭尚欺人，春态苗条先到柳。", "佳人重劝千长寿。", "柏叶椒花芬翠袖。", "醉乡深处少相知，祗与东君偏故旧。"]'),
('song-ci-769','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','[]','蕊珠宫里三千女。',64,'宋词/ci.song.4000.json','["蕊珠宫里三千女。", "滴粉为春尘不住。", "月华冷处欲迎人，七里香风生满路。", "一枝谁寄长安去。", "想得韶光能几许。", "醉翁满眼玉玲珑，直到烟空云尽处。"]'),
('song-ci-770','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','[]','小园半夜东风转。',64,'宋词/ci.song.4000.json','["小园半夜东风转。", "吹皱冰池云母面。", "晓披阊阖见朝阳，知向碧阶添几线。", "小烟弄柳晴先暖。", "残雪禁梅香尚浅。", "殷勤洗拂旧东君，多少韶华聊借看。"]'),
('song-ci-771','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','[]','长安回首空云雾。',64,'宋词/ci.song.4000.json','["长安回首空云雾。", "春梦觉来无觅处。", "冷烟寒雨又黄昏，数尽一堤杨柳树。", "楚山照眼青无数。", "淮口潮生催晓渡。", "西风吹面立苍茫，欲寄此情无雁去。"]'),
('song-ci-772','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','[]','一春花事今宵了。',64,'宋词/ci.song.4000.json','["一春花事今宵了。", "点检落红都已少。", "阿谁追路问东君，祗有青青河畔草。", "尊前不信韶华老。", "酒意妆光相借好。", "檐前暮雨亦多情，未做朝云容易晓。"]'),
('song-ci-773','南歌子','毛滂','宋','宋词','song-ci','南歌子','[]','暮霰寒依树，娇云冷傍人。',62,'宋词/ci.song.4000.json','["暮霰寒依树，娇云冷傍人。", "江南谁寄一枝春。", "何似珑璁十里、更无尘。", "雨萼胭脂淡，香须蝶子轻。", "碧山归路小桥横。", "谁见暗香今夜、月胧明。"]'),
('song-ci-774','南歌子','毛滂','宋','宋词','song-ci','南歌子','[]','庭下新生月，凭君把酒看。',62,'宋词/ci.song.4000.json','["庭下新生月，凭君把酒看。", "不须直待素团团。", "恰似那人眉样、秀弯环。", "冷射鸳鸯瓦，清欺翡翠帘。", "数枝烟竹小桥寒。", "渐见风吹疏影、过阑干。"]'),
('song-ci-775','南歌子','毛滂','宋','宋词','song-ci','南歌子','[]','绿暗藏城市，清香扑酒尊。',62,'宋词/ci.song.4000.json','["绿暗藏城市，清香扑酒尊。", "淡烟疏雨冷黄昏。", "零落酴醿花片、损春痕。", "润入笙箫腻，春馀笑语温。", "更深不锁醉乡门。", "先遣歌声留住、欲归云。"]'),
('song-ci-776','八节长欢','毛滂','宋','宋词','song-ci','八节长欢','[]','名满人间。',120,'宋词/ci.song.4000.json','["名满人间。", "记黄金殿，旧赐清闲。", "才高鹦鹉赋，风懔惠文冠。", "涛波何处试蛟鳄，到白头、犹守溪山。", "且做龚黄样度，留与人看。", "桃溪柳曲阴圆。", "离唱断、旌旗却卷春还。", "襦裤寄馀温，双石畔、唯闻吏胆长寒。", "诗翁去，谁细绕、屈曲阑干。", "从今后、南来幽梦，应随月度云端。"]'),
('song-ci-777','八节长欢','毛滂','宋','宋词','song-ci','八节长欢','[]','泽国秋深。',120,'宋词/ci.song.4000.json','["泽国秋深。", "绣楹天近，坐久魂清。", "溪山绕尊酒，云雾浥衣襟。", "馀霞孤雁送愁眼，寄寒闺、一点离心。", "杜老两峰秀处，短发疏巾。", "佳人为折寒英。", "罗袖湿、真珠露冷钿金。", "幽艳为谁妍，东篱下、却教醉倒渊明。", "君但饮，莫觑他、落日芜城。", "从教夜、龙山清月，端的便解留人。"]'),
('song-ci-778','蓦山溪','毛滂','宋','宋词','song-ci','蓦山溪','[]','雪空毡径，扑扑怜飞絮。',102,'宋词/ci.song.4000.json','["雪空毡径，扑扑怜飞絮。", "柔弱不胜春，任东风、吹来吹去。", "墙阴苑外，一片落谁家，叶依依，烟郁郁，依旧如张绪。", "那人拈得，吹向钗头住。", "不定却飞扬，满眼前、搅人情愫。", "蜂儿蝶子，教得越轻狂，隔斜阳，点芳草，断送青春暮。"]'),
('song-ci-779','蓦山溪','毛滂','宋','宋词','song-ci','蓦山溪','[]','东堂先晓，帘挂扶桑暖。',102,'宋词/ci.song.4000.json','["东堂先晓，帘挂扶桑暖。", "画舫寄江湖，倚小楼、心随望远。", "水边竹畔，石瘦藓花寒，秀阴遮，潜玉梦，鹤下渔矶晚。", "藏花小坞，蝶径深深见。", "彩笔赋阳春，看藻思、飘飘云半。", "烟拖山翠，和月冷西窗，玻璃盏，蒲萄酒，旋落酴醿片。"]'),
('song-ci-780','蓦山溪','毛滂','宋','宋词','song-ci','蓦山溪','[]','婵娟不老，依旧东风面。',102,'宋词/ci.song.4000.json','["婵娟不老，依旧东风面。", "华烛下珠軿，盛寒里、春光一片。", "不教暮景，也似每常来，水精宫，银色界，今夜分明见。", "碧街如水，人影花凌乱。", "谁在柳阴中，小妆寒、落梅数点。", "诗翁独倚，十二玉阑干，露濛濛，云冉冉，千嶂琉璃浅。"]'),
('song-ci-781','蓦山溪','毛滂','宋','宋词','song-ci','蓦山溪','[]','梅花初谢，雪后寒微峭。',102,'宋词/ci.song.4000.json','["梅花初谢，雪后寒微峭。", "谁送一城春，绮罗香、风光窈窕。", "插花走马，天近宝鞭寒，金波上，玉轮边，不是红尘道。", "玻璃山畔，夜色无由到。", "深下水晶帘，拥严妆、铅华相照。", "珠楼缈缈，人月两婵娟，尊前月，月中人，相见年年好。"]'),
('song-ci-782','临江仙','毛滂','宋','宋词','song-ci','临江仙','[]','古寺长廊清夜美，风松烟桧萧然。',70,'宋词/ci.song.4000.json','["古寺长廊清夜美，风松烟桧萧然。", "石阑干外上疏帘。", "过云闲窈窕，斜月静婵娟。", "独自徘徊无个事，瑶琴试奏流泉。", "曲终谁见枕琴眠。", "香残虬尾细，灯暗玉虫偏。"]'),
('song-ci-783','临江仙','毛滂','宋','宋词','song-ci','临江仙','[]','莫恨那回容易别，不妨久远情肠。',70,'宋词/ci.song.4000.json','["莫恨那回容易别，不妨久远情肠。", "为人留下旧风光。", "花枝长好在，馥馥十年香。", "便是旧时帘外月，却来小槛低窗。", "朦胧影里淡梳妆。", "相看如梦寐，回首乍思量。"]'),
('song-ci-784','剔银灯','毛滂','宋','宋词','song-ci','剔银灯','[]','帘下风光自足。',90,'宋词/ci.song.4000.json','["帘下风光自足。", "春到席间屏曲。", "瑶瓮酥融，羽觞蚁闹，花映酃湖寒绿。", "汨罗愁独。", "又何似、红围翠簇。", "聚散悲欢箭速。", "不易一杯相属。", "频剔银灯，别听牙板，尚有龙膏堪续。", "罗熏绣馥。", "锦瑟畔、低迷醉玉。"]'),
('song-ci-785','水调歌头','毛滂','宋','宋词','song-ci','水调歌头','[]','金马空故事，方朔漫多端。',114,'宋词/ci.song.4000.json','["金马空故事，方朔漫多端。", "三千牍在，玉殿何日赐清闲。", "难恋长安锺漏，谁借青云咳唾，拂袖且东还。", "笑杀长缨使，复转出秦关。", "吾道在，虽不遇，面何惭。", "雒阳年少，高轮难与绛侯谈。", "富贵暂饶先手，晞尽草头秋露，掩鼻出东山。", "且饱鲸鱼脍，风月过江南。"]'),
('song-ci-786','水调歌头','毛滂','宋','宋词','song-ci','水调歌头','[]','谢安涵雅量，叔夜赋刚肠。',114,'宋词/ci.song.4000.json','["谢安涵雅量，叔夜赋刚肠。", "清宵假寐，应笑长孺卧淮阳。", "尽彻东平屏障，不废南楼谈咏，宴寝自凝香。", "庭下一杯土，须避赤帷裳。", "双石健，含古色，照新堂。", "百年乔木阴下，僵立两蛟苍。", "目送千山爽气，帘卷一城风月，杖屦合彷徉。", "他日峨眉秀，相望隔明光。"]'),
('song-ci-787','浣溪沙','毛滂','宋','宋词','song-ci','浣溪沙','[]','竹送秋声入小窗。',48,'宋词/ci.song.4000.json','["竹送秋声入小窗。", "香迷夜色暗牙床。", "小屏风掩烛花长。", "雁过故人无信息，酒醒残梦寄凄凉。", "画桥露月冷鸳鸯。"]'),
('song-ci-788','武陵春','毛滂','宋','宋词','song-ci','武陵春','[]','维岳分公英特气，万丈拂长虹。',56,'宋词/ci.song.4000.json','["维岳分公英特气，万丈拂长虹。", "丙魏萧曹总下风。", "千载友夔龙。", "宝熏袅翠昏帘绣，嘉颂佩绅同。", "不用黄精扫鬓中。", "元是黑头翁。"]'),
('song-ci-789','武陵春','毛滂','宋','宋词','song-ci','武陵春','[]','迎得春来闻好语，贺燕立帘钩。',56,'宋词/ci.song.4000.json','["迎得春来闻好语，贺燕立帘钩。", "转蕙风光柳弄柔。", "喜气与春游。", "万钱珍鼎期公饭，天自寿留侯。", "文物升平速置邮。", "江左属风流。"]'),
('song-ci-790','武陵春','毛滂','宋','宋词','song-ci','武陵春','[]','银浦流云初度月，空碧挂团团。',56,'宋词/ci.song.4000.json','["银浦流云初度月，空碧挂团团。", "照夜珠胎贝阙寒。", "光彩满长安。", "春风为拂新沙路，珂马款天关。", "篆印金窠红屈盘。", "嵬ㄝ押千官。"]'),
('song-ci-791','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','[]','今朝何以为公寿。',64,'宋词/ci.song.4000.json','["今朝何以为公寿。", "极贵长年公素有。", "庭阶不乏长芝兰，少翁又是廷臣右。", "三能粲粲依魁秀。", "八柱魏魏蟠地厚。", "皇家卜册万斯年，年光长转洪钧手。"]'),
('song-ci-792','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','["\u6cf0\u5c71"]','我公两器兼文武。',64,'宋词/ci.song.4000.json','["我公两器兼文武。", "谈笑岩廊无治古。", "红颜绿发已官高，赤舄绣裳今仲父。", "我欲形容无妙语。", "颂穆清风须吉甫。", "望公聊比泰山云，岁岁年年天下雨。"]'),
('song-ci-793','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','[]','压玉为浆麟作朒。',64,'宋词/ci.song.4000.json','["压玉为浆麟作朒。", "珠树琼葩长不谢。", "翠帘绣暖燕归来，宝鸭花香蜂上下。", "沙堤佩马催公驾。", "月白风清天不夜。", "重来赫赫照岩廊，不动堂堂凝太华。"]'),
('song-ci-794','秦楼月・忆秦娥','毛滂','宋','宋词','song-ci','秦楼月・忆秦娥','[]','蔷薇折。',56,'宋词/ci.song.4000.json','["蔷薇折。", "一怀秀影花和月。", "花和月。", "著人浓似，粉香酥色。", "绿阴垂幕帘波叠。", "微风过竹凉吹发。", "凉吹发。", "无人分付，这些时节。"]'),
('song-ci-795','遍地花','毛滂','宋','宋词','song-ci','遍地花','[]','白玉阑边自凝伫。',71,'宋词/ci.song.4000.json','["白玉阑边自凝伫。", "满枝头、彩云雕雾。", "甚芳菲、绣得成团，砌合出、韶华好处。", "暖风前、一笑盈盈，吐檀心、向谁分付。", "莫与他、西子精神，不枉了、东君雨露。"]'),
('song-ci-796','夜游宫','毛滂','宋','宋词','song-ci','夜游宫','[]','长记劳君送远。',71,'宋词/ci.song.4000.json','["长记劳君送远。", "柳烟重、桃花波暖。", "花外溪城望不见。", "古槐边，故人稀，秋鬓晚。", "我有凌霄伴。", "在何处、山寒云乱。", "何不随君弄清浅。", "见伊时，话阳春，山数点。"]'),
('song-ci-797','诉衷情','毛滂','宋','宋词','song-ci','诉衷情','[]','花阴柳影映帘栊。',54,'宋词/ci.song.4000.json','["花阴柳影映帘栊。", "罗幕绣重重。", "行云自随语燕，回雪趁惊鸿。", "银字歇，玉杯空。", "蕙烟中。", "桃花髻暖，杏叶眉弯，一片春风。"]'),
('song-ci-798','诉衷情','毛滂','宋','宋词','song-ci','诉衷情','[]','短疏萦缘象床低。',54,'宋词/ci.song.4000.json','["短疏萦缘象床低。", "玉鸭度香迟。", "微云淡著河汉，凉过碧梧枝。", "秋韵起，月阴移。", "下帘时。", "人间天上，一样风光，我与君知。"]'),
('song-ci-799','醉花阴','毛滂','宋','宋词','song-ci','醉花阴','[]','檀板一声莺起速。',62,'宋词/ci.song.4000.json','["檀板一声莺起速。", "山影穿疏木。", "人在翠阴中，欲觅残春，春在屏风曲。", "劝君对客杯须覆。", "灯照瀛洲绿。", "西去玉堂深，魄冷魂清，独引金莲烛。"]'),
('song-ci-800','醉花阴','毛滂','宋','宋词','song-ci','醉花阴','[]','金叶犹温香未歇。',62,'宋词/ci.song.4000.json','["金叶犹温香未歇。", "尘定歌初彻。", "暖透薄罗衣，一霎清风，人映团团月。", "持杯试听留春阕。", "此个情肠别。", "分付与莺莺，劝取东君，停待芳菲节。"]'),
('song-ci-801','减字木兰花','毛滂','宋','宋词','song-ci','减字木兰花','[]','暖风吹雪。',52,'宋词/ci.song.4000.json','["暖风吹雪。", "洗尽碧阶今夜月。", "试觅云英。", "更就蓝桥借月明。", "从教不借。", "自有使君家不夜。", "谁道由天。", "光景随人特地妍。"]'),
('song-ci-802','减字木兰花','毛滂','宋','宋词','song-ci','减字木兰花','[]','曾教风月。',52,'宋词/ci.song.4000.json','["曾教风月。", "催促花边烟棹发。", "不管花开。", "月白风清始肯来。", "既来且住。", "风月闲寻秋好处。", "收取凄清。", "暖日阑干助梦吟。"]'),
('song-ci-803','减字木兰花','毛滂','宋','宋词','song-ci','减字木兰花','[]','小桥秀绝。',52,'宋词/ci.song.4000.json','["小桥秀绝。", "露湿芙蕖花上月。", "月下人人。", "花样精神月样清。", "谁言见惯。", "到了司空情不慢。", "丞相瞋无。", "若不瞋时醉倩扶。"]'),
('song-ci-804','上林春令・一落索','毛滂','宋','宋词','song-ci','上林春令・一落索','[]','蝴蝶初翻帘绣。',65,'宋词/ci.song.4000.json','["蝴蝶初翻帘绣。", "万玉女、齐回舞袖。", "落花飞絮濛濛，长忆著、灞桥别后。", "浓香斗帐自永漏。", "任满地、月深云厚。", "夜寒不近流苏，祗怜他、后庭梅瘦。"]'),
('song-ci-805','人娇','毛滂','宋','宋词','song-ci','人娇','[]','雪做屏风，花为行帐。',80,'宋词/ci.song.4000.json','["雪做屏风，花为行帐。", "屏帐里、见春模样。", "小晴未了，轻阴一饷。", "酒到处、恰如把春拈上。", "官柳黄轻，河堤绿涨。", "花多处、少停兰桨。", "雪边花际，平芜叠幛。", "这一段、凄凉为谁怅望。"]'),
('song-ci-806','人娇','毛滂','宋','宋词','song-ci','人娇','[]','短棹犹停，寸心先往。',80,'宋词/ci.song.4000.json','["短棹犹停，寸心先往。", "说归期、唤做的当。", "夕阳下地，重城远样。", "风露冷、高楼误伊等望。", "今夜孤村，月明怎向。", "依还是、梦回绣幌。", "远山想像。", "秋波荡漾。", "明夜里、与伊画著眉上。"]'),
('song-ci-807','惜分飞','毛滂','宋','宋词','song-ci','惜分飞','[]','山转沙回江声小。',58,'宋词/ci.song.4000.json','["山转沙回江声小。", "望尽冷烟衰草。", "梦断瑶台晓。", "楚云何处英英好。", "古寺黄昏人悄悄。", "帘卷寒堂月到。", "不会思量了。", "素光看尽桐阴少。"]'),
('song-ci-808','惜分飞','毛滂','宋','宋词','song-ci','惜分飞','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','泪湿阑干花著露。',60,'宋词/ci.song.4000.json','["泪湿阑干花著露。", "愁到眉峰碧聚。", "此恨平分取。", "更无言语。", "空相觑。", "短雨残云无意绪。", "寂寞朝朝暮暮。", "今夜山深处。", "断魂分付。", "潮回去。"]'),
('song-ci-809','惜分飞','毛滂','宋','宋词','song-ci','惜分飞','[]','花影低徊帘幕卷。',58,'宋词/ci.song.4000.json','["花影低徊帘幕卷。", "惯了双来燕燕。", "惊散雕阑晚。", "雨昏烟重垂杨院。", "云断月斜红烛短。", "望断真个望断。", "情寄梅花点。", "趁风飞过楼南畔。"]'),
('song-ci-810','惜分飞','毛滂','宋','宋词','song-ci','惜分飞','[]','恰则心头托托地。',59,'宋词/ci.song.4000.json','["恰则心头托托地。", "放下了日多萦系。", "别恨还容易。", "袖痕犹有年时泪。", "满满频斟乞求醉。", "且要时闲忘记。", "明日刘郎起。", "马蹄去便三千里。"]'),
('song-ci-811','蝶恋花','毛滂','宋','宋词','song-ci','蝶恋花','[]','闻说君家传窈窕。',70,'宋词/ci.song.4000.json','["闻说君家传窈窕。", "秀色天真，更夺丹青妙。", "细意端相都总好。", "春愁春媚生颦笑。", "琼玉胸前金凤小。", "那得殷勤，细托琵琶道。", "十二峰云遮醉倒。", "华灯翠帐花相照。"]'),
('song-ci-812','蝶恋花','毛滂','宋','宋词','song-ci','蝶恋花','[]','江接寒溪家已近。',70,'宋词/ci.song.4000.json','["江接寒溪家已近。", "想见秋来，松菊荒三径。", "目送吴山秋色尽。", "星星却入双蓬鬓。", "凫短鹤长真个定。", "勋业来迟，不用频看镜。", "懒出问人人不问。", "绿尊倒尽横书枕。"]'),
('song-ci-813','蝶恋花','毛滂','宋','宋词','song-ci','蝶恋花','[]','相见江南情不少。',70,'宋词/ci.song.4000.json','["相见江南情不少。", "尔许多时，怪得无消耗。", "淡日暖云句引到。", "阑干寂寞怜春小。", "宫面可忺匀画了。", "粉瘦酥寒，一段天真好。", "唤起玉儿娇睡觉。", "半山残月南枝晓。"]'),
('song-ci-814','蝶恋花','毛滂','宋','宋词','song-ci','蝶恋花','[]','红杏梢头寒食雨。',70,'宋词/ci.song.4000.json','["红杏梢头寒食雨。", "燕子泥新，不住飞来去。", "行傍柳阴闻好语。", "莺儿穿过黄金缕。", "桑落酒寒杯懒举。", "总被多情，做得无情绪。", "春过二分能几许。", "银台新火重帘暮。"]'),
('song-ci-815','蝶恋花','毛滂','宋','宋词','song-ci','蝶恋花','[]','三叠阑干铺碧甃。',70,'宋词/ci.song.4000.json','["三叠阑干铺碧甃。", "小雨新晴，才过清明后。", "初见花王披衮绣。", "娇云瑞日明春昼。", "彩女朝真天质秀。", "宝髻微偏，风卷霞衣皱。", "莫道东君情最厚。", "韶光半在东堂手。"]'),
('song-ci-816','蝶恋花','毛滂','宋','宋词','song-ci','蝶恋花','[]','红影斑斑吹锦片。',70,'宋词/ci.song.4000.json','["红影斑斑吹锦片。", "露叶烟梢，寒月娟娟满。", "更起绕庭行百遍。", "无人祗有栖莺见。", "觅个薄情心对换。", "愁绪偏长，不信春宵短。", "正是碧云音信断。", "半衾犹赖香熏暖。"]'),
('song-ci-817','蝶恋花','毛滂','宋','宋词','song-ci','蝶恋花','[]','城上春云低阁雨。',70,'宋词/ci.song.4000.json','["城上春云低阁雨。", "渐觉春随，一片花飞去。", "素颈圆吭莺燕语。", "不妨缓缓歌金缕。", "堕纪颓纲公已举。", "但见清风，萧瑟随谈绪。", "借寇假饶天不许。", "未须忙遣韶华暮。"]'),
('song-ci-818','蝶恋花','毛滂','宋','宋词','song-ci','蝶恋花','[]','花里传觞飞羽过。',70,'宋词/ci.song.4000.json','["花里传觞飞羽过。", "渐觉金槽，月缺圆龙破。", "素手转罗酥作颗。", "鹅溪雪绢云腴堕。", "七盏能醒千日卧。", "扶起瑶山，嫌怕香尘涴。", "醉色轻松留不可。", "清风停待些时过。"]'),
('song-ci-819','蝶恋花','毛滂','宋','宋词','song-ci','蝶恋花','[]','不雨不晴秋气味。',70,'宋词/ci.song.4000.json','["不雨不晴秋气味。", "酒病秋怀，不做醒松地。", "初换夹衣围翠被。", "蔷薇水润衙香腻。", "旋折秋英餐露蕊。", "金缕虬团，更试康王水。", "幽梦不来寻小睡。", "无言划尽屏山翠。"]'),
('song-ci-820','更漏子','毛滂','宋','宋词','song-ci','更漏子','[]','玉狻猊，金叶暖。',58,'宋词/ci.song.4000.json','["玉狻猊，金叶暖。", "馥馥香云不断。", "长下著，绣帘重。", "怕随花信风。", "傍蔷薇，摇露点。", "衣润得香长远。", "双枕凤，一衾鸾。", "柳烟花雾间。"]'),
('song-ci-821','更漏子','毛滂','宋','宋词','song-ci','更漏子','[]','绿窗寒，清漏短。',58,'宋词/ci.song.4000.json','["绿窗寒，清漏短。", "帐底沈香火暖。", "残烛暗，小屏弯。", "云峰遮梦还。", "那些愁，推不去。", "分付一檐寒雨。", "檐外竹，试秋声。", "空庭鹤唤人。"]'),
('song-ci-822','更漏子','毛滂','宋','宋词','song-ci','更漏子','[]','柳藏烟，云漏日。',58,'宋词/ci.song.4000.json','["柳藏烟，云漏日。", "寒满雕盘玉食。", "风卷旆，水摇天。", "鱼龙挟彩船。", "水边人，波面乐。", "太守与民同乐。", "春好处，总随轩。", "花中谁状元。"]'),
('song-ci-823','西江月','毛滂','宋','宋词','song-ci','西江月','[]','花下春藏五马，松间风落双凫。',58,'宋词/ci.song.4000.json','["花下春藏五马，松间风落双凫。", "兵厨玉帐卷酃湖。", "人醉碧云欲暮。", "归去聊登文石，翱翔便是天衢。", "雅歌谁解继投壶。", "桃李无言满路。"]'),
('song-ci-824','西江月','毛滂','宋','宋词','song-ci','西江月','[]','烟雨半藏杨柳，风光初到桃花。',58,'宋词/ci.song.4000.json','["烟雨半藏杨柳，风光初到桃花。", "玉人细细酌流霞。", "醉里将春留下。", "柳畔鸳鸯作伴，花边蝴蝶为家。", "醉翁醉里也随他。", "月在柳桥花榭。"]'),
('song-ci-825','西江月','毛滂','宋','宋词','song-ci','西江月','[]','雨后夹衣初冷，霜前细菊浑斑。',58,'宋词/ci.song.4000.json','["雨后夹衣初冷，霜前细菊浑斑。", "觚棱清月绣团环。", "万里长安秋晚。", "槽下内家玉滴，盘中江国金丸。", "春容著面作微殷。", "烛影红摇醉眼。"]'),
('song-ci-826','西江月','毛滂','宋','宋词','song-ci','西江月','[]','席上芙蓉待暖，花间騕袅还嘶。',58,'宋词/ci.song.4000.json','["席上芙蓉待暖，花间騕袅还嘶。", "劝君不醉且无归。", "归去因谁惜醉。", "汤点瓶心未老，乳堆盏面初肥。", "留连能得几多时。", "两腋清风唤起。"]'),
('song-ci-827','青玉案','毛滂','宋','宋词','song-ci','青玉案','[]','芙蕖花上濛濛雨。',80,'宋词/ci.song.4000.json','["芙蕖花上濛濛雨。", "又冷落、池塘暮。", "何处风来摇碧户。", "卷帘凝望，淡烟疏柳，翡翠穿花去。", "玉京人去无由驻。", "恁独坐、凭阑处。", "试问绿窗秋到否。", "可人今夜，新凉一枕，无计相分付。"]'),
('song-ci-828','青玉案','毛滂','宋','宋词','song-ci','青玉案','[]','玉婴初有排云分。',80,'宋词/ci.song.4000.json','["玉婴初有排云分。", "向晚色、娟娟静。", "秋入风枝清不尽。", "月和粉露，徘徊孤映，独夜扶疏影。", "子猷风调全相称。", "是彼此、无凡韵。", "玉勒前头花柳近。", "水边石上，冷依烟雨，时有幽人问。"]'),
('song-ci-829','青玉案','毛滂','宋','宋词','song-ci','青玉案','[]','玉人为我殷勤醉。',80,'宋词/ci.song.4000.json','["玉人为我殷勤醉。", "向醉里、添姿媚。", "偏著冠儿钗欲坠。", "桃花气暖，露浓烟重，不自禁春意。", "绿榆阴下东行水。", "渐渐近、凄凉地。", "明月侵床愁不睡。", "眉儿吃皱，为谁无语，阁住阳关泪。"]'),
('song-ci-830','青玉案','毛滂','宋','宋词','song-ci','青玉案','[]','今宵月好来同看。',81,'宋词/ci.song.4000.json','["今宵月好来同看。", "月未落、人还散。", "把手留连帘儿畔。", "含羞和恨转娇盼。", "恁花映春风面。", "相思不用宽金钏。", "也不用、多情似玉燕。", "问取婵娟学长远。", "不必清光夜夜见。", "但莫负、团圆愿。"]'),
('song-ci-831','河满子','毛滂','宋','宋词','song-ci','河满子','[]','急雨初收珠点。',86,'宋词/ci.song.4000.json','["急雨初收珠点。", "云峰巉绝天半。", "辘轳金井卷甘冽，帘外翠阴遮遍。", "波翻水精重帘，秋在琉璃双簟。", "漏永流花缓缓。", "未放崦嵫晼晚。", "红荷绿芰暮天好，小宴水亭风馆。", "云乱香喷宝鸭，月冷钗横玉燕。"]'),
('song-ci-832','谒金门','毛滂','宋','宋词','song-ci','谒金门','[]','灯雾里。',53,'宋词/ci.song.4000.json','["灯雾里。", "老去昔游不记。", "月似旧时人不似。", "小楼何处是。", "归卧晚香翠被。", "玉酒著人小醉。", "欲睡先来都不睡。", "此情那恁地。"]'),
('song-ci-833','七娘子','毛滂','宋','宋词','song-ci','七娘子','[]','山屏雾帐玲珑碧。',72,'宋词/ci.song.4000.json','["山屏雾帐玲珑碧。", "更绮窗、临水新凉入。", "雨短烟长，柳桥萧瑟。", "这番一日凉一日。", "离多绿鬓多时白。", "这离情、不似而今惜。", "云外长安，斜晖脉脉。", "西风吹梦来无迹。"]'),
('song-ci-834','七娘子','毛滂','宋','宋词','song-ci','七娘子','[]','月光波影寒相向。',72,'宋词/ci.song.4000.json','["月光波影寒相向。", "借团团、与做长壕样。", "此老南楼，风流可想。", "殷勤冰彩随人上。", "欲同次道倾家酿。", "有兵厨、玉盎金波涨。", "云外归鸿，烟中飞桨。", "五湖秋兴心先往。"]'),
('song-ci-835','雨中花・夜行船','毛滂','宋','宋词','song-ci','雨中花・夜行船','[]','寒浸东倾不定。',57,'宋词/ci.song.4000.json','["寒浸东倾不定。", "更奈橹声催紧。", "堤树胧明孤月上，暗淡移船影。", "旧事十年愁未醒。", "渐老可禁离恨。", "今夜谁知风露里，目断云空尽。"]'),
('song-ci-836','雨中花・夜行船','毛滂','宋','宋词','song-ci','雨中花・夜行船','[]','池上山寒欲雾。',59,'宋词/ci.song.4000.json','["池上山寒欲雾。", "竹暗小窗低户。", "数点秋声侵短梦，檐下芭蕉雨。", "白酒浮蛆鸡啄黍。", "问陶令、几时归去。", "溪月岭云红蓼岸，总是思量处。"]'),
('song-ci-837','夜行船','毛滂','宋','宋词','song-ci','夜行船','[]','寒满一衾谁共。',67,'宋词/ci.song.4000.json','["寒满一衾谁共。", "夜沈沈、醉魂朦鬆。", "雨呼烟唤付凄凉，又不成、那些好梦。", "明日烟江□暝曚。", "扁舟系、一行螮蝀。", "季鹰生事水弥漫，过鲈船、再三目送。"]'),
('song-ci-838','夜行船','毛滂','宋','宋词','song-ci','夜行船','[]','弄水馀英溪畔。',67,'宋词/ci.song.4000.json','["弄水馀英溪畔。", "绮罗香、日迟风慢。", "桃花春浸一篙深，画桥东、柳低烟远。", "涨绿流红空满眼。", "倚兰桡、旧愁无限。", "莫把鸳鸯惊飞去，要歌时、少低檀板。"]'),
('song-ci-839','鹊桥仙','毛滂','宋','宋词','song-ci','鹊桥仙','[]','红摧绿锉，莺愁蝶怨，满院落花风紧。',68,'宋词/ci.song.4000.json','["红摧绿锉，莺愁蝶怨，满院落花风紧。", "醉乡好梦恰瞢腾，又冷落、一成吹醒。", "柔红不耐，暗香犹好，觑著翻成不忍。", "春心减尽眼长闲，更肯被、游丝牵引。"]'),
('song-ci-840','鹊桥仙','毛滂','宋','宋词','song-ci','鹊桥仙','[]','水精帘外，沈香阑畔，新下红油画幕。',68,'宋词/ci.song.4000.json','["水精帘外，沈香阑畔，新下红油画幕。", "百花何处避芳尘，便独自、将春占却。", "月华淡淡，夜寒森森，犹把红灯照著。", "醉时从醉不归家，贤守定、不教冷落。"]'),
('song-ci-841','烛影摇红','毛滂','宋','宋词','song-ci','烛影摇红','[]','一亩清阴，半天潇洒松窗午。',58,'宋词/ci.song.4000.json','["一亩清阴，半天潇洒松窗午。", "床头秋色小屏山，碧帐垂烟缕。", "枕畔风摇绿户。", "唤人醒、不教梦去。", "可怜恰到，瘦石寒泉，冷云幽处。"]'),
('song-ci-842','烛影摇红','毛滂','宋','宋词','song-ci','烛影摇红','["\u897f\u6e56"]','老景萧条，送君归去添凄断。',58,'宋词/ci.song.4000.json','["老景萧条，送君归去添凄断。", "赠君明月满前溪，直到西湖畔。", "门掩绿苔应遍。", "为黄花、频开醉眼。", "橘奴无恙，蝶子相迎，寒窗日短。"]'),
('song-ci-843','烛影摇红','毛滂','宋','宋词','song-ci','烛影摇红','[]','鬓绿飘萧，漫郎已是青云晚。',58,'宋词/ci.song.4000.json','["鬓绿飘萧，漫郎已是青云晚。", "古槐阴外小阑干，不负看山眼。", "此意悠悠无限。", "有云山、知人醉懒。", "他年寻我，水边月底，一蓑烟短。"]'),
('song-ci-844','忆秦娥','毛滂','宋','宋词','song-ci','忆秦娥','[]','醉醉。',45,'宋词/ci.song.4000.json','["醉醉。", "醉击珊瑚碎。", "花花。", "先借春光与酒家。", "夜寒我醉谁扶我。", "应抱瑶琴卧。", "清清。", "揽月吟风不用人。"]'),
('song-ci-845','忆秦娥','毛滂','宋','宋词','song-ci','忆秦娥','[]','夜夜。',45,'宋词/ci.song.4000.json','["夜夜。", "夜了花朝也。", "连忙。", "指点银瓶索酒尝。", "明朝花落知多少。", "莫把残红扫。", "愁人。", "一片花飞减却春。"]'),
('song-ci-846','武陵春','毛滂','宋','宋词','song-ci','武陵春','[]','城上落梅风料峭，寒馥逼清尊。',56,'宋词/ci.song.4000.json','["城上落梅风料峭，寒馥逼清尊。", "爽兴天教属使君。", "雪意压歌云。", "插帽殷罗金缕细，燕燕早随人。", "留取笙歌直到明。", "莲漏已催春。"]'),
('song-ci-847','武陵春','毛滂','宋','宋词','song-ci','武陵春','[]','风过冰檐环佩响，宿雾在华茵。',56,'宋词/ci.song.4000.json','["风过冰檐环佩响，宿雾在华茵。", "剩落瑶花衬月明。", "嫌怕有纤尘。", "凤口衔灯金炫转，人醉觉寒轻。", "但得清光解照人。", "不负五更春。"]'),
('song-ci-848','武陵春','毛滂','宋','宋词','song-ci','武陵春','[]','春在前村梅雪里，一夜到千门。',56,'宋词/ci.song.4000.json','["春在前村梅雪里，一夜到千门。", "玉佩琼琚下冷云。", "银界见东君。", "桃花髻暖双飞燕，金字巧宜春。", "寂寞溪桥柳弄晴。", "老也探花人。"]'),
('song-ci-849','点绛唇','毛滂','宋','宋词','song-ci','点绛唇','[]','高柳横斜，冷光凌乱摇疏翠。',50,'宋词/ci.song.4000.json','["高柳横斜，冷光凌乱摇疏翠。", "露荷珠缀。", "但见鸳鸯睡。", "□□□□，□□□□□。", "□□□。", "□□□□。", "□□□□□。"]'),
('song-ci-850','点绛唇','毛滂','宋','宋词','song-ci','点绛唇','[]','柏叶春醅，为君亲酌玻璃盏。',50,'宋词/ci.song.4000.json','["柏叶春醅，为君亲酌玻璃盏。", "玉箫牙管。", "人意如春暖。", "鬓绿长留，不使韶华晚。", "春无限。", "碧桃花畔。", "笑看蓬莱浅。"]'),
('song-ci-851','点绛唇','毛滂','宋','宋词','song-ci','点绛唇','[]','手抚归鸿，坐临烟雨帘旌润。',50,'宋词/ci.song.4000.json','["手抚归鸿，坐临烟雨帘旌润。", "气清天近。", "云日温阑楯。", "压玉浮金，一醉留青鬓。", "风光胜。", "淡妆人靓。", "眉黛生秋晕。"]'),
('song-ci-852','点绛唇','毛滂','宋','宋词','song-ci','点绛唇','[]','何处君家，蟠桃花下瑶池畔。',50,'宋词/ci.song.4000.json','["何处君家，蟠桃花下瑶池畔。", "日迟烟暖。", "占得春长远。", "几见花开，一任年光换。", "今年见。", "明年重见。", "春色如人面。"]'),
('song-ci-853','点绛唇','毛滂','宋','宋词','song-ci','点绛唇','[]','秀岭寒青，冷泉凌乱催秋意。',50,'宋词/ci.song.4000.json','["秀岭寒青，冷泉凌乱催秋意。", "佩环声里。", "无限真珠碎。", "叹我平生，识尽闲滋味。", "来闲地。", "为君一醉。", "万事浮云外。"]'),
('song-ci-854','点绛唇','毛滂','宋','宋词','song-ci','点绛唇','[]','小院重帘，那回来处花相向。',50,'宋词/ci.song.4000.json','["小院重帘，那回来处花相向。", "迟迟一饷。", "记得春模样。", "昨夜月明，应照芙蓉帐。", "空凝望。", "蜂劳蝶攘。", "谁在花枝上。"]'),
('song-ci-855','点绛唇','毛滂','宋','宋词','song-ci','点绛唇','[]','绣岭横秋，玉螭吹暑迎凉气。',50,'宋词/ci.song.4000.json','["绣岭横秋，玉螭吹暑迎凉气。", "碧崖流水。", "流入春葱指。", "半倚朱弦，微亸连环珥。", "通深意。", "月明风细。", "分付知音耳。"]'),
('song-ci-856','如梦令','毛滂','宋','宋词','song-ci','如梦令','[]','深苑重调弦管。',40,'宋词/ci.song.4000.json','["深苑重调弦管。", "不觉银台烛短。", "相对有金波，天畔杯中都满。", "人远。", "人远。", "醉倚阑干玉冷。"]'),
('song-ci-857','玉楼春','毛滂','宋','宋词','song-ci','玉楼春','[]','当日岭头相见处。',64,'宋词/ci.song.4000.json','["当日岭头相见处。", "玉骨冰肌元淡伫。", "近来因甚要浓妆，不管满城桃杏妒。", "酒晕脸霞春暗度。", "认是东皇偏管顾。", "生罗衣褪为谁羞，香冷熏炉都不觑。"]'),
('song-ci-858','生查子','毛滂','宋','宋词','song-ci','生查子','[]','鲈蟹正肥时，烟雨新凉日。',48,'宋词/ci.song.4000.json','["鲈蟹正肥时，烟雨新凉日。", "露蕊郁金黄，云液蒲萄碧。", "此日古为佳，此醉君宁惜。", "高挂水精帘，尽放秋光入。"]'),
('song-ci-859','生查子','毛滂','宋','宋词','song-ci','生查子','[]','日照小窗纱，风动重帘绣。',48,'宋词/ci.song.4000.json','["日照小窗纱，风动重帘绣。", "宝炷暮云迷，曲沼晴漪皱。", "烟暖柳醒松，雪尽梅清瘦。", "恰是可怜时，好似花秾后。"]'),
('song-ci-860','生查子','毛滂','宋','宋词','song-ci','生查子','[]','钗上燕犹寒，胜里红偏小。',48,'宋词/ci.song.4000.json','["钗上燕犹寒，胜里红偏小。", "恰有尔多春，不许群花笑。", "酒面粉酥融，香袖金泥罩。", "芳意已潜通，残雪犹相照。"]'),
('song-ci-861','生查子','毛滂','宋','宋词','song-ci','生查子','[]','春晚出山城，落日行江岸。',48,'宋词/ci.song.4000.json','["春晚出山城，落日行江岸。", "人不共潮来，香亦临风散。", "花谢小妆残，莺困清歌断。", "行雨梦魂消，飞絮心情乱。"]'),
('song-ci-862','生查子','毛滂','宋','宋词','song-ci','生查子','[]','花地锦斑残，月箔波凌乱。',48,'宋词/ci.song.4000.json','["花地锦斑残，月箔波凌乱。", "斗鸭玉阑旁，扑兽金炉畔。", "小醉奈春何，轻梦催云散。", "却步蕙兰中，应被鸳鸯见。"]'),
('song-ci-863','浪淘沙','毛滂','宋','宋词','song-ci','浪淘沙','[]','深院绣帘垂。',64,'宋词/ci.song.4000.json','["深院绣帘垂。", "前日春归。", "画桥杨柳弄烟霏。", "池面东风先解冻，龟上涟漪。", "酒潋玉东西。", "香暖狻猊。", "远山郁秀入双眉。", "待看碧桃花烂漫，春日迟迟。"]'),
('song-ci-864','菩萨蛮','毛滂','宋','宋词','song-ci','菩萨蛮','[]','玉卮细酌流霞湿。',52,'宋词/ci.song.4000.json','["玉卮细酌流霞湿。", "金钗翠袖勤留客。", "行色小梅残。", "官桥杨柳寒。", "赐环宣室夜。", "看落金莲灺。", "人记海听康。", "流风秀水旁。"]'),
('song-ci-865','菩萨蛮','毛滂','宋','宋词','song-ci','菩萨蛮','[]','端端正正人如月。',52,'宋词/ci.song.4000.json','["端端正正人如月。", "孜孜媚媚花如颊。", "花月不如人。", "眉眉眼眼春。", "沈香添小炷。", "共挹熏炉语。", "香解著人衣。", "君心蝴蝶飞。"]'),
('song-ci-866','菩萨蛮','毛滂','宋','宋词','song-ci','菩萨蛮','[]','含章檐下眉如月。',52,'宋词/ci.song.4000.json','["含章檐下眉如月。", "融酥和粉描疏雪。", "桃杏莫争春。", "凌风台畔人。", "如今千万树。", "零乱孤村雨。", "和雨滴瑶觞。", "归来肌骨香。"]'),
('song-ci-867','菩萨蛮','毛滂','宋','宋词','song-ci','菩萨蛮','[]','淡烟疏雨东篱晓。',52,'宋词/ci.song.4000.json','["淡烟疏雨东篱晓。", "菊团凄露真珠小。", "青蕊抱寒枝。", "因谁特故迟。", "曾是骚人盼。", "羞做茱萸伴。", "揉破郁金黄。", "与君些子香。"]'),
('song-ci-868','菩萨蛮','毛滂','宋','宋词','song-ci','菩萨蛮','[]','溪山不尽知多少。',52,'宋词/ci.song.4000.json','["溪山不尽知多少。", "遥峰秀叠寒波渺。", "携酒上高台。", "与君开壮怀。", "枉做悲秋赋。", "醉后悲何处。", "白发几黄花。", "官裘付酒家。"]'),
('song-ci-869','菩萨蛮','毛滂','宋','宋词','song-ci','菩萨蛮','[]','春潮曾送离魂去。',52,'宋词/ci.song.4000.json','["春潮曾送离魂去。", "春山曾见伤离处。", "老去不堪愁。", "凭阑看水流。", "东风留不住。", "一夜檐前雨。", "明日觅春痕。", "红疏桃杏村。"]'),
('song-ci-870','菩萨蛮','毛滂','宋','宋词','song-ci','菩萨蛮','[]','云山沁绿残眉浅。',52,'宋词/ci.song.4000.json','["云山沁绿残眉浅。", "垂杨睡起腰肢软。", "不见玉妆台。", "飞花将梦来。", "行云何事恶。", "雨透罗衣薄。", "不忍湿残春。", "黄莺啼向人。"]'),
('song-ci-871','菩萨蛮','毛滂','宋','宋词','song-ci','菩萨蛮','[]','当时学舞钧天部。',52,'宋词/ci.song.4000.json','["当时学舞钧天部。", "惊鸿吹下江湖去。", "家住百花桥。", "何郎偏与娇。", "杏梁尘拂面。", "牙板闻莺燕。", "劝客玉梨花。", "月侵钗燕斜。"]'),
('song-ci-872','渔家傲','毛滂','宋','宋词','song-ci','渔家傲','[]','年少莫寻潜玉老。',72,'宋词/ci.song.4000.json','["年少莫寻潜玉老。", "无才无艺烦君笑。", "暖过茅檐霜日晓。", "休起早。", "竹间尽日无人到。", "别径小峰孤碧峭。", "曲沟浅浸寒清绕。", "此老相看情不少。", "浑忘了。", "浑教忘了长安道。"]'),
('song-ci-873','渔家傲','毛滂','宋','宋词','song-ci','渔家傲','[]','恰则小庵贪睡著。',72,'宋词/ci.song.4000.json','["恰则小庵贪睡著。", "不知风撼梅花落。", "一点儿春吹去却。", "香约略。", "黄蜂犹抱红酥萼。", "绕遍寒枝添索寞。", "却穿竹径随孤鹤。", "守定微官真个错。", "从今莫。", "从今莫负云山约。"]'),
('song-ci-874','渔家傲','毛滂','宋','宋词','song-ci','渔家傲','[]','鬓底青春留不住。',72,'宋词/ci.song.4000.json','["鬓底青春留不住。", "功名薄似风前絮。", "何似瓮头春没数。", "都占取。", "只消一纸长门赋。", "寒日半窗桑柘暮。", "倚阑目送繁云去。", "却欲载书寻旧路。", "烟深处。", "杏花菖叶耕春雨。"]'),
('song-ci-875','于飞乐','毛滂','宋','宋词','song-ci','于飞乐','[]','水边山，云畔水，新出烟林。',98,'宋词/ci.song.4000.json','["水边山，云畔水，新出烟林。", "送秋来、双桧寒阴。", "桧堂寒，香雾碧，帘箔清深。", "放衙隐几，谁知共、云水无心。", "望西园，飞盖夜，月到清尊。", "为诗翁、露冷风清。", "退红裙，云碧袖，花草争春。", "劝翁强饮，莫孤负、风月留人。"]'),
('song-ci-876','于飞乐','毛滂','宋','宋词','song-ci','于飞乐','[]','记瞢腾，浓睡里，一片行云。',98,'宋词/ci.song.4000.json','["记瞢腾，浓睡里，一片行云。", "未多时、梦破云惊。", "听辘轳，声断也，井底银瓶。", "不知罗带，等闲便、结得同心。", "系画船，杨柳岸，晓月亭亭。", "记阳关、断韵残声。", "被西风，吹玉枕，酒魄还清。", "有些言语，独自个、说与谁应。"]'),
('song-ci-877','于飞乐','毛滂','宋','宋词','song-ci','于飞乐','[]','并梅兄，双蝶子，烟缕衫轻。',98,'宋词/ci.song.4000.json','["并梅兄，双蝶子，烟缕衫轻。", "凤凰钗、缭绕香云。", "淡梳妆，□得恁，雪腻酥匀。", "揉春捻就，更是他、花与精神。", "黛尖低、桃萼破，微笑轻颦。", "早做成、役梦劳魂。", "好风前，佳月下，莫忘行人。", "扁舟去也，没个事、多样离情。"]'),
('song-ci-878','阮郎归','毛滂','宋','宋词','song-ci','阮郎归','[]','映阶芳草净无尘。',56,'宋词/ci.song.4000.json','["映阶芳草净无尘。", "新晴隔柳阴。", "绿丝步障碧茸茵。", "遮藏欲尽春。", "寒未了，酒须深。", "残花无处寻。", "年来陪尽惜春心。", "闲愁渐不禁。"]'),
('song-ci-879','阮郎归','毛滂','宋','宋词','song-ci','阮郎归','[]','雨馀烟草弄春柔。',56,'宋词/ci.song.4000.json','["雨馀烟草弄春柔。", "芳郊翠欲流。", "暖风时转柳花球。", "晴光烂不收。", "红尽处，绿新稠。", "秾华只暂留。", "却应留下等闲愁。", "令人双鬓秋。"]'),
('song-ci-880','虞美人','毛滂','宋','宋词','song-ci','虞美人','[]','游人莫笑东园小。',66,'宋词/ci.song.4000.json','["游人莫笑东园小。", "莫问花多少。", "一枝半朵恼人肠。", "无限姿姿媚媚、倚斜阳。", "二分春去知何处。", "赖是无风雨。", "更将绣幕密遮花。", "任是东风急性、不由他。"]'),
('song-ci-881','虞美人','毛滂','宋','宋词','song-ci','虞美人','[]','百花赶定东君去。',66,'宋词/ci.song.4000.json','["百花赶定东君去。", "知与花何处。", "阳春但更买花栽。", "留住蜂儿蝶子、等君来。", "翠轻绿嫩庭阴好。", "醉便眠芳草。", "春波如酒不曾空。", "谁见东堂日日、自春风。"]'),
('song-ci-882','虞美人','毛滂','宋','宋词','song-ci','虞美人','[]','柳枝却学腰肢袅。',66,'宋词/ci.song.4000.json','["柳枝却学腰肢袅。", "好似江东小。", "春风吹绿上眉峰。", "秀色欲流不断、眼波融。", "檐前月上灯花堕。", "风递馀香过。", "小欢云散已难收。", "到处冷烟寒雨、为君愁。"]'),
('song-ci-883','一落索','毛滂','宋','宋词','song-ci','一落索','[]','月下风前花畔。',56,'宋词/ci.song.4000.json','["月下风前花畔。", "此情不浅。", "欲留风月守花枝，却不道、而今远。", "樯外鹭飞沙晚。", "烟斜雨短。", "青山祗管一重重，向东下、遮人眼。"]'),
('song-ci-884','散馀霞','毛滂','宋','宋词','song-ci','散馀霞','[]','墙头花□寒犹噤。',53,'宋词/ci.song.4000.json','["墙头花□寒犹噤。", "放绣帘昼静。", "帘外时有蜂儿，趁杨花不定。", "阑干又还独凭。", "念翠低眉晕。", "春梦枉恼人肠，更厌厌酒病。"]'),
('song-ci-885','最高楼','毛滂','宋','宋词','song-ci','最高楼','[]','微雨过，深院芰荷中。',102,'宋词/ci.song.4000.json','["微雨过，深院芰荷中。", "香冉冉，绣重重。", "玉人共倚阑干角，月华犹在小池东。", "入人怀，吹鬓影，可怜风。", "分散去、轻如云与梦，剩下了、许多风与月，侵枕簟，冷帘栊。", "副能小睡还惊觉，略成轻醉早醒松。", "仗行云，将此恨，到眉峰。"]'),
('song-ci-886','最高楼','毛滂','宋','宋词','song-ci','最高楼','[]','新睡起，熏过绣罗衣。',101,'宋词/ci.song.4000.json','["新睡起，熏过绣罗衣。", "梳洗了，百般宜。", "东风淡荡垂杨院，一春心事有谁知。", "苦留人，娇不尽，曲眉低。", "漫良夜、月圆空好意，恐落花、流水终寄恨，悲欢往往相随。", "凤台痴望双双羽，高唐愁著梦回时。", "又争如，遵大路，合逢伊。"]'),
('song-ci-887','少年游','毛滂','宋','宋词','song-ci','少年游','[]','遥山雪气入疏帘。',60,'宋词/ci.song.4000.json','["遥山雪气入疏帘。", "罗幕晓寒添。", "爱日腾波，朝霞入户，一线过冰檐。", "绿尊香嫩蒲萄暖，满酌破冬严。", "庭下早梅，已含芳意，春近瘦枝南。"]'),
('song-ci-888','粉蝶儿','毛滂','宋','宋词','song-ci','粉蝶儿','[]','雪遍梅花，素光都共奇绝。',90,'宋词/ci.song.4000.json','["雪遍梅花，素光都共奇绝。", "到窗前、认君时节。", "下重帏，香篆冷，兰膏明灭。", "梦悠扬，空绕断云残月。", "沈郎带宽，同心放开重结。", "褪罗衣、楚腰一捻。", "正春风，新著摸，花花叶叶。", "粉蝶儿，这回共花同活。"]'),
('song-ci-889','调笑・调笑令','毛滂','宋','宋词','song-ci','调笑・调笑令','[]','城月。',45,'宋词/ci.song.4000.json','["城月。", "冷罗袜。", "郎睡不知鸾帐揭。", "香凄翠被灯明灭。", "花困钗横时节。", "河桥杨柳催行色。", "愁黛有人描得。"]'),
('song-ci-890','调笑・调笑令','毛滂','宋','宋词','song-ci','调笑・调笑令','[]','香歇。',45,'宋词/ci.song.4000.json','["香歇。", "袂红黦。", "记立河桥花自折。", "隼旟绀幰城西阙。", "教妾惊鸿回雪。", "铜驼春梦空愁绝。", "云破碧江流月。"]'),
('song-ci-891','调笑・调笑令','毛滂','宋','宋词','song-ci','调笑・调笑令','[]','无力。',45,'宋词/ci.song.4000.json','["无力。", "倚瑶瑟。", "罢舞霓裳今几日。", "楼空雨小春寒逼。", "钿晕罗衫烟色。", "帘前归燕看人立。", "却趁落花飞入。"]'),
('song-ci-892','调笑・调笑令','毛滂','宋','宋词','song-ci','调笑・调笑令','[]','钗冷。',45,'宋词/ci.song.4000.json','["钗冷。", "鬓云晚。", "罗袖拂人花气暖。", "风流公子来应远。", "半倚瑶琴羞懒。", "云寒日暮天微霰。", "无处不堪肠断。"]'),
('song-ci-893','调笑・调笑令','毛滂','宋','宋词','song-ci','调笑・调笑令','[]','憔悴。',45,'宋词/ci.song.4000.json','["憔悴。", "何郎地。", "密寄软绡三尺泪。", "传心语眼郎应记。", "翠袖犹芬仙桂。", "愿郎学做蝴蝶子。", "去去来来花里。"]'),
('song-ci-894','调笑・调笑令','毛滂','宋','宋词','song-ci','调笑・调笑令','[]','何处。',45,'宋词/ci.song.4000.json','["何处。", "长安路。", "不记墙东花拂树。", "瑶琴理罢霓裳谱。", "依旧月窗风户。", "薄情年少如飞絮。", "梦逐玉环西去。"]'),
('song-ci-895','调笑・调笑令','毛滂','宋','宋词','song-ci','调笑・调笑令','[]','芳草。',45,'宋词/ci.song.4000.json','["芳草。", "恨春老。", "自是寻春来不早。", "落花风起红多少。", "记得一枝春小。", "绿阴青子空相恼。", "此恨平生怀抱。"]'),
('song-ci-896','调笑・调笑令','毛滂','宋','宋词','song-ci','调笑・调笑令','[]','相望。',45,'宋词/ci.song.4000.json','["相望。", "楚江上。", "萦水缭云闻妙唱。", "龙沙醉眼看花浪。", "正要风将月傍。", "云车瑶佩成惆怅。", "衰柳白须相向。"]'),
('song-ci-897','调笑・调笑令','毛滂','宋','宋词','song-ci','调笑・调笑令','[]','酒美。',45,'宋词/ci.song.4000.json','["酒美。", "从酒贵。", "濯锦江边花满地。", "鹔鹴换得文君醉。", "暖和一团春意。", "怕将醒眼看浮世。", "不换云芽雪水。"]'),
('song-ci-898','调笑・调笑令','毛滂','宋','宋词','song-ci','调笑・调笑令','[]','花好。',45,'宋词/ci.song.4000.json','["花好。", "怕花老。", "暖日和风将养到。", "东君须愿长年少。", "图不看花草草。", "西园一点红犹小。", "早被蜂儿知道。"]'),
('song-ci-899','感皇恩','毛滂','宋','宋词','song-ci','感皇恩','[]','两岁抚邦人，曾无恩意。',81,'宋词/ci.song.4000.json','["两岁抚邦人，曾无恩意。", "别后何人更相记。", "题舆玉树，愧与蒹葭相倚。", "殷勤犹念我，同吟醉。", "画舸相追，孤城已闭。", "不道扁舟□云外。", "夜分月冷，一段波平风细。", "忆君清兴满，无由寄。"]'),
('song-ci-900','感皇恩','毛滂','宋','宋词','song-ci','感皇恩','[]','绿水小河亭，朱阑碧甃。',81,'宋词/ci.song.4000.json','["绿水小河亭，朱阑碧甃。", "江月娟娟上高柳。", "画楼缥缈，尽挂窗纱帘绣。", "月明知我意，来相就。", "银字吹笙，金貂取酒。", "小小微风弄襟袖。", "宝熏浓炷，人共博山烟瘦。", "露凉钗燕冷，更深后。"]'),
('song-ci-901','感皇恩','毛滂','宋','宋词','song-ci','感皇恩','[]','多病酒尊疏，饮少辄醉。',81,'宋词/ci.song.4000.json','["多病酒尊疏，饮少辄醉。", "年少衔杯可追记。", "无多酌我，醉倒阿谁扶起。", "满怀明月冷，炉烟细。", "云汉虽高，风波无际。", "何似归来醉乡里。", "玻璃江上，满载春光花气。", "蒲萄仙浪软，迷红翠。"]'),
('song-ci-902','临江仙','毛滂','宋','宋词','song-ci','临江仙','[]','闻道长安灯夜好，雕轮宝马如云。',70,'宋词/ci.song.4000.json','["闻道长安灯夜好，雕轮宝马如云。", "蓬莱清浅对觚棱。", "玉皇开碧落，银界失黄昏。", "谁见江南憔悴客，端忧懒步芳尘。", "小屏风畔冷香凝。", "酒浓春入梦，窗破月寻人。"]'),
('song-ci-903','相见欢','毛滂','宋','宋词','song-ci','相见欢','[]','十年湖海扁舟。',45,'宋词/ci.song.4000.json','["十年湖海扁舟。", "几多愁。", "白发青灯今夜、不宜秋。", "中庭树。", "空阶雨。", "思悠悠。", "寂寞一生心事、五更头。"]'),
('song-ci-904','花心动','刘焘','宋','宋词','song-ci','花心动','[]','偏忆江南，有尘表丰神，世外标格。',126,'宋词/ci.song.4000.json','["偏忆江南，有尘表丰神，世外标格。", "低傍小桥，斜山疏篱，似向陇头曾识。", "暗香孤韵冰雪里，初不怕、春寒要勒。", "问桃杏贤瞒，怎生向前争得。", "省共萧娘笑摘。", "玉纤映琼枝，照人一色。", "澹粉晕酥，多少工夫，到得寿阳宫额。", "再三留待东君看，管都将、别花不惜。", "但只恐、南楼又三弄笛。"]'),
('song-ci-905','八宝妆','刘焘','宋','宋词','song-ci','八宝妆','[]','门掩黄昏，画堂人寂，暮雨乍收残暑。',132,'宋词/ci.song.4000.json','["门掩黄昏，画堂人寂，暮雨乍收残暑。", "帘卷疏星门户悄，隐隐严城钟鼓。", "空街烟暝半开，斜日朦胧，银河澄淡风凄楚。", "还是凤楼人远，桃源无路。", "惆怅夜久星繁，碧空望断，玉箫声在何处。", "念谁伴、茜裙翠袖，共携手、瑶台归去。", "对修竹、森森院宇。", "曲屏香暖凝沈炷。", "问对酒当歌，情怀记得刘郎否。"]'),
('song-ci-906','转调满庭芳・满庭芳','刘焘','宋','宋词','song-ci','转调满庭芳・满庭芳','[]','风急霜浓，天低云淡，过来孤雁声切。',116,'宋词/ci.song.4000.json','["风急霜浓，天低云淡，过来孤雁声切。", "雁儿且住，略听自家说。", "你是离群到此，我共那人才相别。", "松江岸，黄芦影里，天更待飞雪。", "声声肠欲断，和我也、泪珠点点成血。", "一江流水，流也呜咽。", "告你高飞远举，前程事、永没磨折。", "须知道、飘零聚散，终有见时节。"]'),
('song-ci-907','菩萨蛮','刘焘','宋','宋词','song-ci','菩萨蛮','[]','小红桃脸花中笑。',52,'宋词/ci.song.4000.json','["小红桃脸花中笑。", "笑中花脸桃红小。", "垂柳拂帘低。", "低帘拂柳垂。", "袅花风鬓绕。", "绕鬓风花袅。", "归路月沈西。", "西沈月路归。"]'),
('song-ci-908','菩萨蛮','刘焘','宋','宋词','song-ci','菩萨蛮','[]','簟纹双映冰肌艳。',52,'宋词/ci.song.4000.json','["簟纹双映冰肌艳。", "艳肌冰映双纹簟。", "窗外竹生风。", "风生竹外窗。", "点红潮醉脸。", "脸醉潮红点。", "廊上月昏黄。", "黄昏月上廊。"]'),
('song-ci-909','菩萨蛮','刘焘','宋','宋词','song-ci','菩萨蛮','[]','露盘金冷初阑暑。',52,'宋词/ci.song.4000.json','["露盘金冷初阑暑。", "暑阑初冷金盘露。", "风细引鸣蛩。", "蛩鸣引细风。", "雨零愁远路。", "路远愁零雨。", "空醉一尊同。", "同尊一醉空。"]'),
('song-ci-910','菩萨蛮','刘焘','宋','宋词','song-ci','菩萨蛮','[]','屑琼霏玉堆檐雪。',52,'宋词/ci.song.4000.json','["屑琼霏玉堆檐雪。", "雪檐堆玉霏琼屑。", "山远对眉攒。", "攒眉对远山。", "拆梅寒映月。", "月映寒梅拆。", "阑倚暂愁宽。", "宽愁暂倚阑。"]'),
('song-ci-911','菩萨蛮','刘焘','宋','宋词','song-ci','菩萨蛮','[]','湿花春雨如珠泣。',52,'宋词/ci.song.4000.json','["湿花春雨如珠泣。", "泣珠如雨春花湿。", "花枕并敧斜。", "斜敧并枕花。", "织文回字密。", "密字回文织。", "嗟更数年华。", "华年数更嗟。"]'),
('song-ci-912','菩萨蛮','刘焘','宋','宋词','song-ci','菩萨蛮','[]','润肌饶汗香红沁。',52,'宋词/ci.song.4000.json','["润肌饶汗香红沁。", "沁红香汗饶肌润。", "低槛小山围。", "围山小槛低。", "枕横钗坠鬓。", "鬓坠钗横枕。", "归梦与郎期。", "期郎与梦归。"]'),
('song-ci-913','菩萨蛮','刘焘','宋','宋词','song-ci','菩萨蛮','[]','绿窗斜动摇风竹。',52,'宋词/ci.song.4000.json','["绿窗斜动摇风竹。", "竹风摇动斜窗绿。", "虚恍夕凉初。", "初凉夕恍虚。", "曲眉愁翠蹙。", "蹙翠愁眉曲。", "无雁寄书来。", "来书寄雁无。"]'),
('song-ci-914','菩萨蛮','刘焘','宋','宋词','song-ci','菩萨蛮','[]','雪窗寒听孤灯灭。',52,'宋词/ci.song.4000.json','["雪窗寒听孤灯灭。", "灭灯孤听寒窗雪。", "残漏惜衾闲。", "闲衾惜漏残。", "说时常恨别。", "别恨常时说。", "还不奈宵寒。", "寒宵奈不还。"]'),
('song-ci-915','于飞乐','宇文元质','宋','宋词','song-ci','于飞乐','[]','休休得也，只消更、一朵荼蘼。',14,'宋词/ci.song.4000.json','["休休得也，只消更、一朵荼蘼。"]'),
('song-ci-916','满庭芳慢・满庭芳','范致虚','宋','宋词','song-ci','满庭芳慢・满庭芳','[]','紫禁寒轻，瑶津冰泮，丽月光射千门。',117,'宋词/ci.song.4000.json','["紫禁寒轻，瑶津冰泮，丽月光射千门。", "万年枝上，甘露惹祥氛。", "北阙华灯预赏，嬉游盛、丝管纷纷。", "东风峭，雪残梅瘦，烟锁凤城春。", "风光何处好，彩山万仞，宝炬凌云。", "尽欢陪舜乐，喜赞尧仁。", "天子千秋万岁，徵招宴、宰府师臣。", "君恩重，年年此夜，长祝本嘉辰。"]'),
('song-ci-917','鹧鸪天','郑少微','宋','宋词','song-ci','鹧鸪天','[]','谁折南枝傍小丛。',64,'宋词/ci.song.4000.json','["谁折南枝傍小丛。", "佳人丰色与梅同。", "有花无叶真潇洒，不问胭脂借淡红。", "应未许，嫁春风。", "天教雪月伴玲珑。", "池塘疏影伤幽独，何似横斜酒盏中。"]'),
('song-ci-918','思越人・朝天子','郑少微','宋','宋词','song-ci','思越人・朝天子','[]','欲把长绳系日难。',64,'宋词/ci.song.4000.json','["欲把长绳系日难。", "纷纷从此见花残。", "休将世事兼身事，须看人间比梦间。", "红烛继，艳歌阑。", "等闲留客却成欢。", "劝君更尽一杯酒，赢得浮生半日闲。"]'),
('song-ci-919','临江仙','李新','宋','宋词','song-ci','临江仙','[]','杨柳梢头春色重，紫骝嘶入残花。',70,'宋词/ci.song.4000.json','["杨柳梢头春色重，紫骝嘶入残花。", "香风满面日西斜。", "只知闲信马，不觉误随车。", "已许洞天归路晚，空劳眼惜眉怜。", "几回偷为掷花钿。", "今生应已过，重结后来缘。"]'),
('song-ci-920','浣溪沙','李新','宋','宋词','song-ci','浣溪沙','[]','千古人生乐事稀。',48,'宋词/ci.song.4000.json','["千古人生乐事稀。", "露浓烟事薄寒时。", "菊花须插两三枝。", "未老功名辜两鬓，悲秋情绪入双眉。", "茂陵多病有谁知。"]'),
('song-ci-921','浣溪沙','李新','宋','宋词','song-ci','浣溪沙','[]','雨霁笼山碧破赊。',48,'宋词/ci.song.4000.json','["雨霁笼山碧破赊。", "小园围屋粉墙斜。", "朱门闲掩那人家。", "素腕拨香临宝砌，层波窥客擘轻纱。", "隔窗隐隐见簪花。"]'),
('song-ci-922','摊破浣溪沙・山花子','李新','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','几度珠帘卷上钩。',56,'宋词/ci.song.4000.json','["几度珠帘卷上钩。", "折花走马向扬州。", "老去不堪寻往事，上心头。", "陶令无聊惟喜醉，茂陵多病不胜愁。", "脉脉春情长不断，水东流。"]'),
('song-ci-923','临江仙','欧阳辟','宋','宋词','song-ci','临江仙','[]','涧碧山红粉烂漫，烟萝远映霜枫。',70,'宋词/ci.song.4000.json','["涧碧山红粉烂漫，烟萝远映霜枫。", "倚阑人在暮云东。", "遥天垂众壑，平地起孤峰。", "大好家山重九日，尊前切莫匆匆。", "黄花消息雁声中。", "寻芳须未晚，与客且携筇。"]'),
('song-ci-924','黄金缕・蝶恋花','司马','宋','宋词','song-ci','黄金缕・蝶恋花','["\u94b1\u5858\u6c5f"]','家在钱塘江上住。',70,'宋词/ci.song.4000.json','["家在钱塘江上住。", "花落花开，不管年华度。", "燕子又将春色去。", "纱窗一阵黄昏雨。", "斜插犀梳云半吐。", "檀板清歌，唱彻黄金缕。", "望断云行无去处。", "梦回明月生春浦。"]'),
('song-ci-925','河传','司马','宋','宋词','song-ci','河传','[]','银河漾漾。',75,'宋词/ci.song.4000.json','["银河漾漾。", "正桐飞露井，寒生斗帐。", "芳草梦惊，人忆高唐惆怅。", "感离愁，甚情况。", "春风二月桃花浪。", "扁舟征棹，又过吴江上。", "人去雁回，千里风云相望。", "倚江楼，倍凄怆。"]'),
('song-ci-926','蝶恋花','王重','宋','宋词','song-ci','蝶恋花','[]','去岁花前曾记有。',70,'宋词/ci.song.4000.json','["去岁花前曾记有。", "坐醉嬉游，花下携纤手。", "粉面与花相间斗。", "星眸一转晴波溜。", "一见新花还感旧。", "泪眼逢春，忍更看花柳。", "春恨厌厌如永昼。", "□□寂寞黄昏后。"]'),
('song-ci-927','烛影摇红','王重','宋','宋词','song-ci','烛影摇红','[]','烟雨江城，望中绿暗花枝少。',58,'宋词/ci.song.4000.json','["烟雨江城，望中绿暗花枝少。", "惜春长待醉东风，却恨春归早。", "纵有幽情欢会，奈如今、风情渐老。", "凤楼何处，画阑愁倚，天涯芳草。"]'),
('song-ci-928','失调名','某两地','宋','宋词','song-ci','失调名','[]','为爱金陵佳丽。',58,'宋词/ci.song.4000.json','["为爱金陵佳丽。", "乃分符来此。", "拥麾忽又向淮东，便咫尺、人千里。", "画鼓一声催起。", "邦内人齐跪。", "江山有兴我重来，斟别酒、休辞泪。"]'),
('song-ci-929','浣溪沙','王采','宋','宋词','song-ci','浣溪沙','[]','雪里东风未过江。',48,'宋词/ci.song.4000.json','["雪里东风未过江。", "陇头先折一枝芳。", "如今疏影照溪塘。", "北客乍惊无绿叶，东君应笑不红妆。", "玉真爱著淡衣裳。"]'),
('song-ci-930','渔家傲','王采','宋','宋词','song-ci','渔家傲','[]','日月无根天不老。',72,'宋词/ci.song.4000.json','["日月无根天不老。", "浮生总被消磨了。", "陌上红尘常扰扰。", "昏复晓。", "一场大梦谁先觉。", "雒水东流山四绕。", "路傍几个新华表。", "见说在时官职好。", "争信道。", "冷烟寒雨埋荒草。"]'),
('song-ci-931','浣溪沙','王采','宋','宋词','song-ci','浣溪沙','[]','扇影轻摇一线香。',48,'宋词/ci.song.4000.json','["扇影轻摇一线香。", "斜红匀过晚来妆。", "娇多无事做凄凉。", "借问谁教春易老，几时能勾夜何长。", "旧欢新恨总思量。"]'),
('song-ci-932','浣溪沙','王采','宋','宋词','song-ci','浣溪沙','[]','珠箔随檐一桁垂。',48,'宋词/ci.song.4000.json','["珠箔随檐一桁垂。", "绣屏遮枕四边移。", "春归人懒日迟迟。", "旧事只将云入梦，新欢重借月为期。", "晚来花动隔墙枝。"]'),
('song-ci-933','玉楼春','王采','宋','宋词','song-ci','玉楼春','[]','秋闺思入江南远。',64,'宋词/ci.song.4000.json','["秋闺思入江南远。", "帘幕低垂闲不卷。", "玉珂声断晓屏空，好梦惊回还起懒。", "风轻只觉香烟短。", "阴重不知天色晚。", "隔窗人语趁朝归，旋整宿妆匀睡脸。"]'),
('song-ci-934','玉楼春','王采','宋','宋词','song-ci','玉楼春','[]','绣屏晓梦鸳鸯侣。',64,'宋词/ci.song.4000.json','["绣屏晓梦鸳鸯侣。", "可惜夜来欢聚取。", "几声低语记曾闻，一段新愁看乍觑。", "繁红洗尽胭脂雨。", "春被杨花勾引去。", "多情只有旧时香，衣上经年留得住。"]'),
('song-ci-935','蝶恋花','王采','宋','宋词','song-ci','蝶恋花','[]','燕子来时春未老。',70,'宋词/ci.song.4000.json','["燕子来时春未老。", "红蜡团枝，费尽东君巧。", "烟雨弄晴芳意恼。", "雨馀特地残妆好。", "斜倚青楼临远道。", "不管傍人，密共东君笑。", "都见娇多情不少。", "丹青传得倾城貌。"]'),
('song-ci-936','蝶恋花','王采','宋','宋词','song-ci','蝶恋花','[]','濯锦江头春欲暮。',70,'宋词/ci.song.4000.json','["濯锦江头春欲暮。", "枝上繁红，着意留春住。", "只恐东君嫌面素。", "新妆剩把胭脂傅。", "晓梦惊寒初过雨。", "寂寞珠帘，问有馀花否。", "怅望草堂无一语。", "丹青传得凝情处。"]'),
('song-ci-937','蝶恋花','王采','宋','宋词','song-ci','蝶恋花','[]','秾艳娇春春婉娩。',70,'宋词/ci.song.4000.json','["秾艳娇春春婉娩。", "雨惜风饶，学得宫妆浅。", "爱把绿眉都不展。", "无言脉脉情何限。", "花下当时红粉面。", "准拟新年，都向花前见。", "争奈武陵人易散。", "丹青传得闺中怨。"]'),
('song-ci-938','蝶恋花','王采','宋','宋词','song-ci','蝶恋花','[]','镂雪成花檀作蕊。',70,'宋词/ci.song.4000.json','["镂雪成花檀作蕊。", "爱伴秋千，摇曳东风里。", "翠袖年年寒食泪。", "为伊牵惹愁无际。", "幽艳偏宜春雨细。", "红粉阑干，有个人相似。", "钿合金钗谁与寄。", "丹青传得凄凉意。"]'),
('song-ci-939','蝶恋花','王采','宋','宋词','song-ci','蝶恋花','[]','晕绿抽芽新叶斗。',70,'宋词/ci.song.4000.json','["晕绿抽芽新叶斗。", "掩映娇红，脉脉群芳后。", "京兆画眉樊素口。", "风姿别是闺房秀。", "新篆题诗霜实就。", "换得琼琚，心事偏长久。", "应是春来初觉有。", "丹青传得厌厌瘦。"]'),
('song-ci-940','蝶恋花','王采','宋','宋词','song-ci','蝶恋花','[]','花为年年春易改。',70,'宋词/ci.song.4000.json','["花为年年春易改。", "待放柔条，系取长春在。", "宫样妆成还可爱。", "鬓边斜作拖枝戴。", "每到无情风雨大。", "检点群芳，却是深丛耐。", "摇曳绿萝金缕带。", "丹青传得妖娆态。"]'),
('song-ci-941','蓦山溪','周纯','宋','宋词','song-ci','蓦山溪','[]','江南春信，望断人千里。',102,'宋词/ci.song.4000.json','["江南春信，望断人千里。", "魂梦入花枝，染相思、同心并蒂。", "鸳鸯名字，赢得一双双，无限意。", "凝烟水。", "念远教谁寄。", "毫端写兴，莫把丹青拟。", "墨客要卿卿，想临池、等闲梳洗。", "香衣黯淡，元不涴缁尘，怜缟袂。", "东风里。", "只恐于飞起。"]'),
('song-ci-942','满庭霜・满庭芳','周纯','宋','宋词','song-ci','满庭霜・满庭芳','[]','脂泽休施，铅华不御，自然林下真风。',118,'宋词/ci.song.4000.json','["脂泽休施，铅华不御，自然林下真风。", "欲窥馀韵，何处问仙踪。", "路厌横桥夜雪，看暗淡、残月朦胧。", "无言处，丹青莫拟，谁寄染毫工。", "遥通。", "尘外信，寒生墨晕，依约形容。", "似疏疏斜影，蘸水摇空。", "收入云窗雾箔，春不老、芳意无穷。", "梨花雨，飘零尽也，难入梦魂中。"]'),
('song-ci-943','菩萨蛮','周纯','宋','宋词','song-ci','菩萨蛮','[]','梅花韵似才人面。',52,'宋词/ci.song.4000.json','["梅花韵似才人面。", "为伊写在春风扇。", "人面似花妍。", "花应不解言。", "在手微风动。", "勾引相思梦。", "莫用插酴醿。", "酴醿羞见伊。"]'),
('song-ci-944','瑞鹧鸪','周纯','宋','宋词','song-ci','瑞鹧鸪','[]','一痕月色挂帘栊。',64,'宋词/ci.song.4000.json','["一痕月色挂帘栊。", "梅影斜斜小院中。", "狂醉有心窥粉面，梦魂无处避香风。", "愁来梦楚三千里，人在巫山十二重。", "咫尺蓝桥无处问，玉萧声断楚山空。"]'),
('song-ci-945','西江月','曹希蕴','宋','宋词','song-ci','西江月','[]','零落不因春雨，吹嘘何假东风。',58,'宋词/ci.song.4000.json','["零落不因春雨，吹嘘何假东风。", "纱窗一点自然红。", "费尽工夫怎种。", "有艳难寻腻粉，无香不惹游蜂。", "更阑人静画堂中。", "相伴玉人春梦。"]'),
('song-ci-946','踏莎行','曹希蕴','宋','宋词','song-ci','踏莎行','[]','解遣愁人，能添喜气。',68,'宋词/ci.song.4000.json','["解遣愁人，能添喜气。", "些儿好事先施力。", "画堂深处伴妖娆，绛纱笼里丹砂赤。", "有艳难留，无根怎觅。", "几回不忍轻轻别。", "玉人曾向耳边言，花有信、人无的。"]'),
('song-ci-947','望江南・忆江南','廖刚','宋','宋词','song-ci','望江南・忆江南','[]','无诸好，方面镇全闽。',64,'宋词/ci.song.4000.json','["无诸好，方面镇全闽。", "千骑泛云归洞府，三山明玉外风尘。", "依约是蓬瀛。", "贤刺史，龙虎檀香名。", "金花已传当日梦，锦衣聊慰故乡情。", "和气万家春。"]'),
('song-ci-948','望江南・忆江南','廖刚','宋','宋词','song-ci','望江南・忆江南','[]','无诸好，金地遍重城。',64,'宋词/ci.song.4000.json','["无诸好，金地遍重城。", "乌石亭危千嶂合，荔枝楼暖百花明。", "十里暮潮平。", "贤刺史，来暮相欢迎。", "终向凤池朝紫极，暂依猿洞驻朱轮。", "风月锦堂春。"]'),
('song-ci-949','满路花・促拍满路花','廖刚','宋','宋词','song-ci','满路花・促拍满路花','[]','雨霁烟波阔，雁度陇云愁。',97,'宋词/ci.song.4000.json','["雨霁烟波阔，雁度陇云愁。", "西风庭院不胜秋。", "桂华光满，偏照最高楼。", "东山携妓约，故人千里，夜来为舣仙舟。", "明眸皓齿，歌舞总名流。", "恼人情态物中忧。", "阳春一曲，谁把万金酬。", "便好拚沈醉，此夕姮娥，共须著意攀留。"]'),
('song-ci-950','望江南・忆江南','廖刚','宋','宋词','song-ci','望江南・忆江南','[]','柯山瑞，云路玉桥横。',64,'宋词/ci.song.4000.json','["柯山瑞，云路玉桥横。", "六月天香琼蕊秀，千年人瑞昂星明。", "风露湿麒麟。", "廊庙器，冰雪照精神。", "妙世文章凌贾马，致君事业富姬衡。", "松桧倚青青。"]'),
('song-ci-951','望江南・忆江南','廖刚','宋','宋词','song-ci','望江南・忆江南','[]','蓬山晓，龟鹤倚芝庭。',64,'宋词/ci.song.4000.json','["蓬山晓，龟鹤倚芝庭。", "云覆宝熏迷舞凤，玉扶琼液荐文星。", "棠荫署风清。", "人尽道，天遣瑞升平。", "九万鹏程才振翼，八千椿寿恰逢春。", "貂衮瞩公荣。"]'),
('song-ci-952','阮郎归','廖刚','宋','宋词','song-ci','阮郎归','[]','月桥风槛水边居。',56,'宋词/ci.song.4000.json','["月桥风槛水边居。", "画楼三鼓初。", "草堂收拾读闲书。", "起看清夜徂。", "闲想像，尽踌躇。", "玉牌金字铺。", "梦昏纵有也成虚。", "那堪和梦无。"]'),
('song-ci-953','蓦山溪','廖刚','宋','宋词','song-ci','蓦山溪','["\u957f\u6c5f"]','论长校短，总是非闲誉。',102,'宋词/ci.song.4000.json','["论长校短，总是非闲誉。", "光景百年中，似难留、长江东去。", "随缘游戏，触□寄高情，西楼月，北窗风，鸖鹆尊前舞。", "故人襟韵，千里心相许。", "飞骑趁花时，正名园、揉风洗雨。", "玻璃潋滟，聊共醉红裙，阳春曲，碧云词，慷慨怀千古。"]'),
('song-ci-954','念奴娇','赵鼎臣','宋','宋词','song-ci','念奴娇','[]','旧游何处，记金汤形胜，蓬瀛佳丽。',122,'宋词/ci.song.4000.json','["旧游何处，记金汤形胜，蓬瀛佳丽。", "渌水芙蓉，元帅与宾僚，风流济济。", "万柳庭边，雅歌堂上，醉倒春风里。", "十年一梦，觉来烟水千里。", "惆怅送子重游，南楼依旧不，朱阑谁倚。", "要识当时，惟是有明月，曾陪珠履。", "量减杯中，雪添头上，甚矣吾衰矣。", "酒徒相问，为言憔悴如此。"]'),
('song-ci-955','玉漏迟','韩嘉彦','宋','宋词','song-ci','玉漏迟','[]','杏香消散尽，须知自昔，都门春早。',115,'宋词/ci.song.4000.json','["杏香消散尽，须知自昔，都门春早。", "燕子来时，绣陌乱铺芳草。", "蕙圃妖桃过雨，弄笑脸、红筛碧沼。", "深院悄。", "绿杨巷陌，莺声争巧。", "早是赋得多情，更遇酒临花，镇辜欢笑。", "数曲阑干，故国谩劳凝眺。", "汉外微云尽处，乱峰锁、一杆修竹。", "间琅玕，东风泪零多少。"]'),
('song-ci-956','鹊桥仙','谢薖','宋','宋词','song-ci','鹊桥仙','[]','月胧星淡，南飞乌鹊，暗数秋期天上。',68,'宋词/ci.song.4000.json','["月胧星淡，南飞乌鹊，暗数秋期天上。", "锦楼不到野人家，但门外、清流叠嶂。", "一杯相属，佳人何在，不见绕粱清唱。", "人间平地亦崎岖，叹银汉、何曾风浪。"]'),
('song-ci-957','菩萨蛮','谢薖','宋','宋词','song-ci','菩萨蛮','[]','雪消新洗寒林碧。',52,'宋词/ci.song.4000.json','["雪消新洗寒林碧。", "华堂向晚开瑶席。", "一曲杜韦娘。", "有人空断肠。", "谪仙同夜宴。", "晓即归程远。", "莫放酒尊空。", "主人陈孟公。"]'),
('song-ci-958','菩萨蛮','谢薖','宋','宋词','song-ci','菩萨蛮','[]','相思一夜庭花发。',52,'宋词/ci.song.4000.json','["相思一夜庭花发。", "窗前忽认生尘袜。", "晓起艳寒妆。", "雪肌生暗香。", "佳人纤手摘。", "手与花同色。", "插鬓有谁宜。", "惟应潘玉儿。"]'),
('song-ci-959','生查子','谢薖','宋','宋词','song-ci','生查子','[]','情亲难语离，且尽玻璃盏。',48,'宋词/ci.song.4000.json','["情亲难语离，且尽玻璃盏。", "双鲤有来时，莫使音书缓。", "征骖去若飞，不道家山远。", "相见小冯君，笑语迎归雁。"]'),
('song-ci-960','如梦令','谢薖','宋','宋词','song-ci','如梦令','[]','人似已圆孤月。',40,'宋词/ci.song.4000.json','["人似已圆孤月。", "心似丁香百结。", "不见谪仙人，孤负梅花时节。", "愁绝。", "愁绝。", "江上落英如雪。"]'),
('song-ci-961','浣溪沙','谢薖','宋','宋词','song-ci','浣溪沙','[]','柳絮随风散漫飞。',48,'宋词/ci.song.4000.json','["柳絮随风散漫飞。", "檐冰成柱粟生肌。", "力排寒气赖金卮。", "赋丽谁为梁苑客，调高难和郢中词。", "且烦呵笔写乌丝。"]'),
('song-ci-962','偷声木兰花','谢薖','宋','宋词','song-ci','偷声木兰花','[]','景阳楼上钟声晓。',58,'宋词/ci.song.4000.json','["景阳楼上钟声晓。", "半面啼妆匀未了。", "斜月纷纷。", "斜影幽香暗断魂。", "玉颜应在昭阳殿。", "却向前村深夜见。", "冰雪肌肤。", "还有斑斑雪点无。"]'),
('song-ci-963','醉蓬莱','谢薖','宋','宋词','song-ci','醉蓬莱','[]','望晴峰染黛，暮霭澄空，碧天银汉。',120,'宋词/ci.song.4000.json','["望晴峰染黛，暮霭澄空，碧天银汉。", "圆镜高飞，又一年秋半。", "皓色谁同，归心暗折，听唳云孤雁。", "问月停杯，锦袍何处，一尊无伴。", "好在南邻，诗盟酒社，刻烛争成，引觞愁缓。", "今夕楼中，继阿连清玩。", "饮剧狂歌，歌终起舞，醉冷光凌乱。", "乐事难穷，疏星易晓，又成浩叹。"]'),
('song-ci-964','减字木兰花','谢薖','宋','宋词','song-ci','减字木兰花','[]','江边一树。',52,'宋词/ci.song.4000.json','["江边一树。", "愁绝黄昏谁与度。", "琪树琼枝。", "不受雄蜂取次欺。", "风前望处。", "直恐乘风吹得去。", "能动诗情。", "故与诗人独目成。"]'),
('song-ci-965','减字木兰花','谢薖','宋','宋词','song-ci','减字木兰花','[]','寻常三五。',52,'宋词/ci.song.4000.json','["寻常三五。", "坐待丹山飞玉兔。", "试问常娥。", "底事清光此夜多。", "尊空客满。", "纵有鹔鹴无处换。", "不倒金荷。", "可奈金波潋滟何。"]'),
('song-ci-966','减字木兰花','谢薖','宋','宋词','song-ci','减字木兰花','[]','风篁度曲。',52,'宋词/ci.song.4000.json','["风篁度曲。", "倦倚银屏初睡足。", "清簟疏帘。", "金鸭香销懒更添。", "纤纤露玉。", "风雹纵横飞钿局。", "颦敛双蛾。", "凝伫无言密意多。"]'),
('song-ci-967','虞美人','谢薖','宋','宋词','song-ci','虞美人','[]','金钗尽醉何须伴。',66,'宋词/ci.song.4000.json','["金钗尽醉何须伴。", "萸糁浮杯乱。", "黄花香返岭梅魂。", "好把一枝斜插、向乌云。", "坡词欲唱无人会。", "桃叶知何在。", "与君同咏一联诗。", "但道老来能趁、菊花时。"]'),
('song-ci-968','虞美人','谢薖','宋','宋词','song-ci','虞美人','[]','人间离合常相半。',66,'宋词/ci.song.4000.json','["人间离合常相半。", "璧月宁长满。", "九秋风露又方阑。", "何日小窗相对、话悲欢。", "月华临夜宜人醉。", "老去嗟颜悴。", "君如玉树照清空。", "况有凝之道蕴、一尊同。"]'),
('song-ci-969','蝶恋花','谢薖','宋','宋词','song-ci','蝶恋花','[]','一水盈盈牛与女。',70,'宋词/ci.song.4000.json','["一水盈盈牛与女。", "目送经年，脉脉无由语。", "后夜鹊桥知暗度。", "持杯乞与开愁绪。", "君似庾郎愁几许。", "万斛愁生，更作征人去。", "留定征鞍君且住。", "人间岂有无愁处。"]'),
('song-ci-970','定风波','谢薖','宋','宋词','song-ci','定风波','[]','牛女心期与目成。',73,'宋词/ci.song.4000.json','["牛女心期与目成。", "弥弥脉脉得盈盈。", "今夕银河凭鹊度。", "相遇。", "玉钩新吐照云屏。", "行旆雍容留宴语。", "将暮。", "方携珠袖到山亭。", "寂寞江天正云雾。", "回顾。", "不应中有少微星。"]'),
('song-ci-971','江神子・江城子','谢薖','宋','宋词','song-ci','江神子・江城子','[]','破瓜年纪柳腰身。',86,'宋词/ci.song.4000.json','["破瓜年纪柳腰身。", "懒精神。", "带羞瞋。", "手把江梅，冰雪斗清新。", "不向鸦儿飞处著。", "留乞与，眼中人。", "水精船里酒粼粼。", "皱香茵。", "驻行云。", "舞罢歌馀，花困不胜春。", "问著些儿心底事，才靥笑，又眉颦。"]'),
('song-ci-972','念奴娇','谢薖','宋','宋词','song-ci','念奴娇','[]','绿云影里，把明霞、织就千重文绣。',120,'宋词/ci.song.4000.json','["绿云影里，把明霞、织就千重文绣。", "紫腻红骄扶不起，好是未开时候。", "半怯新寒，半宜晴色，养得胭脂透。", "小亭人静。", "嫩莺啼破清昼。", "犹记携手芳阴，一枝斜带艳，娇波双秀。", "小语轻怜花总见，争得似花长久。", "醉浅休归，夜深同睡，明月还相守。", "免叫春去，断肠空叹诗瘦。"]'),
('song-ci-973','满庭芳','沈蔚','宋','宋词','song-ci','满庭芳','[]','柳与堤回，桥随波转，望中如在蓬莱。',118,'宋词/ci.song.4000.json','["柳与堤回，桥随波转，望中如在蓬莱。", "水禽高下，烟雾敛还开。", "认是仙翁住处，都不见、一点尘埃。", "壶天晚，清寒带雪，光景自徘徊。", "高才。", "廊庙手，当年平步，直到尧阶。", "况今朝调鼎，尤待盐梅。", "只恐身闲不久，难留恋、花月楼台。", "看新岁，春风且送，五马过江来。"]'),
('song-ci-974','满庭芳','沈蔚','宋','宋词','song-ci','满庭芳','[]','雪底寻梅，冰痕观水，晚来天气尤寒。',118,'宋词/ci.song.4000.json','["雪底寻梅，冰痕观水，晚来天气尤寒。", "渐闻歌笑，轻暖发春妍。", "赏尽十洲新景，依稀见、三岛风烟。", "判深夜，一年月色，只是这般圆。", "熙然。", "千里地，何妨载酒，频上湖船。", "况坐中高客，不日朝天。", "须信人间好处，没个事、胜得尊前。", "东风近，侵寻桃李，别做醉夤缘。"]'),
('song-ci-975','满庭芳','沈蔚','宋','宋词','song-ci','满庭芳','[]','疏木藏钟，轻烟笼角，几家帘幕灯光。',118,'宋词/ci.song.4000.json','["疏木藏钟，轻烟笼角，几家帘幕灯光。", "暮砧声断，空壁锁寒蜇。", "入袂西风阵阵，彻醉骨、都不胜凉。", "栏干外，依稀嫩竹，月色冷如霜。", "仙乡。", "何处是，云深路杳，不念刘郎。", "但画桥流水，依旧垂杨。", "要见时时便是，一向价、只作寻常。", "争知道，愁肠泪眼，独自个重阳。"]'),
('song-ci-976','临江仙','沈蔚','宋','宋词','song-ci','临江仙','[]','过尽清明三月雨，东风才到溪滨。',70,'宋词/ci.song.4000.json','["过尽清明三月雨，东风才到溪滨。", "画工传得已非真。", "青君著意处，桃李未为伦。", "倚槛盈盈如欲语，就中拈足花神。", "自然亭馆一番新。", "从今观绝品，不独洛阳人。"]'),
('song-ci-977','梦玉人引','沈蔚','宋','宋词','song-ci','梦玉人引','[]','旧追游处，思前事、俨如昔。',104,'宋词/ci.song.4000.json','["旧追游处，思前事、俨如昔。", "过尽莺花，横雨暴风初息。", "杏子枝头，又自然、别是般天色。", "好傍垂杨，系画船桥侧。", "小欢幽会，一霎时、光景也堪惜。", "对酒当歌，故人情分难觅。", "水远山长，不成空相忆。", "这归去重来，又却是、几时来得。"]'),
('song-ci-978','蓦山溪','沈蔚','宋','宋词','song-ci','蓦山溪','[]','想伊不住。',102,'宋词/ci.song.4000.json','["想伊不住。", "船在蓝桥路。", "别语未甘听，更拟问、而今是去。", "门前杨柳，几日转西风，将行色，欲留心，忽忽城头鼓。", "一番幽会，只觉添愁绪。", "邂逅却相逢。", "又还有、此时欢否。", "临岐把酒，莫惜十分斟，尊前月，月中人，明夜知何处。"]'),
('song-ci-979','汉宫春','沈蔚','宋','宋词','song-ci','汉宫春','[]','别酒初醒。',118,'宋词/ci.song.4000.json','["别酒初醒。", "似一番梦觉，屈指堪惊。", "犹疑送消寄息，遇著人听。", "当初唤作，据眼前、略略看承。", "及去了，从头想伊，心下始觉宁宁。", "黄昏画角重城。", "更伤高念远，怀抱何胜。", "良时好景，算来半为愁生。", "幽期暂阻，便就中、月白风清。", "千万计，年年断除不得，是这些情。"]'),
('song-ci-980','寻梅','沈蔚','宋','宋词','song-ci','寻梅','[]','今年早觉花信蹉。',72,'宋词/ci.song.4000.json','["今年早觉花信蹉。", "想芳心、未应误我。", "一月小径几回过。", "始朝来寻见，雪痕微破。", "眼前大抵情无那。", "好景色、只消些个。", "春风烂熳却且可。", "是而今、枝上一朵两朵。"]'),
('song-ci-981','不见・如梦令','沈蔚','宋','宋词','song-ci','不见・如梦令','[]','日过重帘未卷。',40,'宋词/ci.song.4000.json','["日过重帘未卷。", "袅袅欲残香线。", "午醉却醒来，柳外一声莺啭。", "不见。", "不见。", "门掩落花深院。"]'),
('song-ci-982','不见・如梦令','沈蔚','宋','宋词','song-ci','不见・如梦令','[]','回首芜城旧苑。',40,'宋词/ci.song.4000.json','["回首芜城旧苑。", "还是绿深红浅。", "春意已无多，斜日满帘飞燕。", "不见。", "不见。", "花上雨来风转。"]'),
('song-ci-983','诉衷情','沈蔚','宋','宋词','song-ci','诉衷情','[]','深深院宇小池塘。',54,'宋词/ci.song.4000.json','["深深院宇小池塘。", "一径碧梧长。", "青春又归何处，新笋绿成行。", "多少事，恼人肠。", "懒思量。", "香消一炷，睡起霎时，日过东窗。"]'),
('song-ci-984','菩萨・菩萨蛮','沈蔚','宋','宋词','song-ci','菩萨・菩萨蛮','[]','相逢无处无尊酒。',52,'宋词/ci.song.4000.json','["相逢无处无尊酒。", "尊前未必皆朋旧。", "酒到任教倾。", "莫思今夜醒。", "明朝相别后。", "江上空回首。", "欲去不胜情。", "为君歌数声。"]'),
('song-ci-985','菩萨・菩萨蛮','沈蔚','宋','宋词','song-ci','菩萨・菩萨蛮','[]','春城迤逦层阴绕。',52,'宋词/ci.song.4000.json','["春城迤逦层阴绕。", "青梅竞弄枝头小。", "江色雨和烟。", "行人江那边。", "好花都过了。", "满地空芳草。", "落日醉醒闲。", "一春无此寒。"]'),
('song-ci-986','小重山','沈蔚','宋','宋词','song-ci','小重山','[]','花过园林清荫浓。',70,'宋词/ci.song.4000.json','["花过园林清荫浓。", "琅玕新脱笋，绿丛丛。", "雨声只在小池东。", "闲敧枕，直面芰荷风。", "长日敞帘栊。", "轻尘飞不到，画堂空。", "一尊今夜与谁同。", "人如玉，相对月明中。"]'),
('song-ci-987','转调蝶恋花・蝶恋花','沈蔚','宋','宋词','song-ci','转调蝶恋花・蝶恋花','[]','溪上清明初过雨。',70,'宋词/ci.song.4000.json','["溪上清明初过雨。", "春色无多，叶底花如许。", "轻暖时闻燕双语。", "等闲飞入谁家去。", "短墙东畔新朱户。", "前日花前，把酒人何处。", "仿佛桥边船上路。", "绿杨风里黄昏鼓。"]'),
('song-ci-988','转调蝶恋花・蝶恋花','沈蔚','宋','宋词','song-ci','转调蝶恋花・蝶恋花','[]','渐近朱门香夹道。',70,'宋词/ci.song.4000.json','["渐近朱门香夹道。", "一片笙歌，依约楼台杪。", "野色和烟满芳草。", "溪光曲曲山回抱。", "物华不逐人间老。", "日日春风，在处花枝好。", "莫恨云深路难到。", "刘郎可惜归来早。"]'),
('song-ci-989','天仙子','沈蔚','宋','宋词','song-ci','天仙子','[]','景物因人成胜概。',80,'宋词/ci.song.4000.json','["景物因人成胜概。", "满目更无尘可碍。", "等闲帘幕小栏干，衣未解。", "心先快。", "明月清风如有待。", "谁信门前车马隘。", "别是人间闲世界。", "坐中无物不清凉，山一带。", "水一派。", "流水白云长自在。"]'),
('song-ci-990','倾杯・倾杯乐','沈蔚','宋','宋词','song-ci','倾杯・倾杯乐','[]','梅英弄粉。',136,'宋词/ci.song.4000.json','["梅英弄粉。", "尚浅寒、腊雪消未尽。", "布彩箔、层楼高下，灯火万点，金莲相照映。", "香径纵横，听画鼓、声声随步紧。", "渐霄汉无云，月华如水，夜久露清风迅。", "轻车趁马，微尘杂雾，带晓色、绮罗生润。", "花阴下、瞥见仍回，但时闻、笑音中香阵阵。", "奈酒阑人困。", "残漏里、年年馀恨。", "归来沈醉何处，一片笙歌又近。"]'),
('song-ci-991','清商怨','沈蔚','宋','宋词','song-ci','清商怨','[]','城上鸦啼斗转。',53,'宋词/ci.song.4000.json','["城上鸦啼斗转。", "渐渐玉壶冰满。", "月淡寒梅，清香来小院。", "谁遣鸾笺写怨。", "翻锦字、叠叠如愁卷。", "梦破胡笳，江南烟树远。"]'),
('song-ci-992','醉花阴','沈蔚','宋','宋词','song-ci','醉花阴','[]','微含清露真珠滴。',62,'宋词/ci.song.4000.json','["微含清露真珠滴。", "怯晓寒脉脉。", "秉烛倚雕栏，今日尊前，尽是多情客。", "从来应与春相得。", "有动人标格。", "半笑倚春风，醉脸生红，不是胭脂色。"]'),
('song-ci-993','柳摇金・思归乐','沈蔚','宋','宋词','song-ci','柳摇金・思归乐','[]','相将初下蕊珠殿。',68,'宋词/ci.song.4000.json','["相将初下蕊珠殿。", "似醉粉、生香未遍。", "爱惜娇心春不管。", "被东风、赚开一半。", "中黄宫里赐仙衣，斗浅深、妆成笑面。", "放出妖娆难系管。", "笑东君、自家肠断。"]'),
('song-ci-994','柳初新','沈蔚','宋','宋词','song-ci','柳初新','[]','楚天来驾春相送。',100,'宋词/ci.song.4000.json','["楚天来驾春相送。", "半醉侧、花冠重。", "瑶台清宴，群仙戏手，剪出彩衣犹动。", "谁拂瑶琴巧弄。", "舞丹山、三千雏凤。", "艳冶轻盈放纵。", "倚东风、从来遍宠。", "桃花溪上，相思未断，愁掩五云真洞。", "算曾揖、飞鸾双控。", "等闲入、襄王春梦。"]'),
('song-ci-995','诉衷情','唐庚','宋','宋词','song-ci','诉衷情','[]','平生不会敛眉头。',54,'宋词/ci.song.4000.json','["平生不会敛眉头。", "诸事等闲休。", "元来却到愁处，须著与他愁。", "残照外，大江流。", "去悠悠。", "风悲兰杜，烟淡沧浪，何处扁舟。"]'),
('song-ci-996','浣溪沙','惠洪','宋','宋词','song-ci','浣溪沙','[]','南涧茶香笑语新。',48,'宋词/ci.song.4000.json','["南涧茶香笑语新。", "西州春涨小舟横。", "困顿人归烂熳晴。", "天迥游丝长百尺，日高飞絮满重城。", "一番花信近清明。"]'),
('song-ci-997','浣溪沙','惠洪','宋','宋词','song-ci','浣溪沙','[]','日暮江空船自流。',48,'宋词/ci.song.4000.json','["日暮江空船自流。", "谁家院落近沧洲。", "一枝闲暇出墙头。", "数朵幽香和月暗，十分归意为春留。", "风撩片片是闲愁。"]'),
('song-ci-998','渔父词・渔父','惠洪','宋','宋词','song-ci','渔父词・渔父','[]','玉带云袍童顶露。',72,'宋词/ci.song.4000.json','["玉带云袍童顶露。", "一生笑傲知何故。", "万里归来方旦暮。", "休疑虑。", "大千捏在豪端聚。", "不解犁田分亩步。", "却能对客鸣花鼓。", "忽共老安相耳语。", "还推去。", "莫来拦我球门路。"]'),
('song-ci-999','渔父词・渔父','惠洪','宋','宋词','song-ci','渔父词・渔父','[]','不怕石头行路滑。',72,'宋词/ci.song.4000.json','["不怕石头行路滑。", "归来那爱驹儿踏。", "言下百骸俱拨撒。", "无剩法。", "灵然昼夜光通达。", "古寺天寒还恶发。", "夜将木佛齐烧杀。", "炙背横眠真快活。", "憨抹挞。", "从教院主无须发。"]'),
('song-ci-0','渔父词・渔父','惠洪','宋','宋词','song-ci','渔父词・渔父','[]','来往独龙冈畔路。',72,'宋词/ci.song.5000.json','["来往独龙冈畔路。", "杖头落索闲家具。", "后事前观如目睹。", "非谶语。", "须知一念无今古。", "长笑老萧多病苦。", "笑中与药皆狼虎。", "蜡炬一枝非嘱付。", "聊戏汝。", "热来脱却娘生裤。"]'),
('song-ci-1','渔父词・渔父','惠洪','宋','宋词','song-ci','渔父词・渔父','[]','画饼充饥人笑汝。',72,'宋词/ci.song.5000.json','["画饼充饥人笑汝。", "一庵归扫南阳坞。", "击竹作声方省悟。", "徐回顾。", "本来面目无藏处。", "却望沩山敷坐具。", "老师头角浑呈露。", "珍重此恩逾父母。", "须荐取。", "堂堂密密声前句。"]'),
('song-ci-2','渔父词・渔父','惠洪','宋','宋词','song-ci','渔父词・渔父','[]','野鹤精神云格调。',72,'宋词/ci.song.5000.json','["野鹤精神云格调。", "逼人气韵霜天晓。", "松下残经看未了。", "当斜照。", "苍烟风撼流泉绕。", "闺阁珍奇徒照耀。", "光无渗漏方灵妙。", "活计现成谁管绍。", "孤峰表。", "一声月下闻清啸。"]'),
('song-ci-3','渔父词・渔父','惠洪','宋','宋词','song-ci','渔父词・渔父','[]','讲虎天华随玉麈。',72,'宋词/ci.song.5000.json','["讲虎天华随玉麈。", "波心月在那能取。", "旁舍老僧偷指注。", "回头觑。", "虚空特地能言语。", "归对学徒重自诉。", "从前见解都欺汝。", "隔岸有山横暮雨。", "翻然去。", "千岩万壑无寻处。"]'),
('song-ci-4','渔父词・渔父','惠洪','宋','宋词','song-ci','渔父词・渔父','[]','急雨颠风花信早。',72,'宋词/ci.song.5000.json','["急雨颠风花信早。", "枝枝叶叶春俱到。", "何待小桃方悟道。", "休迷倒。", "出门无限青青草。", "根不覆藏尘亦扫。", "见精明树唯心造。", "试借疑情看白皂。", "回头讨。", "灵云笑杀玄沙老。"]'),
('song-ci-5','渔父词・渔父','惠洪','宋','宋词','song-ci','渔父词・渔父','[]','万叠空青春杳杳。',72,'宋词/ci.song.5000.json','["万叠空青春杳杳。", "一蓑烟雨吴江晓。", "醉眼忽醒惊白鸟。", "拍手笑。", "清波不犯鱼吞钓。", "津渡有僧求法要。", "一桡为汝除玄妙。", "已去回头知不峭。", "犹迷照。", "渔舟性懆都翻了。"]'),
('song-ci-6','凤栖梧・蝶恋花','惠洪','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','碧瓦笼晴烟雾绕。',70,'宋词/ci.song.5000.json','["碧瓦笼晴烟雾绕。", "水殿西偏，小立闻啼鸟。", "风度女墙吹语笑。", "南枝破腊应开了。", "道骨不凡江瘴晓。", "春色通灵，医得花重少。", "爆暖酿寒空杳杳。", "江城画角催残照。"]'),
('song-ci-7','千秋岁','惠洪','宋','宋词','song-ci','千秋岁','[]','半身屏外。',87,'宋词/ci.song.5000.json','["半身屏外。", "睡觉唇红退。", "春思乱，芳心碎。", "空馀簪髻玉，不见流苏带。", "试与问，今人秀整谁宜对。", "湘浦曾同会。", "手搴轻罗盖。", "疑是梦，今犹在。", "十分春易尽，一点情难改。", "多少事，却随恨远连云海。"]'),
('song-ci-8','青玉案','惠洪','宋','宋词','song-ci','青玉案','[]','绿槐烟柳长亭路。',80,'宋词/ci.song.5000.json','["绿槐烟柳长亭路。", "恨取次、分离去。", "日永如年愁难度。", "高城回首，暮云遮尽，目断人何处。", "解鞍旅舍天将暮。", "暗忆丁宁千万句。", "一寸柔肠情几许。", "薄衾孤枕，梦回人静，彻晓潇潇雨。"]'),
('song-ci-9','西江月','惠洪','宋','宋词','song-ci','西江月','[]','十指嫩抽春笋，纤纤玉软红柔。',58,'宋词/ci.song.5000.json','["十指嫩抽春笋，纤纤玉软红柔。", "人前欲展强娇羞。", "微露云衣霓袖。", "最好洞天春晚，黄庭卷罢清幽。", "凡心无计奈闲愁。", "试拈花枝频嗅。"]'),
('song-ci-10','西江月','惠洪','宋','宋词','song-ci','西江月','[]','大厦吞风吐月，小舟坐水眠空。',58,'宋词/ci.song.5000.json','["大厦吞风吐月，小舟坐水眠空。", "雾窗春晓翠如葱。", "睡起云涛正涌。", "往事回头笑处，此生弹指声中。", "玉笺佳句敏惊鸿。", "闻道衡阳价重。"]'),
('song-ci-11','鹧鸪天','惠洪','宋','宋词','song-ci','鹧鸪天','[]','蜜烛花光清夜阑。',64,'宋词/ci.song.5000.json','["蜜烛花光清夜阑。", "粉衣香翅绕团团。", "人犹认假为真实，蛾岂将灯作火看。", "方叹息，为遮拦。", "也知爱处实难拚。", "忽然性命随烟焰，始觉从前被眼瞒。"]'),
('song-ci-12','清商怨','惠洪','宋','宋词','song-ci','清商怨','[]','一段文章种性。',52,'宋词/ci.song.5000.json','["一段文章种性。", "更谪仙风韵。", "画戟丛中，清香凝宴寝。", "落日清寒勒花信。", "愁似海、洗光词锦。", "后夜归舟，云涛喧醉枕。"]'),
('song-ci-13','青玉案','惠洪','宋','宋词','song-ci','青玉案','[]','凝祥宴罢闻歌吹。',81,'宋词/ci.song.5000.json','["凝祥宴罢闻歌吹。", "画毂走，香尘起。", "冠压花枝驰万骑。", "马行灯闹，凤楼帘卷，陆海龙鳌山对。", "当年曾看天颜醉。", "御杯举，欢声沸。", "时节虽同悲乐异。", "海风吹梦，岭猿啼月，一枕思归泪。"]'),
('song-ci-14','西江月','惠洪','宋','宋词','song-ci','西江月','[]','入骨风流国色，透尘种性真香。',58,'宋词/ci.song.5000.json','["入骨风流国色，透尘种性真香。", "为谁风鬓涴新妆。", "半树入村春暗。", "雪压枝低篱落，月高影动池塘。", "高情数笔寄微茫。", "小寝初开雾帐。"]'),
('song-ci-15','浪淘沙','惠洪','宋','宋词','song-ci','浪淘沙','[]','城里久偷闲。',64,'宋词/ci.song.5000.json','["城里久偷闲。", "尘浣云衫。", "此身已是再眠蚕。", "隔岸有山归去好，万壑千岩。", "霜晓更凭阑。", "减尽晴岚。", "微云生处是茅庵。", "试问此生谁作伴，弥勒同龛。"]'),
('song-ci-16','浪淘沙','惠洪','宋','宋词','song-ci','浪淘沙','[]','山径晚樵远。',64,'宋词/ci.song.5000.json','["山径晚樵远。", "深壑孱颜。", "孙山背后泊船看。", "手把遗编披白帔，剩却清闲。", "篱落竹丛寒。", "渔业凋残。", "水痕无底照秋宽。", "好在夕阳凝睇处，数笔秋山。"]'),
('song-ci-17','水调歌头','吕颐浩','宋','宋词','song-ci','水调歌头','[]','一片苍崖璞，孕秀自天锺。',114,'宋词/ci.song.5000.json','["一片苍崖璞，孕秀自天锺。", "浑如暖烟堆里，乍放力犹慵。", "疑是犀眠海畔，贪玩烂银光彩，精魄入蟾宫。", "泼墨阴云妒，蟾影淡朦胧。", "沩山颂，戴生笔，写难穷。", "些儿造化，凭谁细与问元工。", "那用牧童鞭索，不入千群万队，扣角起雷同。", "莫怪作诗手，偷入锦囊中。"]'),
('song-ci-18','点绛唇','苏过','宋','宋词','song-ci','点绛唇','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','新月娟娟，夜寒江静山衔斗。',50,'宋词/ci.song.5000.json','["新月娟娟，夜寒江静山衔斗。", "起来搔首。", "梅影横窗瘦。", "好个霜天，闲却传杯手。", "君知否。", "乱鸦啼后。", "归兴浓如酒。"]'),
('song-ci-19','感皇恩','陆蕴','宋','宋词','song-ci','感皇恩','[]','残角两三声，催登古道。',81,'宋词/ci.song.5000.json','["残角两三声，催登古道。", "远水长山又重到。", "水声山色，看尽轮蹄昏晓。", "风头日脚下，人空老。", "匹马旧时，西征谈笑。", "绿鬓朱颜正年少。", "旗亭斗酒，任是十千倾倒。", "面今酒兴减，诗情少。"]'),
('song-ci-20','忆君王・忆王孙','谢克家','宋','宋词','song-ci','忆君王・忆王孙','[]','依依宫柳拂宫墙。',36,'宋词/ci.song.5000.json','["依依宫柳拂宫墙。", "楼殿无人春昼长。", "燕子归来依旧忙。", "忆君王。", "月破黄昏人断肠。"]'),
('song-ci-21','江神子・江城子','葛胜仲','宋','宋词','song-ci','江神子・江城子','[]','昏昏雪意惨云容。',86,'宋词/ci.song.5000.json','["昏昏雪意惨云容。", "猎霜风。", "岁将穷。", "流落天涯，憔悴一衰翁。", "清夜小窗围兽火，倾酒绿，借颜红。", "官梅疏艳小壶中。", "暗香浓。", "玉玲珑。", "对景忽惊，身在大江东。", "上国故人谁念我，晴嶂远，暮云重。"]'),
('song-ci-22','蝶恋花','葛胜仲','宋','宋词','song-ci','蝶恋花','[]','雨后春光浓似醉。',70,'宋词/ci.song.5000.json','["雨后春光浓似醉。", "著柳催花，节物侵龙忌。", "绣褓香阁当日佩。", "紫兰宫堕人间世。", "歌管停云香吐穗。", "碧酒红裳，共祝鱼轩贵。", "天上阿环金箓秘。", "龟龄鹤寿三千岁。"]'),
('song-ci-23','蝶恋花','葛胜仲','宋','宋词','song-ci','蝶恋花','[]','共乐堂深帘不卷。',70,'宋词/ci.song.5000.json','["共乐堂深帘不卷。", "恻恻寒轻，二月春犹浅。", "续寿竞来歌舞院。", "龙涎香衬鲛绡段。", "画栋朝飞双语燕。", "端似知人，著意窥金盏。", "柳外花前同祝愿。", "朱颜长在年龄远。"]'),
('song-ci-24','临江仙','葛胜仲','宋','宋词','song-ci','临江仙','[]','郊外黄垓端可厌，归来移病香闺。',70,'宋词/ci.song.5000.json','["郊外黄垓端可厌，归来移病香闺。", "象床珍簟共委蛇。", "耆婆寻草尽，天女散花迟。", "小雨作寒秋意晚。", "檐声与梦相宜。", "冷侵罗幌酒烟微。", "试评书五朵，何似画双眉。"]'),
('song-ci-25','渔家傲','葛胜仲','宋','宋词','song-ci','渔家傲','[]','岩壑萦回云水窟。',72,'宋词/ci.song.5000.json','["岩壑萦回云水窟。", "林深路断迷烟客。", "茅屋数椽携杖舄。", "人寂寂。", "侵檐万个琅玕碧。", "倦客羁怀清似涤。", "更无一点飞埃迹。", "溪涨慢流过几席。", "寒湜湜。", "凫鷖点破琉璃色。"]'),
('song-ci-26','渔家傲','葛胜仲','宋','宋词','song-ci','渔家傲','[]','叠叠云山供四顾。',72,'宋词/ci.song.5000.json','["叠叠云山供四顾。", "簿书忙里偷闲去。", "心远地偏陶令趣。", "登览处。", "清幽疑是斜川路。", "野蔌溪毛供饮具。", "此身甘被烟霞痼。", "兴尽碧云催日暮。", "招晚渡。", "遥遥一叶随鸥鹭。"]'),
('song-ci-27','鹧鸪天','葛胜仲','宋','宋词','song-ci','鹧鸪天','[]','小榭幽园翠箔垂。',64,'宋词/ci.song.5000.json','["小榭幽园翠箔垂。", "云轻日薄淡秋晖。", "菊英露浥渊明径，藕叶风吹叔宝池。", "酬素景，泥芳卮。", "老人痴钝强伸眉。", "欢华莫遣笙歌散，归路从教灯影稀。"]'),
('song-ci-28','鹧鸪天','葛胜仲','宋','宋词','song-ci','鹧鸪天','[]','婆律香深气味佳。',64,'宋词/ci.song.5000.json','["婆律香深气味佳。", "玻璃仙碗进流霞。", "凝膏清涤高阳醉，灵液甘和正焙芽。", "香染指，浪浮花。", "加笾礼尽客还家。", "贯珠声断红裳散，踏影人归素月斜。"]'),
('song-ci-29','点绛唇','葛胜仲','宋','宋词','song-ci','点绛唇','[]','秋晚寒斋，藜床香篆横轻雾。',50,'宋词/ci.song.5000.json','["秋晚寒斋，藜床香篆横轻雾。", "闲愁几许。", "梦逐芭蕉雨。", "云外哀鸿，似替幽人语。", "归不去。", "乱山无数。", "斜日荒城鼓。"]'),
('song-ci-30','行香子','葛胜仲','宋','宋词','song-ci','行香子','[]','风物飕飕。',84,'宋词/ci.song.5000.json','["风物飕飕。", "木落沧洲。", "渐老人、不奈悲秋。", "羁怀都在，鬓上眉头。", "似休文瘦，文通恨，子山愁。", "庭梧影薄，篱菊香浮。", "强招寻、聊命朋俦。", "穷通皆梦，今古如流。", "且渊明径，子猷舫，仲宣楼。"]'),
('song-ci-31','诉衷情','葛胜仲','宋','宋词','song-ci','诉衷情','[]','清明寒食景暄妍。',54,'宋词/ci.song.5000.json','["清明寒食景暄妍。", "花映碧罗天。", "参差捍拨齐奏，丰颊拥芳筵。", "逢诞日，揖真仙。", "托炉烟。", "朱颜长似，头上花枝，岁岁年年。"]'),
('song-ci-32','水调歌头','葛胜仲','宋','宋词','song-ci','水调歌头','[]','夜泛南溪月，光影冷涵空。',114,'宋词/ci.song.5000.json','["夜泛南溪月，光影冷涵空。", "棹飞穿碎金电，翻动水精宫。", "横管何妨三弄，重醑仍须一斗，知费几青铜。", "坐久桂花落，襟袖觉香浓。", "庾公阁，子猷舫，兴应同。", "从来好景良夜，我辈敢情锺。", "但恐仙娥川后，嫌我尘容俗状，清境不相容。", "击汰同情赏，赖有紫溪翁。"]'),
('song-ci-33','水调歌头','葛胜仲','宋','宋词','song-ci','水调歌头','[]','下濑惊船驶，挥麈恐尊空。',114,'宋词/ci.song.5000.json','["下濑惊船驶，挥麈恐尊空。", "谁吹尺八寥亮，嚼徵更含宫。", "坐爱金波潋滟，影落蒲萄涨绿，夜漏尽移铜。", "回棹携红袖，一水带香浓。", "坐中客，驰隽辩，语无同。", "青鞋黄帽，此乐谁肯换千锺。", "岩壑从来无主，风月故应长在，赏不待先容。", "羽化寻烟客，家有左仙翁。"]'),
('song-ci-34','水调歌头','葛胜仲','宋','宋词','song-ci','水调歌头','[]','胜友欣倾盖，羁宦懒书空。',114,'宋词/ci.song.5000.json','["胜友欣倾盖，羁宦懒书空。", "爱君笔力清壮，名已在蟾宫。", "萧散英姿直上，自有练裙葛帔，岂待半通铜。", "长短作新语，墨纸似鸦浓。", "山吐月，溪泛艇，率君同。", "吾侪轰饮文字，乐不在歌锺。", "今夜长风万里，且倩泓澄浩荡，一为洗尘容。", "世上闲荣辱，都付寒边翁。"]'),
('song-ci-35','木兰花・玉楼春','葛胜仲','宋','宋词','song-ci','木兰花・玉楼春','[]','木阑干外池光阔。',64,'宋词/ci.song.5000.json','["木阑干外池光阔。", "午夜乔林迷岸樾。", "掠船凉吹起青苹，萦水歌声欺白雪。", "檀郎响趁红牙节。", "胡语嘈嘈仍切切。", "人生何乐似同襟，莫待骊驹声惨咽。"]'),
('song-ci-36','满庭霜・满庭芳','葛胜仲','宋','宋词','song-ci','满庭霜・满庭芳','[]','百不为多，一不为少，阿谁昔仕吾邦。',118,'宋词/ci.song.5000.json','["百不为多，一不为少，阿谁昔仕吾邦。", "共推任笔，洪鼎力能扛。", "不为桃花禄米，雠书倦、一苇横江。", "招寻处，徒行曳杖，曾不拥麾幢。", "山川，真大好，鱼矶无恙，密岭难双。", "听讼诉多就，樵坞僧窗。", "岁月音容远矣，风流在、遐想心降。", "云烟路，搜奇吊古，时为酹空缸。"]'),
('song-ci-37','醉蓬莱','葛胜仲','宋','宋词','song-ci','醉蓬莱','[]','望葱葱佳气，虹渚祥开，斗枢光绕。',120,'宋词/ci.song.5000.json','["望葱葱佳气，虹渚祥开，斗枢光绕。", "析木天津，正灵晖腾照。", "鹭缀分班，象胥交贡，奉御觞清晓。", "玉殿寒轻，金徒漏永，瑞炉烟袅。", "万宇均欢，示慈颁燕，寿祝南山，庆均凫藻。", "缥缈红云，望九重天表。", "舞兽锵洋，抃鳌欣戴，度管弦声杳。", "历草长新，蟠桃永秀，与天难老。"]'),
('song-ci-38','西江月','葛胜仲','宋','宋词','song-ci','西江月','[]','羁宦新来作恶，穷途谁肯相从。',58,'宋词/ci.song.5000.json','["羁宦新来作恶，穷途谁肯相从。", "追攀十日水云中。", "情谊知君独重。", "寂寂回廊小院，冥冥细雨尖风。", "凤山香雪定应空。", "昨夜疏枝入梦。"]'),
('song-ci-39','西江月','葛胜仲','宋','宋词','song-ci','西江月','[]','山镇红桃阡陌，烟迷绿水人家。',58,'宋词/ci.song.5000.json','["山镇红桃阡陌，烟迷绿水人家。", "尘容误到只惊嗟。", "骨冷玉堂今夜。", "莫对佳人锦瑟，休辞洞府流霞。", "峰回路转乱云遮。", "归去空传图画。"]'),
('song-ci-40','南乡子','葛胜仲','宋','宋词','song-ci','南乡子','[]','柳岸正飞绵。',66,'宋词/ci.song.5000.json','["柳岸正飞绵。", "选胜斋轻漾碧涟。", "笑语忘怀机事尽，鸥边。", "万顷溪光上下天。", "菰苇久延缘。", "不觉遥峰霭暮烟。", "对酒莫嫌红粉陋，婵娟。", "自有孤高月妇仙。"]'),
('song-ci-41','浣溪沙','葛胜仲','宋','宋词','song-ci','浣溪沙','[]','可惜随风面旋飘。',48,'宋词/ci.song.5000.json','["可惜随风面旋飘。", "直须烧烛看娇娆。", "人间花月更无妖。", "浓丽独将春色殿，繁华端合众芳朝。", "南床应为醉陶陶。"]'),
('song-ci-42','浣溪沙','葛胜仲','宋','宋词','song-ci','浣溪沙','[]','通白轻红溢万枝。',48,'宋词/ci.song.5000.json','["通白轻红溢万枝。", "浓香百和透丰肌。", "丹山威凤势将飞。", "玉镜台前呈国艳，沈香亭北映朝曦。", "如花惟有上皇妃。"]'),
('song-ci-43','浣溪沙','葛胜仲','宋','宋词','song-ci','浣溪沙','[]','斗鸭栏边晓路沾。',48,'宋词/ci.song.5000.json','["斗鸭栏边晓路沾。", "华堂醉赏轴珠帘。", "插花人好手纤纤。", "遮护轻寒施翠幄，标题仙品露牙签。", "词人遗恨独江淹。"]'),
('song-ci-44','西江月','葛胜仲','宋','宋词','song-ci','西江月','[]','山外半规残日，云边一缕馀霞。',58,'宋词/ci.song.5000.json','["山外半规残日，云边一缕馀霞。", "满城飞雪散苕花。", "万顷溪连罨画。", "柳恽风流旧国，鹤龄潇洒人家。", "肯嗟流落在天涯。", "云水从今起价。"]'),
('song-ci-45','西江月','葛胜仲','宋','宋词','song-ci','西江月','[]','晚路交游绿酒，平生志趣青霞。',58,'宋词/ci.song.5000.json','["晚路交游绿酒，平生志趣青霞。", "霜风时节近黄花。", "泛宅舟将鹢画。", "不分两溪明月，夜深只属渔家。", "今朝清赏寄情涯。", "肯向萦涂索价。"]'),
('song-ci-46','蝶恋花','葛胜仲','宋','宋词','song-ci','蝶恋花','[]','风过涟漪纹縠细。',70,'宋词/ci.song.5000.json','["风过涟漪纹縠细。", "十指香檀，惊破交禽睡。", "野蔌溪毛真易致。", "风流未减兰亭会。", "击汰千艘供洛禊。", "映水垂杨，万缕拖浓翠。", "小海一声波上戏。", "殷勤留客千金意。"]'),
('song-ci-47','临江仙','葛胜仲','宋','宋词','song-ci','临江仙','[]','自古吴兴称冷僻，菰城水浸粼粼。',70,'宋词/ci.song.5000.json','["自古吴兴称冷僻，菰城水浸粼粼。", "回星难望使车尘。", "如何三日饮，并有五行人。", "文似枚皋加敏速，记书易若张巡。", "幕中无用郄嘉宾。", "他年浮枣会，莫忘两溪春。"]'),
('song-ci-48','临江仙','葛胜仲','宋','宋词','song-ci','临江仙','[]','千古乌程新酿美，玉觞风过粼粼。',70,'宋词/ci.song.5000.json','["千古乌程新酿美，玉觞风过粼粼。", "歌声未办起梁尘。", "九天持斧客，来作绣衣人。", "夙有辞华惊乙览，传闻献颂东巡。", "未应握节久宾宾。", "一封驰诏旨，却醉上林春。"]'),
('song-ci-49','临江仙','葛胜仲','宋','宋词','song-ci','临江仙','[]','小样洪河分九曲，飞泉环绕粼粼。',70,'宋词/ci.song.5000.json','["小样洪河分九曲，飞泉环绕粼粼。", "青莲往事已成尘。", "羽觞浮玉甃，宝剑捧金人。", "绿绮且依流水调，蓬蓬釂鼓催巡。", "玉堂词客是佳宾。", "茂林修竹地，大胜永和春。"]'),
('song-ci-50','定风波','葛胜仲','宋','宋词','song-ci','定风波','[]','千叠云山万里流。',73,'宋词/ci.song.5000.json','["千叠云山万里流。", "坐中碧落与鳌头。", "真意见嬉吾已领。", "烟景。", "不辞捧诏久汀洲。", "老去一官真是漫。", "溪岸。", "独馀此兴未能收。", "留与吴儿传胜事。", "长记。", "赤栏桥上揽清秋。"]'),
('song-ci-51','定风波','葛胜仲','宋','宋词','song-ci','定风波','[]','共喜新凉大火流。',73,'宋词/ci.song.5000.json','["共喜新凉大火流。", "一声水调听歌头。", "况有修蛾兼粉领。", "佳景。", "谢公无不碍沦洲。", "平昔短檠真大漫。", "气岸。", "老来都向酒杯收。", "云水光中修禊事。", "犹记。", "转头不觉已三秋。"]'),
('song-ci-52','浣溪沙','葛胜仲','宋','宋词','song-ci','浣溪沙','[]','今夜风光恋渚苹。',48,'宋词/ci.song.5000.json','["今夜风光恋渚苹。", "欲教四角出车轮。", "金钗离立座生春。", "神女恍惊巫峡梦，飞琼原是阆风人。", "诏封后院宠儒臣。"]'),
('song-ci-53','浣溪沙','葛胜仲','宋','宋词','song-ci','浣溪沙','[]','溪岸沈深属泛苹。',48,'宋词/ci.song.5000.json','["溪岸沈深属泛苹。", "倾城容貌此推轮。", "可怜虚度二年春。", "暮暮来时骚客赋，朝朝新处后庭人。", "天留花月伴羁臣。"]'),
('song-ci-54','浣溪沙','葛胜仲','宋','宋词','song-ci','浣溪沙','[]','东道殷勤玉斝飞。',48,'宋词/ci.song.5000.json','["东道殷勤玉斝飞。", "华灯倾国拥珠玑。", "玉奴嫌瘦玉环肥。", "缥缈幸闻缑岭曲。", "参差犹隔夏侯衣。", "放开云月出清辉。"]'),
('song-ci-55','瑞鹧鸪','葛胜仲','宋','宋词','song-ci','瑞鹧鸪','[]','两年人住岂无情。',64,'宋词/ci.song.5000.json','["两年人住岂无情。", "别乘辞华四水清。", "何事千锺勤饮饯，故知一别未能轻。", "解龟虽幸樊笼出，挂席还愁海汐平。", "江草江花都是泪，骊驹休作断肠声。"]'),
('song-ci-56','浪淘沙','葛胜仲','宋','宋词','song-ci','浪淘沙','[]','步屧对东风。',64,'宋词/ci.song.5000.json','["步屧对东风。", "细探春工。", "百花堂下牡丹丛。", "莫恨使君来便去，不见鞓红。", "雾眼一衰翁。", "无意芳秾。", "年来结习已成空。", "寄语国香雕槛里，好为人容。"]'),
('song-ci-57','蓦山溪','葛胜仲','宋','宋词','song-ci','蓦山溪','[]','望云门外。',102,'宋词/ci.song.5000.json','["望云门外。", "油壁如流水。", "空巷逐朱幡，步春风、香河七里。", "冶容炫服，摸石道宜男，穿翠霭，度飞桥，影在清漪里。", "秦头楚尾。", "千古风流地。", "试问汉江边，有解佩、行云旧事。", "主人是客，一笑强颁春，烧灯后，赏花前，遥忆年年醉。"]'),
('song-ci-58','蓦山溪','葛胜仲','宋','宋词','song-ci','蓦山溪','[]','春风野外。',102,'宋词/ci.song.5000.json','["春风野外。", "卵色天如水。", "鱼戏舞绡纹，似出听、新声北里。", "追风骏足，千骑卷高冈，一箭过，万人呼，雁落寒空里。", "天穿过了，此日名穿地。", "横石俯清波。", "竞追随、新年乐事。", "谁怜老子，使得暂遨游，争捧手，乍凭肩，夹道游人醉。"]'),
('song-ci-59','减字木兰花','吴则礼','宋','宋词','song-ci','减字木兰花','[]','团团璧月。',52,'宋词/ci.song.5000.json','["团团璧月。", "今夜广寒真秀发。", "何处吹笙。", "催得清霜满凤城。", "淮南好梦。", "镜里星星还种种。", "犹记银床。", "曾为凉洲唤玉觞。"]'),
('song-ci-60','减字木兰花','吴则礼','宋','宋词','song-ci','减字木兰花','[]','淮天不断。',52,'宋词/ci.song.5000.json','["淮天不断。", "点缀南云秋几雁。", "白露沾衣。", "始是银屏梦觉时。", "别离怀抱。", "消得镜中青鬓老。", "小字无能。", "烦寄平安一纸书。"]'),
('song-ci-61','减字木兰花','吴则礼','宋','宋词','song-ci','减字木兰花','[]','斑斑小雨。',52,'宋词/ci.song.5000.json','["斑斑小雨。", "初入高梧黄叶暮。", "又是重阳。", "昨夜西风作许凉。", "鲜鲜丛菊。", "只解凋人双鬓绿。", "试傍清尊。", "分付幽香与断魂。"]'),
('song-ci-62','减字木兰花','吴则礼','宋','宋词','song-ci','减字木兰花','[]','九年离别。',52,'宋词/ci.song.5000.json','["九年离别。", "梦里相逢端怕说。", "携手河梁。", "雁噭淮天如许长。", "鲈鱼正美。", "白发季鹰聊启齿。", "后夜江干。", "与把梅花子细看。"]'),
('song-ci-63','减字木兰花','吴则礼','宋','宋词','song-ci','减字木兰花','[]','淮山清夜。',52,'宋词/ci.song.5000.json','["淮山清夜。", "镜面平铺纤月挂。", "端是生还。", "同倚西风十二栏。", "休论往事。", "投老相逢真梦寐。", "两鬓疏疏。", "好在松江一尺鲈。"]'),
('song-ci-64','满庭芳','吴则礼','宋','宋词','song-ci','满庭芳','[]','声促铜壶，灰飞玉琯，梦惊偷换年华。',118,'宋词/ci.song.5000.json','["声促铜壶，灰飞玉琯，梦惊偷换年华。", "江南芳信，疏影月横斜。", "又喜椒觞到手，宝胜里、仍翦金花。", "钗头燕，妆台弄粉，梅额故相夸。", "隼旟，人未老，东风袅袅，已傍高牙。", "渐园林月永，叠鼓凝笳。", "小字新传秀句，歌扇底、深把流霞。", "聊行乐，他时画省，归近紫皇家。"]'),
('song-ci-65','满庭芳','吴则礼','宋','宋词','song-ci','满庭芳','[]','玉垒尊罍，清秋关塞，正宜催唤香醪。',118,'宋词/ci.song.5000.json','["玉垒尊罍，清秋关塞，正宜催唤香醪。", "凉风吹帽，横槊试登高。", "相见征西旧事，龙山会、宾主俱豪。", "来群雁，凉生画角，红叶聚亭皋。", "南洲、应好在，长关梦眼，天际云涛。", "有一簪黄菊，两鬓霜毛。", "快把金荷共倒，凝望久、只遣魂消。", "君须听，新翻燕乐，馀韵响檀槽。"]'),
('song-ci-66','木兰花慢','吴则礼','宋','宋词','song-ci','木兰花慢','[]','尽晴春自老，乍翠巘、出清流。',124,'宋词/ci.song.5000.json','["尽晴春自老，乍翠巘、出清流。", "望杳杳飞旌，翩翩戍骑，初过边头。", "幽花尚猗短岸，渐鸣禽、唤友绕行輈。", "端有雕戈锦领，竟驰騕袅骅骝。", "凝眸。", "雁入长天，羌管罢、陇云愁。", "共解鞍临水，雷惊电散，雪溅霜浮。", "玉觞正风味好，对幽香、堕蕊且消忧。", "莫以纶巾羽扇，便忘绿浦沧洲。"]'),
('song-ci-67','醉落魄・一斛珠','吴则礼','宋','宋词','song-ci','醉落魄・一斛珠','[]','梅花褪雪。',67,'宋词/ci.song.5000.json','["梅花褪雪。", "赏心莫使慵欢悦。", "大家且恁同攀折。", "馀蕊残英，偏称淡笼月。", "当初相见花初发。", "如今花谢人离缺。", "一年又比一年别。", "惟有花枝，只似旧时节。"]'),
('song-ci-68','踏莎行','吴则礼','宋','宋词','song-ci','踏莎行','[]','一片花飞，青春已减。',68,'宋词/ci.song.5000.json','["一片花飞，青春已减。", "可堪南陌红千点。", "生憎杨柳要藏鸦，东风只遣横笳怨。", "看定新巢，初怜语燕。", "游丝正把残英罥。", "酒尊也会不相违，风光本自同流转。"]'),
('song-ci-69','鹧鸪天','吴则礼','宋','宋词','song-ci','鹧鸪天','[]','永遇英雄际会时。',64,'宋词/ci.song.5000.json','["永遇英雄际会时。", "垂天鹏翼逐云飞。", "退朝日上青花道，催直霜零赤雁池。", "鸣汉履，侍唐眉。", "渭川莘野晚追随。", "归来仍对金銮老，三峡词源气未衰。"]'),
('song-ci-70','鹧鸪天','吴则礼','宋','宋词','song-ci','鹧鸪天','[]','作赋丁年厌兔园。',64,'宋词/ci.song.5000.json','["作赋丁年厌兔园。", "紫微深锁九重关。", "花墩屡赐清闲燕，文石难忘咫尺颜。", "烟外屐，水边山。", "纶巾羽扇五湖间。", "自怜季子貂裘敝，来与机云相对闲。"]'),
('song-ci-71','鹧鸪天','吴则礼','宋','宋词','song-ci','鹧鸪天','[]','衮绣三朝社稷臣。',64,'宋词/ci.song.5000.json','["衮绣三朝社稷臣。", "旧调元鼎斡洪钧。", "垂绅屡转龙墀日，接膝潜回黼座春。", "金凿落，玉麒麟。", "凤鸣良月庆佳辰。", "巨鳌行听扃华禁，又起商周梦卜人。"]'),
('song-ci-72','红楼慢','吴则礼','宋','宋词','song-ci','红楼慢','[]','声慑燕然，势压横山，镇西名重榆塞。',122,'宋词/ci.song.5000.json','["声慑燕然，势压横山，镇西名重榆塞。", "干霄百雉朱阑下，极目长河如带。", "玉垒凉生过雨，帘卷晴岚凝黛。", "有城头、钟鼓连云，殷春雷天外。", "长啸，畴昔驰边骑。", "听陇底鸣笳，风搴双旆。", "霜髯飞将曾百战，欲掳名王朝帝。", "锦带吴钩未解，谁识凭栏深意。", "空沙场，牧马萧萧晚无际。"]'),
('song-ci-73','声声慢','吴则礼','宋','宋词','song-ci','声声慢','[]','林塘朱夏，雨过斑斑，绿苔绕地初遍。',118,'宋词/ci.song.5000.json','["林塘朱夏，雨过斑斑，绿苔绕地初遍。", "叶底雏莺，犹记日斜春晚。", "芙蕖靓妆红粉，傍高荷、闲倚歌扇。", "轻风起，縠纹滟滟，翠生波面。", "可是追凉月下，清坐久，微云屡遮星汉。", "露湿纶巾，遥望玉清台殿。", "白头共论胜事，须偿五湖深愿。", "南枝好，有南飞乌鹊，绕枝低转。"]'),
('song-ci-74','水龙吟','吴则礼','宋','宋词','song-ci','水龙吟','[]','秋生泽国，无边落木，又作萧萧下。',127,'宋词/ci.song.5000.json','["秋生泽国，无边落木，又作萧萧下。", "澄江过雨，凉飙吹面，黄花初把。", "苍鬓羁孤，粗营鸡黍，浊醪催贳。", "对斜斜露脚，寒香正好，幽人去、空惊咤。", "头上纶巾醉堕，要猗眠、水云萦舍。", "牵衣儿女，归来欢笑，仍邀同社。", "月底蓬门，一株江树，悲虫鸣夜。", "把茱萸细看，牛山底事，强成沾洒。"]'),
('song-ci-75','眼儿媚','李德载','宋','宋词','song-ci','眼儿媚','[]','雪儿魂在水云乡。',58,'宋词/ci.song.5000.json','["雪儿魂在水云乡。", "犹忆学梅妆。", "玻璃枝上，体薰山麝，色带飞霜。", "水边竹外愁多少，不断俗人肠。", "如何伴我，黄昏携手，步月斜廊。"]'),
('song-ci-76','早梅芳近・早梅芳','李德载','宋','宋词','song-ci','早梅芳近・早梅芳','[]','深院静，小阑傍。',57,'宋词/ci.song.5000.json','["深院静，小阑傍。", "标致不寻常。", "尽他桃杏占风光。", "谁敢斗新妆。", "玉堂中，梁苑里。", "休把雪来轻比。", "莫吹长笛巧催残。", "留取月中看。"]'),
('song-ci-77','早梅芳近・早梅芳','李德载','宋','宋词','song-ci','早梅芳近・早梅芳','[]','残腊里，早梅芳。',57,'宋词/ci.song.5000.json','["残腊里，早梅芳。", "春信报新阳。", "晓来枝上斗寒光。", "轻点寿阳妆。", "雪难欺，霜莫妒。", "别是一般风措。", "望林人意正夭饶。", "又看长新条。"]'),
('song-ci-78','鹧鸪天','赵子发','宋','宋词','song-ci','鹧鸪天','[]','约略应飞白玉盘。',64,'宋词/ci.song.5000.json','["约略应飞白玉盘。", "明楼渐放满轮寒。", "天垂万丈清光外，人在三秋爽气间。", "闻叶吹，想风鬟。", "浮空仿佛女乘鸾。", "此时不合人间有，尽入嵩山静夜看。"]'),
('song-ci-79','洞仙歌','赵子发','宋','宋词','song-ci','洞仙歌','[]','荒山明月，下有云来去。',101,'宋词/ci.song.5000.json','["荒山明月，下有云来去。", "深夜纤毫静可数。", "问古今底事，留此空光，修月户、犹是当年玉斧。", "思君持羽扇，来伴微吟，水佩风环饮松露。", "待勾漏丹成，约与轻飞，人间世、不知归处。", "更长啸、馀声振林溪，见乱红惊飞，半岩花雨。"]'),
('song-ci-80','桃源忆故人','赵子发','宋','宋词','song-ci','桃源忆故人','[]','芳菲已有东风露。',56,'宋词/ci.song.5000.json','["芳菲已有东风露。", "寒著轻罗未去。", "午夜鸾车鹤驭。", "散入千莲步。", "粉香度曲嬉游女。", "草草相逢无据。", "肠断泪零无数。", "洒作花梢雨。"]'),
('song-ci-81','浣溪沙','赵子发','宋','宋词','song-ci','浣溪沙','[]','疏荫摇摇趁岸移。',48,'宋词/ci.song.5000.json','["疏荫摇摇趁岸移。", "惊鸥点点过帆飞。", "船分水打嫩沙回。", "断梦不知人去处，卷帘还有燕来时。", "日斜风紧转湾西。"]'),
('song-ci-82','南歌子','赵子发','宋','宋词','song-ci','南歌子','[]','天末疑无路，波翻欲御风。',62,'宋词/ci.song.5000.json','["天末疑无路，波翻欲御风。", "此身忽在玉壶中。", "醉倒不知、南北与西东。", "猎猎遥鸣草，飕飕静打篷。", "与君回棹碧云浓。", "不是思归、只为酒船空。"]'),
('song-ci-83','南歌子','赵子发','宋','宋词','song-ci','南歌子','[]','人有纫兰佩，云无出岫心。',62,'宋词/ci.song.5000.json','["人有纫兰佩，云无出岫心。", "扁舟来入碧涛深。", "坐见楚咻、儿女变齐音。", "但醉双瓶玉，从渠六印金。", "此时何处可幽寻。", "风定津头、白日照平林。"]'),
('song-ci-84','点绛唇','赵子发','宋','宋词','song-ci','点绛唇','[]','野岸孤舟，断桥明月穿流水。',50,'宋词/ci.song.5000.json','["野岸孤舟，断桥明月穿流水。", "雁声嘹呖。", "双落行人泪。", "去岁吾家，曾插黄花醉。", "今那是。", "杖藜西指。", "看即成千里。"]'),
('song-ci-85','虞美人','赵子发','宋','宋词','song-ci','虞美人','[]','飞云流水来无信。',66,'宋词/ci.song.5000.json','["飞云流水来无信。", "花发年年恨。", "小桃如脸柳如眉。", "记得那人模样、旧家时。", "楼高映步拖金缕。", "香湿黄昏雨。", "如今不见欲凭书。", "门外水平波暖、一双鱼。"]'),
('song-ci-86','惜分飞','赵子发','宋','宋词','song-ci','惜分飞','[]','数点雨声惊残暑。',58,'宋词/ci.song.5000.json','["数点雨声惊残暑。", "帘外秋光容与。", "重换熏炉炷。", "渐低罗幕香成雾。", "今夜夜凉情几许。", "莫向屏山取取。", "却笑阳台女。", "楚人空□高唐赋。"]'),
('song-ci-87','阮郎归','赵子发','宋','宋词','song-ci','阮郎归','[]','马蹄踏月响空山。',56,'宋词/ci.song.5000.json','["马蹄踏月响空山。", "梅生烟壑寒。", "水妃去后泪痕乾。", "天风吹佩兰。", "纫香久，怕花残。", "与君聊据鞍。", "一枝欲寄北人看。", "如今行路难。"]'),
('song-ci-88','忆王孙','赵子发','宋','宋词','song-ci','忆王孙','[]','日长高柳一蝉声。',36,'宋词/ci.song.5000.json','["日长高柳一蝉声。", "翡翠帘深宝簟清。", "梦远春云不散情。", "晓风轻。", "玉楝花飞宿雨晴。"]'),
('song-ci-89','杨柳枝','赵子发','宋','宋词','song-ci','杨柳枝','[]','淅淅西风生暮寒。',48,'宋词/ci.song.5000.json','["淅淅西风生暮寒。", "绣衣单。", "碧梧叶落藕花残。", "恨前欢。", "月镂虚棂烟逗竹，梦千山。", "玉箫清夜忆孤鸾。", "镇长闲。"]'),
('song-ci-90','望江南・忆江南','赵子发','宋','宋词','song-ci','望江南・忆江南','[]','新梦断，久立暗伤春。',32,'宋词/ci.song.5000.json','["新梦断，久立暗伤春。", "柳下月如花下月，今年人忆去年人。", "往事梦中身。"]'),
('song-ci-91','菩萨蛮','赵子发','宋','宋词','song-ci','菩萨蛮','[]','闲庭草色侵阶绿。',52,'宋词/ci.song.5000.json','["闲庭草色侵阶绿。", "琐窗午梦人如玉。", "抛枕出罗帏。", "风吹金缕衣。", "怨春风雨恶。", "二月桃花落。", "雨后纵多晴。", "花休春不成。"]'),
('song-ci-92','少年游','赵子发','宋','宋词','song-ci','少年游','[]','晓山日薄半春阴。',60,'宋词/ci.song.5000.json','["晓山日薄半春阴。", "烟暖柳拖金。", "满眼新晴，歌声妆影，悠荡碧云心。", "闲庭客散人归去，疏雨湿罗襟。", "楼阁濛濛，断虹明处，十里暮云深。"]'),
('song-ci-93','采桑子','赵子发','宋','宋词','song-ci','采桑子','[]','春蚕昨夜眠方起，闲了罗机。',52,'宋词/ci.song.5000.json','["春蚕昨夜眠方起，闲了罗机。", "共采柔枝。", "桑柘阴阴三月时。", "背人佯笑移金钏，惆怅花期。", "故故留迟。", "独自归来雨满衣。"]'),
('song-ci-94','浪淘沙','赵子发','宋','宋词','song-ci','浪淘沙','[]','约素小腰身。',64,'宋词/ci.song.5000.json','["约素小腰身。", "不奈伤春。", "疏梅影下晚妆新。", "袅袅娉娉何样似，一缕轻云。", "歌巧动朱唇。", "字字娇嗔。", "桃花深处一通津。", "怅望瑶台清夜月，还送归轮。"]'),
('song-ci-95','念奴娇','徐俯','宋','宋词','song-ci','念奴娇','[]','素光练静，照青山隐隐，修眉横绿。',120,'宋词/ci.song.5000.json','["素光练静，照青山隐隐，修眉横绿。", "鳷鹊楼高天似水，碧瓦寒生银粟。", "万丈辉光，奔云涌雾，飞过卢鸿屋。", "更无尘翳，皓然冷浸梧竹。", "因念鹤发仙翁，当时曾共赏，紫岩飞瀑。", "对影三人聊痛饮，一洗闲愁千斛。", "斗转参移，翻然归去，万里骑黄鹄。", "一川霜晓，叫云吹断横玉。"]'),
('song-ci-96','浣溪沙','徐俯','宋','宋词','song-ci','浣溪沙','[]','章水何如颍水清。',48,'宋词/ci.song.5000.json','["章水何如颍水清。", "江山明秀发诗情。", "七言还我是长城。", "小小钿花开宝靥，纤纤玉笋见云英。", "十千名酒十分倾。"]'),
('song-ci-97','虞美人','徐俯','宋','宋词','song-ci','虞美人','[]','梅花元自江南得。',66,'宋词/ci.song.5000.json','["梅花元自江南得。", "还醉江南客。", "雪中雨里为谁香。", "闻道数枝清笑、出东墙。", "多情宋玉还知否。", "梁苑无寻处。", "胭脂为萼玉为肌。", "却恨恼人桃杏、不同时。"]'),
('song-ci-98','卜算子','徐俯','宋','宋词','song-ci','卜算子','[]','心空道亦空，风静林还静。',52,'宋词/ci.song.5000.json','["心空道亦空，风静林还静。", "卷尽浮云月自明，中有山河影。", "供养及修行。", "旧话成重省。", "豆爆生莲火里时，痛拨寒灰冷。"]'),
('song-ci-99','卜算子','徐俯','宋','宋词','song-ci','卜算子','[]','天生百种愁，挂在斜阳树。',54,'宋词/ci.song.5000.json','["天生百种愁，挂在斜阳树。", "绿叶阴阴占得春，草满莺啼处。", "不见生尘步。", "空忆如簧语。", "柳外重重叠叠山，遮不断、愁来路。"]'),
('song-ci-100','卜算子','徐俯','宋','宋词','song-ci','卜算子','[]','清池过雨凉，暗有清香度。',52,'宋词/ci.song.5000.json','["清池过雨凉，暗有清香度。", "缥缈娉婷绝代歌，翠袖风中举。", "忽敛双眉去。", "总是关情处。", "一段江山一片云，又下阳台雨。"]'),
('song-ci-101','鹧鸪天','徐俯','宋','宋词','song-ci','鹧鸪天','[]','绿水名园不是村。',64,'宋词/ci.song.5000.json','["绿水名园不是村。", "淡妆浓笑两生春。", "笛中已自多愁怨，雨里因谁有泪痕。", "香旖旎，酒氤氲。", "多情生怕落纷纷。", "旧来好事浑如梦，年少风流付与君。"]'),
('song-ci-102','鹧鸪天','徐俯','宋','宋词','song-ci','鹧鸪天','[]','满眼纷纷恰似花。',64,'宋词/ci.song.5000.json','["满眼纷纷恰似花。", "飘飘泊泊自天涯。", "雨中添得无穷湿，风里吹成一道斜。", "银作屋，玉为车。", "姮娥青女过人家。", "应嫌素面微微露，故着轻云薄薄遮。"]'),
('song-ci-103','踏莎行','徐俯','宋','宋词','song-ci','踏莎行','[]','素景将阑，黄花初笑。',68,'宋词/ci.song.5000.json','["素景将阑，黄花初笑。", "登高一望秋天杳。", "邀宾携妓数能来，醉中赢得闲多少。", "佳气氤氲，飞云缥缈。", "竹林更着清江绕。", "高歌屡舞莫催人，华筵直待华灯照。"]'),
('song-ci-104','踏莎行','徐俯','宋','宋词','song-ci','踏莎行','[]','画栋风生，绣筵花绕。',68,'宋词/ci.song.5000.json','["画栋风生，绣筵花绕。", "层台胜日频高眺。", "清辉爽气自娱人，何妨称意开颜笑。", "水碧无穷，山青未了。", "斜阳浦口归帆少。", "云鬟烟鬓只供愁，琵琶更作相思调。"]'),
('song-ci-105','踏莎行','徐俯','宋','宋词','song-ci','踏莎行','[]','玉露团花，金风破雾。',68,'宋词/ci.song.5000.json','["玉露团花，金风破雾。", "高台与上晴空去。", "举杯相属看前山，烟中乱叠青无数。", "皓齿明眸，肌香体素。", "恼人正在秋波注。", "因何欲雨又还晴，歌声遏得行云住。"]'),
('song-ci-106','南歌子','徐俯','宋','宋词','song-ci','南歌子','[]','细蕊黄金嫩，繁花白雪香。',62,'宋词/ci.song.5000.json','["细蕊黄金嫩，繁花白雪香。", "共谁连璧向河阳。", "自是不须汤饼、试何郎。", "婀娜拢松髻，轻盈淡薄妆。", "莫令韩寿在伊傍。", "便逐游蜂惊蝶、过东墙。"]'),
('song-ci-107','鹧鸪天','徐俯','宋','宋词','song-ci','鹧鸪天','[]','宜笑宜颦掌上身。',64,'宋词/ci.song.5000.json','["宜笑宜颦掌上身。", "能歌能舞恶精神。", "脸边红入桃花嫩，眉上青归柳叶新。", "娇不语，易生嗔。", "尊前还是一番春。", "深杯百罚重拚却，只为妖饶醉得人。"]'),
('song-ci-108','浣溪沙','徐俯','宋','宋词','song-ci','浣溪沙','[]','西塞山前白鹭飞。',48,'宋词/ci.song.5000.json','["西塞山前白鹭飞。", "桃花流水鳜鱼肥。", "一波才动万波随。", "黄帽岂如青箬笠，羊裘何似绿蓑衣。", "斜风细雨不须归。"]'),
('song-ci-109','浣溪沙','徐俯','宋','宋词','song-ci','浣溪沙','[]','新妇矶边秋月明。',48,'宋词/ci.song.5000.json','["新妇矶边秋月明。", "女儿浦口晚潮平。", "沙头鹭宿戏鱼惊。", "青箬笠前明此事，绿蓑衣底度平生。", "斜风细雨小舟轻。"]'),
('song-ci-110','鹧鸪天','徐俯','宋','宋词','song-ci','鹧鸪天','["\u957f\u6c5f"]','西塞山前白鹭飞。',64,'宋词/ci.song.5000.json','["西塞山前白鹭飞。", "桃花柳水鳜鱼肥。", "朝廷若觅元真子，晴在长江理钓丝。", "青箬笠，绿蓑衣。", "斜风细雨不须归。", "浮云万里烟波客，惟有沧浪孺子知。"]'),
('song-ci-111','鹧鸪天','徐俯','宋','宋词','song-ci','鹧鸪天','["\u6d1e\u5ead\u6e56"]','七泽三湘碧草连。',64,'宋词/ci.song.5000.json','["七泽三湘碧草连。", "洞庭江汉水如天。", "朝廷若觅元真子，不在云边则酒边。", "明月棹，夕阳船。", "鲈鱼恰似镜中悬。", "丝纶钓饵都收却，八字山前听雨眠。"]'),
('song-ci-112','虞美人','王安中','宋','宋词','song-ci','虞美人','[]','千山青比妆眉浅。',66,'宋词/ci.song.5000.json','["千山青比妆眉浅。", "却奈眉峰远。", "玉人元自不禁秋。", "更算恼伊深处、月当楼。", "分携不见凭阑际。", "只料无红泪。", "万千应在锦回纹。", "嘱付断鸿西去、问行云。"]'),
('song-ci-113','浣溪沙','王安中','宋','宋词','song-ci','浣溪沙','[]','慵整金钗缩指尖。',48,'宋词/ci.song.5000.json','["慵整金钗缩指尖。", "晓霙犹自入疏帘。", "绿窗清冷脸红添。", "妒粉尽饶花六六，回风从斗玉纤纤。", "不成香暖也相兼。"]'),
('song-ci-114','玉楼春','王安中','宋','宋词','song-ci','玉楼春','[]','秋鸿只向秦筝住。',64,'宋词/ci.song.5000.json','["秋鸿只向秦筝住。", "终寄青楼书不去。", "手因春梦有携时，眼到花开无著处。", "泥金小字蛮笺句。", "泪湿残妆今在否。", "欲寻巫峡旧时云，问取阳关西去路。"]'),
('song-ci-115','绿头鸭・多丽','王安中','宋','宋词','song-ci','绿头鸭・多丽','[]','魏都雄，凤皇飞观云间。',173,'宋词/ci.song.5000.json','["魏都雄，凤皇飞观云间。", "佩麟符、荀池元老，暂辞西省仙班。", "憩甘棠、地澄远籁，咏华黍、河卷惊澜。", "碧草萋迷，丹毫冷落，圜扉铃索镇长闲。", "绣筵展、三台星近，锵玉韵珊珊。", "金尊滟、新醅方荐，薄暑初残。", "政成时、欢馀客散，后园朱户休关。", "度秋风、画阑枕水，挂夜月、雕栏骑山。", "锦帐笼香，鸾钗按曲，琵琶双转语绵蛮。", "劝行□、傍眉黄气，先报衮衣还。", "登庸际，应褒旧德，喜动天颜。"]'),
('song-ci-116','北山移文哨遍・哨遍','王安中','宋','宋词','song-ci','北山移文哨遍・哨遍','[]','世有达人，潇洒出尘，招隐青霄际。',243,'宋词/ci.song.5000.json','["世有达人，潇洒出尘，招隐青霄际。", "终始追。", "游览老山栖。", "藐千金、轻脱如屣。", "彼假容江皋，滥巾云岳，缨情好爵欺松桂。", "观向释谈空，寻真讲道，巢由何足相拟。", "待诏书来起便驺驰。", "席次早焚烈芰荷衣。", "敲朴喧喧，牒诉匆匆，抗颜自喜。", "嗟明月高霞，石径幽绝谁回睇。", "空怅猿惊处，凄凉孤鹤嘹唳。", "任列壑争讥。", "众蜂竦诮，林惭涧愧移星岁。", "方浪枻神京，腾装魏阙，徘徊经过留憩。", "致草堂灵怒蒋侯麾。", "扃岫幌、驱烟勒新移。", "忍丹崖碧岭重滓。", "鸣湍声断深谷，逋客归何计。", "信知一逐浮荣，便丧素守，身成俗士。", "伯鸾家有孟光妻。", "岂逡巡、眷恋名利。"]'),
('song-ci-117','菩萨蛮','王安中','宋','宋词','song-ci','菩萨蛮','[]','中军玉帐旌旗绕。',52,'宋词/ci.song.5000.json','["中军玉帐旌旗绕。", "吴钩锦带明霜晓。", "铁马去追风。", "弓声惊塞鸿。", "分兵闲细柳。", "金字回飞奏。", "犒饮上恩浓。", "燕然思勒功。"]'),
('song-ci-118','御街行','王安中','宋','宋词','song-ci','御街行','[]','清霜飞入蓬莱殿。',90,'宋词/ci.song.5000.json','["清霜飞入蓬莱殿。", "别进云裘软。", "却回宸虑念多寒，诏语日边亲遣。", "冰蚕绵厚，金雕锦好，永夜缝宫线。", "红旌绛旆迎星传。", "喜气欢声远。", "庙堂勋旧使台贤，领袖坐中争绚。", "天香馥郁，君恩岁岁，一醉春生面。"]'),
('song-ci-119','鹧鸪天','王安中','宋','宋词','song-ci','鹧鸪天','[]','茜雾红云捧建章。',64,'宋词/ci.song.5000.json','["茜雾红云捧建章。", "鸣珂星使渡银潢。", "亲将圣主如丝语，传与陪都振鹭行。", "香袅袅，佩锵锵。", "升平歌管趁飞觞。", "明时玉帐恩相续，清夜钧天梦更长。"]'),
('song-ci-120','蝶恋花','王安中','宋','宋词','song-ci','蝶恋花','[]','曲径深丛枝袅袅。',70,'宋词/ci.song.5000.json','["曲径深丛枝袅袅。", "晕粉揉绵，破蕊烘清晓。", "十二番开寒最好。", "此花不惜春归早。", "青女飞来红翠少。", "特地芳菲，绝艳惊衰草。", "只殢东风终甚了。", "久长欲伴姮娥老。"]'),
('song-ci-121','蝶恋花','王安中','宋','宋词','song-ci','蝶恋花','[]','巧剪明霞成片片。',70,'宋词/ci.song.5000.json','["巧剪明霞成片片。", "欲笑还颦，金蕊依稀见。", "拾翠人寒妆易浅。", "浓香别注唇膏点。", "竹雀喧喧烟岫远。", "晚色溟濛，六出花飞遍。", "此际一枝红绿眩。", "画工谁写银屏面。"]');
